    let _resp = send_cmd::<_, S>(io, Cmd::AppCmd, cmd55, cmd_arg, DataTransType::None).unwrap();
    // send acmd51
    // 1. set transact size
    set_transaction_size(io, 8, 8);
    // 2. send command
    let acmd51 = CmdReg::from(Cmd::SendScr);
