        let resp = resp[0] as u128
            | (resp[1] as u128) << 32
            | (resp[2] as u128) << 64
            | (resp[3] as u128) << 96;
        let cid = Cid::new(resp);
        #[cfg(feature = "alloc")]
        pprintln!("cid: {}", cid.fmt());
        #[cfg(not(feature = "alloc"))]
        pprintln!("cid: {:?}", cid);
    }
