    uint64 rsvd3 : 2;
    /**
     * Bit  24 is write enable to the channel suspend bit
     * 0x1 for enable write to CH1_SUSP bit
     * 0x0 for disable write to CH1_SUSP bit
     */
    uint64 ch1_susp_we : 1;
    /**
     * Bit  25 is write enable to the channel suspend bit
