}

struct vma {
    enum segtype type;  //分配的vma的作用是干什么
    int perm;           //这个vma的权限是什么
    uint64 addr;        // vma映射的内存地址是什么
    uint64 sz;          // vma映射的大小是什么
    uint64 end;         // vma映射的结束地址
    int flags;
