struct pipe {
    struct spinlock lock;
    char data[PIPESIZE];
    uint nread;     // number of bytes read
    uint nwrite;    // number of bytes written
    int readopen;   // read fd is still open
    int writeopen;  // write fd is still open
}

struct cpu {
    struct proc *proc;       // The process running on this cpu, or null.
    struct context context;  // swtch() here to enter scheduler().
    int noff;                // Depth of push_off() nesting.
    int intena;              // Were interrupts enabled before push_off()?
}

struct proc {
    struct spinlock lock;

    // p->lock must be held when using these:
    enum procstate state;  // Process state
    struct proc *parent;   // Parent process
    void *chan;            // If non-zero, sleeping on chan
    int killed;            // If non-zero, have been killed
    int xstate;            // Exit status to be returned to parent's wait
    int pid;               // Process ID
    int uid;               // User ID
    int gid;               // Group ID
    int pgid;              // Process group ID

    uint64 filelimit;

    // these are private to the process, so p->lock need not be held.
    thread *main_thread;          // Main thread per process
    thread *thread_queue;         // Thread queue
    uint64 kstack;                // Virtual address of kernel stack
    uint64 sz;                    // Size of process memory (bytes)
    pagetable_t pagetable;        // User page table
    pagetable_t kpagetable;       // Kernel page table
    struct trapframe *trapframe;  // data page for trampoline.S
    struct context context;       // swtch() here to run process
    struct file *ofile[NOFILE];   // Open files
    struct dirent *cwd;           // Current directory
    struct ext4_dirent *ext4_dir;
    int *exec_close;  // File descriptors to close after exec
    char name[16];    // Process name (debugging)
    int tmask;        // trace mask
    struct vma *vma;
    int ktime;
    int utime;
    int thread_num;
    uint64 clear_child_tid;
    // signal
    sigaction sigaction[SIGRTMAX + 1];  // signal action
    __sigset_t sig_set;                 // signal mask
    __sigset_t sig_pending;             // pending signal
    struct trapframe *sig_tf;           // trapframe for signal
}

struct rlimit {
    uint64 rlim_cur;
    uint64 rlim_max;
}

struct thread_stack_param {
    uint64 func_point;
    uint64 arg_point;
}

struct thread {
    struct spinlock lock;

    // 当使用下面这些变量的时候，thread的锁必须持有
    enum threadState state;   // 线程的状态
    struct proc *p;    // 这个线程属于哪一个进程
    void *chan;   // 如果不为NULL,则在chan地址上睡眠
    int tid;   // 线程ID
    uint64 awakeTime; 

    // 使用下面这些变量的时候，thread的锁不需要持有
    uint64 kstack;   // 线程内核栈的地址,一个进程的不同线程所用的内核栈的地址应该不同
    uint64 vtf;   // 线程的trapframe的虚拟地址
    uint64 sz;   // 复制自进程的sz
    struct trapframe *trapframe;
    context context;  // 每个进程应该有自己的context
    uint64 kstack_pa;
    uint64 clear_child_tid;

    struct thread *next_thread;
    struct thread *pre_thread;
    // TODO: signal
}

