void gpiohs_set_drive_mode(uint8 pin, gpio_drive_mode_t mode) {
    // configASSERT(pin < GPIOHS_MAX_PINNO);
    int io_number = fpioa_get_io_by_function(FUNC_GPIOHS0 + pin);
    // configASSERT(io_number >= 0);

    fpioa_pull_t pull = FPIOA_PULL_NONE;
    uint32 dir = 0;

    switch (mode) {
    case GPIO_DM_INPUT:
        pull = FPIOA_PULL_NONE;
        dir = 0;
        break;
    case GPIO_DM_INPUT_PULL_DOWN:
        pull = FPIOA_PULL_DOWN;
        dir = 0;
        break;
    case GPIO_DM_INPUT_PULL_UP:
        pull = FPIOA_PULL_UP;
        dir = 0;
        break;
    case GPIO_DM_OUTPUT:
        pull = FPIOA_PULL_DOWN;
        dir = 1;
        break;
    default:
        // configASSERT(!"GPIO drive mode is not supported.")
        break;
    }

    fpioa_set_io_pull(io_number, pull);
    volatile uint32 *reg = dir ? gpiohs->output_en.u32 : gpiohs->input_en.u32;
    volatile uint32 *reg_d =
        !dir ? gpiohs->output_en.u32 : gpiohs->input_en.u32;
    set_gpio_bit(reg_d, pin, 0);
    set_gpio_bit(reg, pin, 1);
}

void gpiohs_set_pin(uint8 pin, gpio_pin_value_t value) {
    // configASSERT(pin < GPIOHS_MAX_PINNO);
    set_gpio_bit(gpiohs->output_val.u32, pin, value);
}

void spi_init(spi_device_num_t spi_num, spi_work_mode_t work_mode,
              spi_frame_format_t frame_format, uint64 data_bit_length,
              uint32 endian) {
    // configASSERT(data_bit_length >= 4 && data_bit_length <= 32);
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
    // spi_clk_init(spi_num);

    // uint8 dfs_offset, frf_offset, work_mode_offset;
    uint8 dfs_offset = 0;
    uint8 frf_offset = 0;
    uint8 work_mode_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        dfs_offset = 16;
        frf_offset = 21;
        work_mode_offset = 6;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        dfs_offset = 0;
        frf_offset = 22;
        work_mode_offset = 8;
        break;
    }

    switch (frame_format) {
    case SPI_FF_DUAL:
        // configASSERT(data_bit_length % 2 == 0);
        break;
    case SPI_FF_QUAD:
        // configASSERT(data_bit_length % 4 == 0);
        break;
    case SPI_FF_OCTAL:
        // configASSERT(data_bit_length % 8 == 0);
        break;
    default:
        break;
    }
    volatile spi_t *spi_adapter = spi[spi_num];
    if (spi_adapter->baudr == 0) spi_adapter->baudr = 0x14;
    spi_adapter->imr = 0x00;
    spi_adapter->dmacr = 0x00;
    spi_adapter->dmatdlr = 0x10;
    spi_adapter->dmardlr = 0x00;
    spi_adapter->ser = 0x00;
    spi_adapter->ssienr = 0x00;
    spi_adapter->ctrlr0 = (work_mode << work_mode_offset) |
                          (frame_format << frf_offset) |
                          ((data_bit_length - 1) << dfs_offset);
    spi_adapter->spi_ctrlr0 = 0;
    spi_adapter->endian = endian;
}

static void spi_set_tmod(uint8 spi_num, uint32 tmod) {
    // configASSERT(spi_num < SPI_DEVICE_MAX);
    volatile spi_t *spi_handle = spi[spi_num];
    uint8 tmod_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
    case 2:
        tmod_offset = 8;
        break;
    case 3:
    default:
        tmod_offset = 10;
        break;
    }
    set_bit(&spi_handle->ctrlr0, 3 << tmod_offset, tmod << tmod_offset);
}

static spi_transfer_width_t spi_get_frame_size(uint64 data_bit_length) {
    if (data_bit_length < 8)
        return SPI_TRANS_CHAR;
    else if (data_bit_length < 16)
        return SPI_TRANS_SHORT;
    return SPI_TRANS_INT;
}

void spi_send_data_normal(spi_device_num_t spi_num,
                          spi_chip_select_t chip_select, const uint8 *tx_buff,
                          uint64 tx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);

    uint64 index, fifo_len;
    spi_set_tmod(spi_num, SPI_TMOD_TRANS);

    volatile spi_t *spi_handle = spi[spi_num];

    // uint8 dfs_offset;
    uint8 dfs_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        dfs_offset = 16;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        dfs_offset = 0;
        break;
    }
    uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
    spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

    uint8 v_misalign_flag = 0;
    uint32 v_send_data;
    if ((uintptr_t)tx_buff % frame_width) v_misalign_flag = 1;

    spi_handle->ssienr = 0x01;
    spi_handle->ser = 1U << chip_select;
    uint32 i = 0;
    while (tx_len) {
        fifo_len = 32 - spi_handle->txflr;
        fifo_len = fifo_len < tx_len ? fifo_len : tx_len;
        switch (frame_width) {
        case SPI_TRANS_INT:
            fifo_len = fifo_len / 4 * 4;
            if (v_misalign_flag) {
                for (index = 0; index < fifo_len; index += 4) {
                    // memcpy(&v_send_data, tx_buff + i, 4);
                    memmove(&v_send_data, tx_buff + i, 4);
                    spi_handle->dr[0] = v_send_data;
                    i += 4;
                }
            } else {
                for (index = 0; index < fifo_len / 4; index++)
                    spi_handle->dr[0] = ((uint32 *)tx_buff)[i++];
            }
            break;
        case SPI_TRANS_SHORT:
            fifo_len = fifo_len / 2 * 2;
            if (v_misalign_flag) {
                for (index = 0; index < fifo_len; index += 2) {
                    // memcpy(&v_send_data, tx_buff + i, 2);
                    memmove(&v_send_data, tx_buff + i, 2);
                    spi_handle->dr[0] = v_send_data;
                    i += 2;
                }
            } else {
                for (index = 0; index < fifo_len / 2; index++)
                    spi_handle->dr[0] = ((uint16 *)tx_buff)[i++];
            }
            break;
        default:
            for (index = 0; index < fifo_len; index++)
                spi_handle->dr[0] = tx_buff[i++];
            break;
        }
        tx_len -= fifo_len;
    }
    while ((spi_handle->sr & 0x05) != 0x04)
        ;
    spi_handle->ser = 0x00;
    spi_handle->ssienr = 0x00;
}

void spi_send_data_standard(spi_device_num_t spi_num,
                            spi_chip_select_t chip_select,
                            const uint8 *cmd_buff, uint64 cmd_len,
                            const uint8 *tx_buff, uint64 tx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
    // uint8 *v_buf = malloc(cmd_len + tx_len);
    uint8 *v_buf = kalloc();
    uint64 i;
    for (i = 0; i < cmd_len; i++) v_buf[i] = cmd_buff[i];
    for (i = 0; i < tx_len; i++) v_buf[cmd_len + i] = tx_buff[i];

    spi_send_data_normal(spi_num, chip_select, v_buf, cmd_len + tx_len);
    // free((void *)v_buf);
    kfree((void *)v_buf);
}

void spi_receive_data_standard(spi_device_num_t spi_num,
                               spi_chip_select_t chip_select,
                               const uint8 *cmd_buff, uint64 cmd_len,
                               uint8 *rx_buff, uint64 rx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
    uint64 index, fifo_len;
    if (cmd_len == 0)
        spi_set_tmod(spi_num, SPI_TMOD_RECV);
    else
        spi_set_tmod(spi_num, SPI_TMOD_EEROM);
    volatile spi_t *spi_handle = spi[spi_num];

    // uint8 dfs_offset;
    uint8 dfs_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        dfs_offset = 16;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        dfs_offset = 0;
        break;
    }
    uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
    spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

    uint32 i = 0;
    uint64 v_cmd_len = cmd_len / frame_width;
    uint32 v_rx_len = rx_len / frame_width;

    spi_handle->ctrlr1 = (uint32)(v_rx_len - 1);
    spi_handle->ssienr = 0x01;

    while (v_cmd_len) {
        fifo_len = 32 - spi_handle->txflr;
        fifo_len = fifo_len < v_cmd_len ? fifo_len : v_cmd_len;
        switch (frame_width) {
        case SPI_TRANS_INT:
            for (index = 0; index < fifo_len; index++)
                spi_handle->dr[0] = ((uint32 *)cmd_buff)[i++];
            break;
        case SPI_TRANS_SHORT:
            for (index = 0; index < fifo_len; index++)
                spi_handle->dr[0] = ((uint16 *)cmd_buff)[i++];
            break;
        default:
            for (index = 0; index < fifo_len; index++)
                spi_handle->dr[0] = cmd_buff[i++];
            break;
        }
        spi_handle->ser = 1U << chip_select;
        v_cmd_len -= fifo_len;
    }

    if (cmd_len == 0) {
        spi_handle->dr[0] = 0xffffffff;
        spi_handle->ser = 1U << chip_select;
    }

    i = 0;
    while (v_rx_len) {
        fifo_len = spi_handle->rxflr;
        fifo_len = fifo_len < v_rx_len ? fifo_len : v_rx_len;
        switch (frame_width) {
        case SPI_TRANS_INT:
            for (index = 0; index < fifo_len; index++)
                ((uint32 *)rx_buff)[i++] = spi_handle->dr[0];
            break;
        case SPI_TRANS_SHORT:
            for (index = 0; index < fifo_len; index++)
                ((uint16 *)rx_buff)[i++] = (uint16)spi_handle->dr[0];
            break;
        default:
            for (index = 0; index < fifo_len; index++)
                rx_buff[i++] = (uint8)spi_handle->dr[0];
            break;
        }

        v_rx_len -= fifo_len;
    }

    spi_handle->ser = 0x00;
    spi_handle->ssienr = 0x00;
}

static spi_frame_format_t spi_get_frame_format(spi_device_num_t spi_num) {
    uint8 frf_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        frf_offset = 21;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        frf_offset = 22;
        break;
    }
    volatile spi_t *spi_adapter = spi[spi_num];
    return ((spi_adapter->ctrlr0 >> frf_offset) & 0x3);
}

void spi_receive_data_normal_dma(dmac_channel_number_t dma_send_channel_num,
                                 dmac_channel_number_t dma_receive_channel_num,
                                 spi_device_num_t spi_num,
                                 spi_chip_select_t chip_select,
                                 const void *cmd_buff, uint64 cmd_len,
                                 void *rx_buff, uint64 rx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);

    if (cmd_len == 0)
        spi_set_tmod(spi_num, SPI_TMOD_RECV);
    else
        spi_set_tmod(spi_num, SPI_TMOD_EEROM);

    volatile spi_t *spi_handle = spi[spi_num];

    spi_handle->ctrlr1 = (uint32)(rx_len - 1);
    spi_handle->dmacr = 0x3;
    spi_handle->ssienr = 0x01;
    if (cmd_len)
        sysctl_dma_select((sysctl_dma_channel_t)dma_send_channel_num,
                          SYSCTL_DMA_SELECT_SSI0_TX_REQ + spi_num * 2);
    sysctl_dma_select((sysctl_dma_channel_t)dma_receive_channel_num,
                      SYSCTL_DMA_SELECT_SSI0_RX_REQ + spi_num * 2);

    dmac_set_single_mode(dma_receive_channel_num, (void *)(&spi_handle->dr[0]),
                         rx_buff, DMAC_ADDR_NOCHANGE, DMAC_ADDR_INCREMENT,
                         DMAC_MSIZE_1, DMAC_TRANS_WIDTH_32, rx_len);
    if (cmd_len)
        dmac_set_single_mode(dma_send_channel_num, cmd_buff,
                             (void *)(&spi_handle->dr[0]), DMAC_ADDR_INCREMENT,
                             DMAC_ADDR_NOCHANGE, DMAC_MSIZE_4,
                             DMAC_TRANS_WIDTH_32, cmd_len);
    if (cmd_len == 0 && spi_get_frame_format(spi_num) == SPI_FF_STANDARD)
        spi[spi_num]->dr[0] = 0xffffffff;
    spi_handle->ser = 1U << chip_select;
    if (cmd_len) dmac_wait_done(dma_send_channel_num);
    dmac_wait_done(dma_receive_channel_num);

    spi_handle->ser = 0x00;
    spi_handle->ssienr = 0x00;
}

void spi_send_data_normal_dma(dmac_channel_number_t channel_num,
                              spi_device_num_t spi_num,
                              spi_chip_select_t chip_select,
                              const void *tx_buff, uint64 tx_len,
                              spi_transfer_width_t spi_transfer_width) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
    spi_set_tmod(spi_num, SPI_TMOD_TRANS);
    volatile spi_t *spi_handle = spi[spi_num];
    uint32 *buf;
    int i;
    switch (spi_transfer_width) {
    case SPI_TRANS_SHORT:
        // buf = malloc((tx_len) * sizeof(uint32));
        buf = kalloc();
        for (i = 0; i < tx_len; i++) buf[i] = ((uint16 *)tx_buff)[i];
        break;
    case SPI_TRANS_INT:
        buf = (uint32 *)tx_buff;
        break;
    case SPI_TRANS_CHAR:
    default:
        buf = kalloc();
        for (i = 0; i < tx_len; i++) buf[i] = ((uint8 *)tx_buff)[i];
        break;
    }
    spi_handle->dmacr = 0x2; /*enable dma transmit*/
    spi_handle->ssienr = 0x01;

    sysctl_dma_select((sysctl_dma_channel_t)channel_num,
                      SYSCTL_DMA_SELECT_SSI0_TX_REQ + spi_num * 2);
    dmac_set_single_mode(channel_num, buf, (void *)(&spi_handle->dr[0]),
                         DMAC_ADDR_INCREMENT, DMAC_ADDR_NOCHANGE, DMAC_MSIZE_4,
                         DMAC_TRANS_WIDTH_32, tx_len);
    spi_handle->ser = 1U << chip_select;
    dmac_wait_done(channel_num);
    if (spi_transfer_width != SPI_TRANS_INT) kfree((void *)buf);

    while ((spi_handle->sr & 0x05) != 0x04)
        ;
    spi_handle->ser = 0x00;
    spi_handle->ssienr = 0x00;
}

void spi_receive_data_standard_dma(
    dmac_channel_number_t dma_send_channel_num,
    dmac_channel_number_t dma_receive_channel_num, spi_device_num_t spi_num,
    spi_chip_select_t chip_select, const uint8 *cmd_buff, uint64 cmd_len,
    uint8 *rx_buff, uint64 rx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
    volatile spi_t *spi_handle = spi[spi_num];

    uint8 dfs_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        dfs_offset = 16;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        dfs_offset = 0;
        break;
    }
    uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
    spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

    uint64 i;

    uint32 *write_cmd;
    uint32 *read_buf;
    uint64 v_recv_len;
    uint64 v_cmd_len;
    switch (frame_width) {
    case SPI_TRANS_INT:
        write_cmd = kalloc();
        for (i = 0; i < cmd_len / 4; i++)
            write_cmd[i] = ((uint32 *)cmd_buff)[i];
        read_buf = &write_cmd[i];
        v_recv_len = rx_len / 4;
        v_cmd_len = cmd_len / 4;
        break;
    case SPI_TRANS_SHORT:
        write_cmd = kalloc();
        for (i = 0; i < cmd_len / 2; i++)
            write_cmd[i] = ((uint16 *)cmd_buff)[i];
        read_buf = &write_cmd[i];
        v_recv_len = rx_len / 2;
        v_cmd_len = cmd_len / 2;
        break;
    default:
        write_cmd = kalloc();
        for (i = 0; i < cmd_len; i++) write_cmd[i] = cmd_buff[i];
        read_buf = &write_cmd[i];
        v_recv_len = rx_len;
        v_cmd_len = cmd_len;
        break;
    }

    spi_receive_data_normal_dma(dma_send_channel_num, dma_receive_channel_num,
                                spi_num, chip_select, write_cmd, v_cmd_len,
                                read_buf, v_recv_len);

    switch (frame_width) {
    case SPI_TRANS_INT:
        for (i = 0; i < v_recv_len; i++) ((uint32 *)rx_buff)[i] = read_buf[i];
        break;
    case SPI_TRANS_SHORT:
        for (i = 0; i < v_recv_len; i++) ((uint16 *)rx_buff)[i] = read_buf[i];
        break;
    default:
        for (i = 0; i < v_recv_len; i++) rx_buff[i] = read_buf[i];
        break;
    }

    kfree(write_cmd);
}

void spi_send_data_standard_dma(dmac_channel_number_t channel_num,
                                spi_device_num_t spi_num,
                                spi_chip_select_t chip_select,
                                const uint8 *cmd_buff, uint64 cmd_len,
                                const uint8 *tx_buff, uint64 tx_len) {
    // configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);

    volatile spi_t *spi_handle = spi[spi_num];

    uint8 dfs_offset = 0;
    switch (spi_num) {
    case 0:
    case 1:
        dfs_offset = 16;
        break;
    case 2:
        // configASSERT(!"Spi Bus 2 Not Support!");
        break;
    case 3:
    default:
        dfs_offset = 0;
        break;
    }
    uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
    spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

    uint32 *buf;
    uint64 v_send_len;
    int i;
    switch (frame_width) {
    case SPI_TRANS_INT:
        buf = kalloc();
        for (i = 0; i < cmd_len / 4; i++) buf[i] = ((uint32 *)cmd_buff)[i];
        for (i = 0; i < tx_len / 4; i++)
            buf[cmd_len / 4 + i] = ((uint32 *)tx_buff)[i];
        v_send_len = (cmd_len + tx_len) / 4;
        break;
    case SPI_TRANS_SHORT:
        buf = kalloc();
        for (i = 0; i < cmd_len / 2; i++) buf[i] = ((uint16 *)cmd_buff)[i];
        for (i = 0; i < tx_len / 2; i++)
            buf[cmd_len / 2 + i] = ((uint16 *)tx_buff)[i];
        v_send_len = (cmd_len + tx_len) / 2;
        break;
    default:
        buf = kalloc();
        for (i = 0; i < cmd_len; i++) buf[i] = cmd_buff[i];
        for (i = 0; i < tx_len; i++) buf[cmd_len + i] = tx_buff[i];
        v_send_len = cmd_len + tx_len;
        break;
    }

    spi_send_data_normal_dma(channel_num, spi_num, chip_select, buf, v_send_len,
                             SPI_TRANS_INT);

    kfree((void *)buf);
}

void uartinit(void) {
    // disable interrupts.
    WriteReg(IER, 0x00);

    // special mode to set baud rate.
    WriteReg(LCR, LCR_BAUD_LATCH);

    // LSB for baud rate of 38.4K.
    WriteReg(0, 0x03);

    // MSB for baud rate of 38.4K.
    WriteReg(1, 0x00);

    // leave set-baud mode,
    // and set word length to 8 bits, no parity.
    WriteReg(LCR, LCR_EIGHT_BITS);

    // reset and enable FIFOs.
    WriteReg(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR);

    // enable transmit and receive interrupts.
    WriteReg(IER, IER_TX_ENABLE | IER_RX_ENABLE);

    uart_tx_w = uart_tx_r = 0;

    initlock(&uart_tx_lock, "uart");
}

void uartputc(int c) {
    acquire(&uart_tx_lock);

    if (panicked) {
        for (;;)
            ;
    }

    while (1) {
        if (((uart_tx_w + 1) % UART_TX_BUF_SIZE) == uart_tx_r) {
            // buffer is full.
            // wait for uartstart() to open up space in the buffer.
            sleep(&uart_tx_r, &uart_tx_lock);
        } else {
            uart_tx_buf[uart_tx_w] = c;
            uart_tx_w = (uart_tx_w + 1) % UART_TX_BUF_SIZE;
            uartstart();
            release(&uart_tx_lock);
            return;
        }
    }
}

void uartputc_sync(int c) {
    push_off();

    if (panicked) {
        for (;;)
            ;
    }

    // wait for Transmit Holding Empty to be set in LSR.
    while ((ReadReg(LSR) & LSR_TX_IDLE) == 0)
        ;
    WriteReg(THR, c);

    pop_off();
}

void uartstart() {
    while (1) {
        if (uart_tx_w == uart_tx_r) {
            // transmit buffer is empty.
            return;
        }

        if ((ReadReg(LSR) & LSR_TX_IDLE) == 0) {
            // the UART transmit holding register is full,
            // so we cannot give it another byte.
            // it will interrupt when it's ready for a new byte.
            return;
        }

        int c = uart_tx_buf[uart_tx_r];
        uart_tx_r = (uart_tx_r + 1) % UART_TX_BUF_SIZE;

        // maybe uartputc() is waiting for space in the buffer.
        wakeup(&uart_tx_r);

        WriteReg(THR, c);
    }
}

int uartgetc(void) {
    if (ReadReg(LSR) & 0x01) {
        // input data is ready.
        return ReadReg(RHR);
    } else {
        return -1;
    }
}

void uartintr(void) {
    // read and process incoming characters.
    while (1) {
        int c = uartgetc();
        if (c == -1) break;
        consoleintr(c);
    }

    // send buffered characters.
    acquire(&uart_tx_lock);
    uartstart();
    release(&uart_tx_lock);
}

struct disk {
    // memory for virtio descriptors &c for queue 0.
    // this is a global instead of allocated because it must
    // be multiple contiguous pages, which kalloc()
    // doesn't support, and page aligned.
    char pages[2 * PGSIZE];
    struct VRingDesc *desc;
    uint16 *avail;
    struct UsedArea *used;

    // our own book-keeping.
    char free[NUM];   // is a descriptor free?
    uint16 used_idx;  // we've looked this far in used[2..NUM].

    // track info about in-flight operations,
    // for use when completion interrupt arrives.
    // indexed by first descriptor index of chain.
    struct {
        struct buf *b;
        char status;
    } info[NUM];

    struct spinlock vdisk_lock;

} __attribute__((aligned(PGSIZE)))

void virtio_disk_init(void) {
    uint32 status = 0;

    initlock(&disk.vdisk_lock, "virtio_disk");

    if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 ||
        *R(VIRTIO_MMIO_VERSION) != 1 || *R(VIRTIO_MMIO_DEVICE_ID) != 2 ||
        *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) {
        panic("could not find virtio disk");
    }

    status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
    *R(VIRTIO_MMIO_STATUS) = status;

    status |= VIRTIO_CONFIG_S_DRIVER;
    *R(VIRTIO_MMIO_STATUS) = status;

    // negotiate features
    uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
    features &= ~(1 << VIRTIO_BLK_F_RO);
    features &= ~(1 << VIRTIO_BLK_F_SCSI);
    features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
    features &= ~(1 << VIRTIO_BLK_F_MQ);
    features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
    features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
    features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
    *R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

    // tell device that feature negotiation is complete.
    status |= VIRTIO_CONFIG_S_FEATURES_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    // tell device we're completely ready.
    status |= VIRTIO_CONFIG_S_DRIVER_OK;
    *R(VIRTIO_MMIO_STATUS) = status;

    *R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;

    // initialize queue 0.
    *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
    uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
    if (max == 0) panic("virtio disk has no queue 0");
    if (max < NUM) panic("virtio disk max queue too short");
    *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
    memset(disk.pages, 0, sizeof(disk.pages));
    *R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64)disk.pages) >> PGSHIFT;

    // desc = pages -- num * VRingDesc
    // avail = pages + 0x40 -- 2 * uint16, then num * uint16
    // used = pages + 4096 -- 2 * uint16, then num * vRingUsedElem

    disk.desc = (struct VRingDesc *)disk.pages;
    disk.avail =
        (uint16 *)(((char *)disk.desc) + NUM * sizeof(struct VRingDesc));
    disk.used = (struct UsedArea *)(disk.pages + PGSIZE);

    for (int i = 0; i < NUM; i++) disk.free[i] = 1;

// plic.c and trap.c arrange for interrupts from VIRTIO0_IRQ.
#ifdef DEBUG
    printf("virtio_disk_init\n");
#endif
}

static int alloc_desc() {
    for (int i = 0; i < NUM; i++) {
        if (disk.free[i]) {
            disk.free[i] = 0;
            return i;
        }
    }
    return -1;
}

static void free_desc(int i) {
    if (i >= NUM) panic("virtio_disk_intr 1");
    if (disk.free[i]) panic("virtio_disk_intr 2");
    disk.desc[i].addr = 0;
    disk.free[i] = 1;
    wakeup(&disk.free[0]);
}

static void free_chain(int i) {
    while (1) {
        free_desc(i);
        if (disk.desc[i].flags & VRING_DESC_F_NEXT)
            i = disk.desc[i].next;
        else
            break;
    }
}

static int alloc3_desc(int *idx) {
    for (int i = 0; i < 3; i++) {
        idx[i] = alloc_desc();
        if (idx[i] < 0) {
            for (int j = 0; j < i; j++) free_desc(idx[j]);
            return -1;
        }
    }
    return 0;
}

void virtio_disk_rw(struct buf *b, int write) {
    uint64 sector = b->sectorno;

    acquire(&disk.vdisk_lock);
    // the spec says that legacy block operations use three
    // descriptors: one for type/reserved/sector, one for
    // the data, one for a 1-byte status result.

    // allocate the three descriptors.
    int idx[3];
    while (1) {
        if (alloc3_desc(idx) == 0) {
            break;
        }
        sleep(&disk.free[0], &disk.vdisk_lock);
    }

    // format the three descriptors.
    // qemu's virtio-blk.c reads them.

    struct virtio_blk_outhdr {
        uint32 type;
        uint32 reserved;
        uint64 sector;
    } buf0;

    if (write)
        buf0.type = VIRTIO_BLK_T_OUT;  // write the disk
    else
        buf0.type = VIRTIO_BLK_T_IN;  // read the disk
    buf0.reserved = 0;
    buf0.sector = sector;

    // buf0 is on a kernel stack, which is not direct mapped,
    // thus the call to kvmpa().
    disk.desc[idx[0]].addr =
        (uint64)kwalkaddr(myproc()->kpagetable, (uint64)&buf0);
    disk.desc[idx[0]].len = sizeof(buf0);
    disk.desc[idx[0]].flags = VRING_DESC_F_NEXT;
    disk.desc[idx[0]].next = idx[1];

    disk.desc[idx[1]].addr = (uint64)b->data;
    disk.desc[idx[1]].len = BSIZE;
    if (write)
        disk.desc[idx[1]].flags = 0;  // device reads b->data
    else
        disk.desc[idx[1]].flags = VRING_DESC_F_WRITE;  // device writes b->data
    disk.desc[idx[1]].flags |= VRING_DESC_F_NEXT;
    disk.desc[idx[1]].next = idx[2];

    disk.info[idx[0]].status = 0;
    disk.desc[idx[2]].addr = (uint64)&disk.info[idx[0]].status;
    disk.desc[idx[2]].len = 1;
    disk.desc[idx[2]].flags = VRING_DESC_F_WRITE;  // device writes the status
    disk.desc[idx[2]].next = 0;

    // record struct buf for virtio_disk_intr().
    b->disk = 1;
    disk.info[idx[0]].b = b;

    // avail[0] is flags
    // avail[1] tells the device how far to look in avail[2...].
    // avail[2...] are desc[] indices the device should process.
    // we only tell device the first index in our chain of descriptors.
    disk.avail[2 + (disk.avail[1] % NUM)] = idx[0];
    __sync_synchronize();
    disk.avail[1] = disk.avail[1] + 1;

    *R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0;  // value is queue number

    // Wait for virtio_disk_intr() to say request has finished.
    while (b->disk == 1) {
        sleep(b, &disk.vdisk_lock);
    }

    disk.info[idx[0]].b = 0;
    free_chain(idx[0]);

    release(&disk.vdisk_lock);
}

