struct {
    struct spinlock lock;
    struct buf buf[NBUF];
    struct buf head;
}

void binit(void) {
    struct buf *Buf;

    initlock(&BufferCache.lock, "bcache");

    // Create linked list of buffers
    BufferCache.head.next = BufferCache.head.prev = &BufferCache.head;

    for (Buf = BufferCache.buf; BufferCache.buf > Buf - NBUF; ++Buf) {
        Buf->dev = ~0;
        Buf->refcnt = 0;

        Buf->prev = &BufferCache.head;
        Buf->next = BufferCache.head.next;

        Buf->sectorno = ~0;
        initsleeplock(&Buf->lock, "buffer");
        BufferCache.head.next->prev = Buf;
        BufferCache.head.next = Buf;
    }
    // #ifdef DEBUG
    //     printf("binit\n");
    // #endif
}

static struct buf *bget(uint dev, uint sectorno) {
    struct buf *Buf;
    printf("Try to get lock\n");
    acquire(&BufferCache.lock);
    printf("Manage to get the lock\n");
    // Is the block already cached?
    for (Buf = BufferCache.head.next; &BufferCache.head != Buf;
         Buf = Buf->next) {
        if (sectorno == Buf->sectorno && Buf->dev == dev) {
            ++Buf->refcnt;
            // releasesleep(&Buf->lock);
            release(&BufferCache.lock), acquiresleep(&Buf->lock);
            return Buf;
        }
    }
    printf("Manage to get the cache\n");
    // Not cached.
    // Recycle the least recently used (LRU) unused buffer.
    for (Buf = BufferCache.head.prev; &BufferCache.head != Buf;
         Buf = Buf->prev) {
        if (!Buf->refcnt) {
            Buf->refcnt = 1;
            Buf->valid = 0;
            Buf->dev = dev;
            Buf->sectorno = sectorno;
            release(&BufferCache.lock), acquiresleep(&Buf->lock);
            return Buf;
        }
    }
    panic("bget: no buffers");
}

