    int total_recv_cnt = 0;
    int total_req_cnt = n;
    while (total_recv_cnt < n) {
        // Read 4096 bytes every time
        // memset(content, 0, sizeof(content));

        int this_read_cnt = (total_req_cnt > BSIZE) ? BSIZE : total_req_cnt;
        size_t receive_cnt = 0;
