int ext4_ewrite(struct ext4_dirent *entry, int user_src, uint64 src, uint off,
                uint n) {
    uint tot, m;
    if ((entry->attribute & ATTR_READ_ONLY) || (uint64)off + n > 0xffffffff ||
        off + n < off) {
        return -1;
    }

    int r = ext4_fseek(&entry->file, off, 0);
    if (r) {
        printf("fseek failed!\n");
        return -r;
    }

    char *true_src = (char *)kmalloc(n);
    either_copyin(true_src, user_src, src, n);
    size_t wcnt = 0;
    r = ext4_fwrite(&entry->file, (void *)true_src, n, &wcnt);
    if (r) {
        printf("fwrite failed!\n");
        return -r;
    }
    if (true_src) kfree(true_src);

    return wcnt;
}

