void ext4_eput(struct ext4_dirent *entry) {
    acquire(&fcache.lock);
    if (entry->ref == 1 && &root_entry != entry && entry->valid) {
        // ref == 1 means no other process can have entry locked,
        // so this acquiresleep() won't block (or deadlock).
        acquiresleep(&entry->lock);
        entry->next->prev = entry->prev;
        entry->prev->next = entry->next;
        entry->next = root_entry.next;
        entry->prev = &root_entry;
        root_entry.next->prev = entry;
        root_entry.next = entry;
        release(&fcache.lock);
        if (entry->valid != -1) {
            // ext4_elock(entry->parent);
            // // eupdate(entry);
            // ext4_eunlock(entry->parent);
        } else {
            // etrunc(entry);
        }
        releasesleep(&entry->lock);

        // Once entry->ref decreases down to 0, we can't guarantee the
        // entry->parent field remains unchanged. Because eget() may take the
        // entry away and write it.
        // struct ext4_dirent *eparent = entry->parent;
        acquire(&fcache.lock);
        --entry->ref;
        release(&fcache.lock);
        // if (!entry->ref) {
        //     ext4_eput(eparent);
        // }
        return;
    }
    --entry->ref;
    release(&fcache.lock);
}

