void ext4_init_filecache() {
    initlock(&fcache.lock, "fcache");
    memset(&root_entry, 0, sizeof(root_entry));
    initsleeplock(&root_entry.lock, "entry");
    root_entry.attribute = (EXT4_ATTR_SYSTEM | EXT4_ATTR_DIRECTORY);
    int r = ext4_dir_open(&root_entry.dir, "/");
    // root.cur_clus = root.first_clus = fat.bpb.root_clus;
    // root_entry.cur_block =
    root_entry.prev = &root_entry, root_entry.next = &root_entry;
    root_entry.valid = 1;
    root_entry.parent = 0;
    root_entry.ref = 0;
    root_entry.dirty = 0;
    root_entry.dev = 0;
    root_entry.cur_block = 0;
    root_entry.block_cnt = 0;

    for (struct ext4_dirent *de = fcache.entries;
         fcache.entries + MAX_FILE > de; ++de) {
        de->parent = 0;
        de->ref = 0;
        de->dirty = 0;
        de->valid = 0;
        de->dev = 0;
        de->next = root_entry.next, de->prev = &root_entry;
        initsleeplock(&de->lock, "entry");
        root_entry.next->prev = de, root_entry.next = de;
    }
    return;
}

