struct ext4_dirent *ext4_getdir_fcache(struct ext4_dirent *parent, char *name) {
    acquire(&fcache.lock);
    struct ext4_dirent *ep;
    if (0 != name) {
        for (ep = root_entry.next; &root_entry != ep;
             ep = ep->next) {  // LRU algo
            if (!strncmp(ep->filename, name, EXT4_MAX_FILENAME) &&
                ep->parent == parent && ep->valid == 1) {
                if (0 == ep->ref) {
                    ++ep->ref;
                    ++ep->parent->ref;
                }
                // printf("not dead 21\n");
                release(&fcache.lock);
                // edup(ep->parent);
                return ep;
            }
        }
    }
    // printf("not dead3\n");
    for (ep = root_entry.prev; &root_entry != ep; ep = ep->prev) {  // LRU algo
        if (!ep->ref) {
            ep->valid = 1;
            ep->dirty = 0;
            ep->off = 0;
            ep->dev = parent->dev;
            ep->ref = 1;
            strncpy(ep->filename, name, EXT4_MAX_FILENAME);
            release(&fcache.lock);
            return ep;
        }
    }
    panic("ext4 dir get: insufficient ecache");

    return 0;
}

