    int sector_start = Buf->sectorno * 8;

    int r = 0;
    for (uint64 i = 0; i < BSIZE / 512; ++i) {
        r = sd_read_block(sector_start + i, (buf + i * SECTOR_SIZE));
    }
}

void sdcard_write_block(struct buf *Buf, void *buf) {
    int sector_start = Buf->sectorno * 8;

    int r = 0;
    for (uint64 i = 0; i < BSIZE / 512; ++i) {
        r = sd_write_block(sector_start + i, (buf + i * SECTOR_SIZE));
    }
}

