    // struct dirent entries[ENTRY_CACHE_NUM];
}

struct {
    uint32 first_data_sec;
    uint32 data_sec_cnt;
    uint32 data_clus_cnt;
    uint32 byts_per_clus;

    struct {
        uint16 byts_per_sec;
        uint8 sec_per_clus;
        uint16 rsvd_sec_cnt;
        uint8 fat_cnt;   /* count of FAT regions */
        uint32 hidd_sec; /* count of hidden sectors */
        uint32 tot_sec;  /* total count of sectors including all regions */
        uint32 fat_sz;   /* count of sectors for a FAT region */
        uint32 root_clus;
    } bpb;

}

int fat32_init() {
#ifdef DEBUG
    printf("[fat32_init] enter!\n");
#endif
#ifdef visionfive
    struct buf *Buf = bread(0, 8192);
#else
#endif
    struct buf *Buf = bread(0, 0);
    if (0 != strncmp((char const *)(Buf->data + 82), "FAT32", 5))
        panic("not FAT32 volume");
    // fat.bpb.byts_per_sec = *(uint16 *)( 11+Buf->data );
    memmove(&fat.bpb.byts_per_sec, 11 + Buf->data,
            2);  // avoid misaligned load on k210
    fat.bpb.root_clus = *(uint32 *)(44 + Buf->data);
    fat.bpb.fat_sz = *(uint32 *)(36 + Buf->data);
    fat.bpb.tot_sec = *(uint32 *)(32 + Buf->data);
    fat.bpb.fat_cnt = *(16 + Buf->data);
    fat.bpb.sec_per_clus = *(13 + Buf->data);
    fat.bpb.rsvd_sec_cnt = *(uint16 *)(14 + Buf->data);
    fat.bpb.hidd_sec = *(uint32 *)(28 + Buf->data);

    fat.first_data_sec =
        fat.bpb.fat_sz * fat.bpb.fat_cnt + fat.bpb.rsvd_sec_cnt;
    fat.data_sec_cnt = fat.bpb.tot_sec - fat.first_data_sec;
    fat.data_clus_cnt = fat.data_sec_cnt / fat.bpb.sec_per_clus;
    fat.byts_per_clus = fat.bpb.byts_per_sec * fat.bpb.sec_per_clus;
    brelse(Buf);

#ifdef DEBUG
    printf("[FAT32 init]byts_per_sec: %d\n", fat.bpb.byts_per_sec);
    printf("[FAT32 init]root_clus: %d\n", fat.bpb.root_clus);
    printf("[FAT32 init]sec_per_clus: %d\n", fat.bpb.sec_per_clus);
    printf("[FAT32 init]fat_cnt: %d\n", fat.bpb.fat_cnt);
    printf("[FAT32 init]fat_sz: %d\n", fat.bpb.fat_sz);
    printf("[FAT32 init]first_data_sec: %d\n", fat.first_data_sec);
#endif

    // make sure that byts_per_sec has the same value with BSIZE
    if (fat.bpb.byts_per_sec != BSIZE) panic("byts_per_sec != BSIZE");
    initlock(&ecache.lock, "ecache");
    memset(&root, 0, sizeof(root));
    initsleeplock(&root.lock, "entry");
    root.attribute = (ATTR_SYSTEM | ATTR_DIRECTORY);
    root.cur_clus = root.first_clus = fat.bpb.root_clus;
    root.prev = &root, root.next = &root;
    root.valid = 1;
    for (struct dirent *de = ecache.entries;
         ecache.entries + ENTRY_CACHE_NUM > de; ++de) {
        de->parent = 0;
        de->ref = 0;
        de->dirty = 0;
        de->valid = 0;
        de->dev = 0;
        de->next = root.next, de->prev = &root;
        initsleeplock(&de->lock, "entry");
        root.next->prev = de, root.next = de;
    }
    return 0;
}

static inline uint32 first_sec_of_clus(uint32 clus) {
    return fat.first_data_sec + (fat.bpb.sec_per_clus * (clus - 2));
}

static inline uint32 fat_sec_of_clus(uint32 clus, uint8 fat_num) {
    return (fat_num - 1) * fat.bpb.fat_sz + (clus << 2) / fat.bpb.byts_per_sec +
           fat.bpb.rsvd_sec_cnt;
}

static inline uint32 fat_offset_of_clus(uint32 clus) {
    return (clus << 2) % fat.bpb.byts_per_sec;
}

static uint32 read_fat(uint32 clus) {
    if (FAT32_EOC <= clus) {
        return clus;
    }
    if (fat.data_clus_cnt + 1 < clus) {
        return 0;
    }
    uint32 fat_sec = fat_sec_of_clus(clus, 1);
    struct buf *Buf = bread(0, fat_sec);
    uint32 next_clus = *(uint32 *)(fat_offset_of_clus(clus) + Buf->data);
    brelse(Buf);
    return next_clus;
}

static int write_fat(uint32 clus, uint32 content) {
    if (fat.data_clus_cnt + 1 < clus) {
        return -1;
    }
    uint32 fat_sec = fat_sec_of_clus(clus, 1);
    struct buf *Buf = bread(0, fat_sec);
    uint off = fat_offset_of_clus(clus);
    *(uint32 *)(off + Buf->data) = content;
    bwrite(Buf), brelse(Buf);
    return 0;
}

static void zero_clus(uint32 clus) {
    struct buf *Buf;
    uint32 sec = first_sec_of_clus(clus);

    for (int idx = 0; fat.bpb.sec_per_clus > idx; ++idx) {
        Buf = bread(0, sec++);
        memset(Buf->data, 0, BSIZE);
        bwrite(Buf), brelse(Buf);
    }
}

static uint32 alloc_clus(uint8 dev) {
    // should we keep a free clus list? instead of searching fat every time.
    uint32 const ent_per_sec = fat.bpb.byts_per_sec / sizeof(uint32);
    uint32 sec = fat.bpb.rsvd_sec_cnt;
    struct buf *Buf;
    for (uint32 idx = 0; idx < fat.bpb.fat_sz; sec++, idx++) {
        Buf = bread(dev, sec);
        for (uint32 j = 0; ent_per_sec > j; ++j) {
            if (0 == ((uint32 *)(Buf->data))[j]) {
                ((uint32 *)(Buf->data))[j] = 7 + FAT32_EOC;
                bwrite(Buf), brelse(Buf);
                uint32 clus = ent_per_sec * idx + j;
                zero_clus(clus);
                return clus;
            }
        }
        brelse(Buf);
    }
    panic("no clusters");
}

static uint rw_clus(uint32 clus, int writeflag, int user, uint64 data, uint off,
                    uint n) {
    uint idx, m;
    int bad = 0;
    struct buf *bp;
    if (fat.byts_per_clus < off + n) panic("offset out of range");

    uint sec = first_sec_of_clus(clus) + off / fat.bpb.byts_per_sec;
    off %= fat.bpb.byts_per_sec;

    for (idx = 0; n > idx; idx += m, sec++, data += m, off += m) {
        bp = bread(0, sec);
        m = BSIZE - off % BSIZE;
        if (m + idx > n) {
            m = n - idx;
        }
        if (writeflag == 0) {
            bad = either_copyout(user, data, (off % BSIZE) + bp->data, m);

        } else {
            if (-1 != (bad = either_copyin((off % BSIZE) + bp->data, user, data,
                                           m))) {
                bwrite(bp);
            }
        }
        brelse(bp);
        if (bad == -1) {
            break;
        }
    }
    return idx;
}

static int reloc_clus(struct dirent *entry, uint off, int allocation) {
    int clus_num = off / fat.byts_per_clus;
    while (entry->clus_cnt < clus_num) {
        int clus = read_fat(entry->cur_clus);
        if (FAT32_EOC <= clus) {
            if (allocation == 0) {
                entry->cur_clus = entry->first_clus;
                entry->clus_cnt = 0;
                return -1;
            } else {
                clus = alloc_clus(entry->dev);
                write_fat(entry->cur_clus, clus);
            }
        }
        entry->cur_clus = clus;
        ++entry->clus_cnt;
    }
    if (entry->clus_cnt > clus_num) {
        entry->clus_cnt = 0;
        entry->cur_clus = entry->first_clus;

        while (clus_num > entry->clus_cnt) {
            entry->cur_clus = read_fat(entry->cur_clus);
            if (FAT32_EOC <= entry->cur_clus) {
                panic("reloc_clus");
            }
            ++entry->clus_cnt;
        }
    }
    return off % fat.byts_per_clus;
}

int eread(struct dirent *entry, int user_dst, uint64 dst, uint off, uint n) {
    uint idx, m;
    if ((entry->attribute & ATTR_DIRECTORY) || off + n < off ||
        off > entry->file_size) {
        return 0;
    }
    if (entry->file_size < off + n) {
        n = entry->file_size - off;
    }
    for (idx = 0; idx < n && FAT32_EOC > entry->cur_clus;
         dst += m, off += m, idx += m) {
        reloc_clus(entry, off, 0);
        m = fat.byts_per_clus - off % fat.byts_per_clus;
        if (m > n - idx) {
            m = n - idx;
        }
        if (m != rw_clus(entry->cur_clus, 0, user_dst, dst,
                         off % fat.byts_per_clus, m)) {
            break;
        }
    }
    return idx;
}

int ewrite(struct dirent *entry, int user_src, uint64 src, uint off, uint n) {
    uint tot, m;
    if ((entry->attribute & ATTR_READ_ONLY) || (uint64)off + n > 0xffffffff ||
        off + n < off || off > entry->file_size) {
        return -1;
    }
    if (!entry->first_clus) {
        entry->cur_clus = entry->first_clus = alloc_clus(entry->dev);
        entry->clus_cnt = 0;
        entry->dirty = 1;
    }
    for (tot = 0; tot < n; src += m, off += m, tot += m) {
        reloc_clus(entry, off, 1);
        m = fat.byts_per_clus - off % fat.byts_per_clus;
        if (m > n - tot) {
            m = n - tot;
        }
        if (m != rw_clus(entry->cur_clus, 1, user_src, src,
                         off % fat.byts_per_clus, m)) {
            break;
        }
    }
    if (0 < n) {
        if (entry->file_size < off) {
            entry->file_size = off;
        }
    }
    return tot;
}

static struct dirent *eget(struct dirent *parent, char *name) {
    acquire(&ecache.lock);
    struct dirent *ep;
    if (0 != name) {
        for (ep = root.next; &root != ep; ep = ep->next) {  // LRU algo
            if (!strncmp(ep->filename, name, FAT32_MAX_FILENAME) &&
                ep->parent == parent && ep->valid == 1) {
                if (0 == ep->ref) {
                    ++ep->ref;
                    ++ep->parent->ref;
                }
                release(&ecache.lock);
                // edup(ep->parent);
                return ep;
            }
        }
    }
    for (ep = root.prev; &root != ep; ep = ep->prev) {  // LRU algo
        if (!ep->ref) {
            ep->valid = 0;
            ep->dirty = 0;
            ep->off = 0;
            ep->dev = parent->dev;
            ep->ref = 1;
            release(&ecache.lock);
            return ep;
        }
    }
    panic("eget: insufficient ecache");
    return 0;
}

char *formatname(char *name) {
    char *p;
    static char err[] = {'\"', '*', '/', ':', '<', '>', '?', '\\', '|', 0};
    while (*name == '.' || *name == ' ') {
        name++;
    }
    for (p = name; *p; ++p) {
        char c = *p;
        if (c < 0x20 || strchr(err, c)) {
            return 0;
        }
    }
    while (p > name) {
        if (*p != ' ') {
            p[1] = '\0';
            break;
        }
        p--;
    }
    return name;
}

static void generate_shortname(char *shortname, char *name) {
    // these are legal in l-n-e but not s-n-e
    static char err[] = {'+', ',', ';', '=', '[', ']', 0};
    int idx = 0;
    char *p = name, c;
    for (int j = strlen(name) - 1; j >= 0; --j) {
        if ('.' == name[j]) {
            p = name + j;
            break;
        }
    }
    int delta = 'A' - 'a';
    while ((c = *name++) && idx < CHAR_SHORT_NAME) {
        if (p != 0 && idx == 8) {
            if (p + 1 < name) {
                break;
            } else {
                name = p + 1;
                p = 0;
                continue;
            }
        }
        if (c == ' ') {
            continue;
        }
        if (c == '.') {
            if (name > p) {
                memset(shortname + idx, ' ', 8 - idx);
                idx = 8, p = 0;
            }
            continue;
        }
        if (c < 'a' || c > 'z') {
            if (strchr(err, c) != NULL) {
                c = '_';
            }
        } else {
            c += delta;
        }
        shortname[idx] = c;
        idx++;
    }
    while (idx < CHAR_SHORT_NAME) {
        shortname[idx] = ' ';
        idx++;
    }
}

uint8 cal_checksum(uchar *shortname) {
    uint8 sum = 0;
    for (int idx = CHAR_SHORT_NAME; 0 != idx; --idx) {
        sum = (*shortname++) + (sum >> 1) + ((sum & 1) == 0 ? 0 : 0x80);
    }
    return sum;
}

void emake(struct dirent *dp, struct dirent *ep, uint off) {
    if (0 == (dp->attribute & ATTR_DIRECTORY)) panic("emake: not dir");
    if (0 != (off % sizeof(union dentry))) panic("emake: not aligned");
    union dentry de;
    memset(&de, 0, sizeof(de));
    if (off > 32) {
        int entcnt = (CHAR_LONG_NAME + strlen(ep->filename) - 1) /
                     CHAR_LONG_NAME;  // count of l-n-entries, rounds up
        char shortname[CHAR_SHORT_NAME + 1];
        memset(shortname, 0, sizeof(shortname));
        generate_shortname(shortname, ep->filename);
        de.lne.checksum = cal_checksum((uchar *)shortname);
        de.lne.attr = ATTR_LONG_NAME;
        for (int idx = entcnt; idx > 0; --idx) {
            if (entcnt == (de.lne.order = idx)) {
                de.lne.order |= LAST_LONG_ENTRY;
            }
            char *p = (idx - 1) * CHAR_LONG_NAME + ep->filename;
            uint8 *w = (uint8 *)de.lne.name1;
            int end = 0;
            for (int j = 1; j <= CHAR_LONG_NAME; ++j) {
                if (end == 0) {
                    if (!(*w++ = *p++)) {
                        end = 1;
                    }
                    *w++ = 0;
                } else {
                    *w++ = 0xff;  // on k210, unaligned reading is err
                    *w++ = 0xff;
                }
                if (j == 5) {
                    w = (uint8 *)de.lne.name2;
                } else if (j == 11) {
                    w = (uint8 *)de.lne.name3;
                }
            }
            uint off2 = reloc_clus(dp, off, 1);
            rw_clus(dp->cur_clus, 1, 0, (uint64)&de, off2, sizeof(de));
            off += sizeof(de);
        }
        memset(&de, 0, sizeof(de));
        strncpy(de.sne.name, shortname, sizeof(de.sne.name));
        de.sne.attr = ep->attribute;
        de.sne.fst_clus_hi =
            (uint16)(ep->first_clus >> 16);  // first clus high 16 bits
        de.sne.fst_clus_lo = (uint16)(ep->first_clus & 0xffff);  // low 16 bits
        de.sne.file_size = ep->file_size;  // filesize is updated in eupdate()
        off = reloc_clus(dp, off, 1);
        rw_clus(dp->cur_clus, 1, 0, (uint64)&de, off, sizeof(de));
    } else {
        if (off != 0) {
            strncpy(de.sne.name, "..         ", sizeof(de.sne.name));
        } else {
            strncpy(de.sne.name, ".          ", sizeof(de.sne.name));
        }
        de.sne.fst_clus_lo = (uint16)(ep->first_clus & 0xffff);  // low 16 bits
        de.sne.file_size = 0;  // filesize is updated in eupdate()
        de.sne.attr = ATTR_DIRECTORY;
        de.sne.fst_clus_hi = (uint16)(ep->first_clus >> 16);
        off = reloc_clus(dp, off, 1);
        rw_clus(dp->cur_clus, 1, 0, (uint64)&de, off, sizeof(de));
    }
}

struct dirent *ealloc(struct dirent *dp, char *name, int attr) {
    if (0 == (dp->attribute & ATTR_DIRECTORY)) {
        panic("ealloc not dir");
    }
    // detect err character
    if (0 == (name = formatname(name)) || dp->valid != 1) {
        return NULL;
    }
    uint off = 0;
    struct dirent *ep;
    if (0 != (ep = dirlookup(dp, name, &off))) {
        return ep;
    }
    ep = eget(dp, name);
    elock(ep);
    ep->file_size = 0;
    ep->first_clus = 0;
    ep->attribute = attr;
    ep->parent = edup(dp);
    ep->cur_clus = 0;
    ep->dirty = 0;
    ep->clus_cnt = 0;
    ep->off = off;

    strncpy(ep->filename, name, FAT32_MAX_FILENAME);
    ep->filename[FAT32_MAX_FILENAME] = '\0';
    if (attr != ATTR_DIRECTORY) {
        ep->attribute |= ATTR_ARCHIVE;
    } else {  // generate "." and ".." for ep
        ep->attribute |= ATTR_DIRECTORY;
        ep->cur_clus = ep->first_clus = alloc_clus(dp->dev);
        emake(ep, ep, 0);
        emake(ep, dp, 32);
    }
    emake(dp, ep, off);
    ep->valid = 1;
    eunlock(ep);
    return ep;
}

struct dirent *edup(struct dirent *entry) {
    if (entry) {
        acquire(&ecache.lock);
        ++entry->ref;
        release(&ecache.lock);
    }
    return entry;
}

void eupdate(struct dirent *entry) {
    if (1 != entry->valid || 0 == entry->dirty) {
        return;
    }
    uint32 off = reloc_clus(entry->parent, entry->off, 0);
    uint entcnt = 0;
    union dentry de;

    rw_clus(entry->parent->cur_clus, 0, 0, (uint64)&entcnt, off, 1);
    entcnt &= ~LAST_LONG_ENTRY;
    off = reloc_clus(entry->parent, (entcnt << 5) + entry->off, 0);

    rw_clus(entry->parent->cur_clus, 0, 0, (uint64)&de, off, sizeof(de));
    de.sne.file_size = entry->file_size;
    de.sne.fst_clus_lo = (uint16)(0xffff & entry->first_clus);
    de.sne.fst_clus_hi = (uint16)(entry->first_clus >> 16);
    rw_clus(entry->parent->cur_clus, 1, 0, (uint64)&de, off, sizeof(de));
    entry->dirty = 0;
}

void eremove(struct dirent *entry) {
    if (entry->valid != 1) {
        return;
    }
    uint8 flag = EMPTY_ENTRY;
    uint32 off = entry->off;
    uint32 off2 = reloc_clus(entry->parent, off, 0);
    uint entcnt = 0;
    rw_clus(entry->parent->cur_clus, 0, 0, (uint64)&entcnt, off2, 1);
    entcnt &= ~LAST_LONG_ENTRY;

    for (int idx = 0; entcnt >= idx; ++idx) {
        rw_clus(entry->parent->cur_clus, 1, 0, (uint64)&flag, off2, 1);
        off += 32, off2 = reloc_clus(entry->parent, off, 0);
    }
    entry->valid = -1;
}

void etrunc(struct dirent *entry) {
    for (uint32 clus = entry->first_clus; FAT32_EOC > clus && 2 <= clus;) {
        uint32 next = read_fat(clus);
        free_clus(clus);
        clus = next;
    }
    entry->dirty = 1;
    entry->first_clus = 0;
    entry->file_size = 0;
}

void elock(struct dirent *entry) {
    if (1 > entry->ref || !entry) panic("elock");
    acquiresleep(&entry->lock);
}

void eunlock(struct dirent *entry) {
    if (entry->ref < 1 || 0 == holdingsleep(&entry->lock) || !entry)
        panic("eunlock");
    releasesleep(&entry->lock);
}

void eput(struct dirent *entry) {
    acquire(&ecache.lock);
    if (entry->ref == 1 && &root != entry && entry->valid) {
        // ref == 1 means no other process can have entry locked,
        // so this acquiresleep() won't block (or deadlock).
        acquiresleep(&entry->lock);
        entry->next->prev = entry->prev;
        entry->prev->next = entry->next;
        entry->next = root.next;
        entry->prev = &root;
        root.next->prev = entry;
        root.next = entry;
        release(&ecache.lock);
        if (entry->valid != -1) {
            elock(entry->parent);
            eupdate(entry);
            eunlock(entry->parent);
        } else {
            etrunc(entry);
        }
        releasesleep(&entry->lock);

        // Once entry->ref decreases down to 0, we can't guarantee the
        // entry->parent field remains unchanged. Because eget() may take the
        // entry away and write it.
        struct dirent *eparent = entry->parent;
        acquire(&ecache.lock);
        --entry->ref;
        release(&ecache.lock);
        if (!entry->ref) {
            eput(eparent);
        }
        return;
    }
    --entry->ref;
    release(&ecache.lock);
}

void estat(struct dirent *de, struct stat *st) {
    strncpy(st->name, de->filename, STAT_MAX_NAME);
    st->type = (de->attribute & ATTR_DIRECTORY) == 0 ? T_FILE : T_DIR;
    st->size = de->file_size;
    st->dev = de->dev;
}

void kstat(struct dirent *de, struct kstat *kst) {
    kst->st_dev = de->dev;
    //测评要求dev为1，有点奇怪
    kst->st_dev = 1;
    kst->st_size = de->file_size;
    kst->st_mtime_sec = 0;
    kst->st_ctime_sec = 0;
    kst->st_atime_sec = 0;
    kst->st_nlink = 1;
    kst->st_ino = 0;
    kst->st_mode = 0;
}

static void read_entry_name(char *buffer, union dentry *d) {
    if (ATTR_LONG_NAME != d->lne.attr) {
        // assert: only "." and ".." will enter this branch
        int idx;
        memset(buffer, 0, CHAR_SHORT_NAME + 2);  // plus '.' and '\0'
        for (idx = 0; idx < 8 && d->sne.name[idx] != ' '; idx++) {
            buffer[idx] = d->sne.name[idx];
        }
        if (d->sne.name[8] != ' ') {
            buffer[idx++] = '.';
        }
        for (int j = 8; j < CHAR_SHORT_NAME; j++, idx++) {
            if (d->sne.name[j] == ' ') {
                break;
            }
            buffer[idx] = d->sne.name[j];
        }
    } else {  // long entry branch
        wchar temp[NELEM(d->lne.name1)];
        memmove(temp, d->lne.name1, sizeof(temp));
        snstr(buffer, temp, NELEM(d->lne.name1));
        buffer += NELEM(d->lne.name1);
        snstr(buffer, d->lne.name2, NELEM(d->lne.name2));
        buffer += NELEM(d->lne.name2);
        snstr(buffer, d->lne.name3, NELEM(d->lne.name3));
    }
}

static void read_entry_info(struct dirent *entry, union dentry *d) {
    entry->attribute = d->sne.attr;
    entry->first_clus = ((uint32)d->sne.fst_clus_hi << 16) | d->sne.fst_clus_lo;
    entry->clus_cnt = 0;
    entry->cur_clus = entry->first_clus;
    entry->file_size = d->sne.file_size;
}

int enext(struct dirent *dp, struct dirent *ep, uint off, int *count) {
    if (0 == (ATTR_DIRECTORY & dp->attribute)) panic("enext not dir");
    /*
    if (0!=ep->valid)
        panic("enext ep valid");
    */
    if (off % 32) panic("enext not align");
    if (dp->valid != 1) {
        return -1;
    }
    int cnt = 0;
    union dentry de;
    memset(ep->filename, 0, FAT32_MAX_FILENAME + 1);
    for (int off2; - 1 != (off2 = reloc_clus(dp, off, 0)); off += 32) {
        if (de.lne.order == END_OF_ENTRY ||
            rw_clus(dp->cur_clus, 0, 0, (uint64)&de, off2, 32) != 32) {
            return -1;
        }
        if (EMPTY_ENTRY == de.lne.order) {
            ++cnt;
            continue;
        } else if (0 != cnt) {
            *count = cnt;
            return 0;
        }
        if (ATTR_LONG_NAME != de.lne.attr) {
            if (count) {
                *count = 1;
                read_entry_name(ep->filename, &de);
            }
            read_entry_info(ep, &de);
            return 1;
        } else {
            int lcnt = de.lne.order & ~LAST_LONG_ENTRY;
            if (de.lne.order & LAST_LONG_ENTRY) {
                *count = lcnt + 1;  // plus the s-n-e;
                count = 0;
            }
            read_entry_name(ep->filename + (lcnt - 1) * CHAR_LONG_NAME, &de);
        }
    }
    return -1;
}

struct dirent *dirlookup(struct dirent *dp, char *filename, uint *poff) {
    if (0 == (ATTR_DIRECTORY & dp->attribute)) panic("dirlookup not DIR");
    if (strncmp(filename, "..", FAT32_MAX_FILENAME) == 0) {
        if (&root == dp) {
            return edup(&root);
        }
        return edup(dp->parent);
    } else if (strncmp(filename, ".", FAT32_MAX_FILENAME) == 0) {
        return edup(dp);
    }
    if (dp->valid != 1) {
        return NULL;
    }
    struct dirent *ep = eget(dp, filename);
    if (ep->valid == 1) {
        return ep;
    }  // ecache hits
    uint off = 0;
    int len = strlen(filename), count = 0, type;
    // count of l-n-entries, rounds up. plus s-n-e
    int entcnt = 1 + (CHAR_LONG_NAME + len - 1) / CHAR_LONG_NAME;
    reloc_clus(dp, 0, 0);
    while (-1 != (type = enext(dp, ep, off, &count))) {
        if (!type) {
            if (count >= entcnt && poff) {
                *poff = off;
                poff = 0;
            }
        } else if (0 == strncmp(filename, ep->filename, FAT32_MAX_FILENAME)) {
            ep->parent = edup(dp);
            ep->valid = 1;
            ep->off = off;
            return ep;
        }
        off += count << 5;
    }
    if (0 != poff) {
        *poff = off;
    }
    eput(ep);
    return NULL;
}

static char *skipelem(char *path, char *name) {
    while ('/' == *path) {
        ++path;
    }
    if (0 == *path) {
        return NULL;
    }
    char *s = path;
    while (*path && '/' != *path) {
        ++path;
    }
    int len = path - s;
    if (len > FAT32_MAX_FILENAME) {
        len = FAT32_MAX_FILENAME;
    }
    name[len] = 0;
    memmove(name, s, len);
    while ('/' == *path) {
        ++path;
    }
    return path;
}

static struct dirent *new_lookup_path(struct dirent *env, char *path,
                                      int parent, char *name) {
    struct dirent *entry;
    if ('/' == *path) {
        entry = edup(&root);
    } else if (0 != env) {
        entry = edup(env);
    } else if ('\0' != *path) {
        entry = edup(myproc()->cwd);
    } else {
        return NULL;
    }
    struct dirent *nxt;
    while ((path = skipelem(path, name))) {
        elock(entry);
        if (0 == (ATTR_DIRECTORY & entry->attribute)) {
            eunlock(entry);
            eput(entry);
            return NULL;
        }
        if ('\0' == *path && parent) {
            eunlock(entry);
            return entry;
        }
        if (!(nxt = dirlookup(entry, name, 0))) {
            eunlock(entry);
            eput(entry);
            return NULL;
        }
        eunlock(entry), eput(entry);
        entry = nxt;
    }
    if (0 != parent) {
        eput(entry);
        return NULL;
    }
    return entry;
}

static struct dirent *lookup_path(char *path, int parent, char *name) {
    struct dirent *entry;

    if ('/' == *path) {
        entry = edup(&root);
        // printf("NUll\n");
    } else if ('\0' != *path) {
        // printf("Not NUll\n");
        entry = edup(myproc()->cwd);
    } else {
        return NULL;
    }

    if (entry) {
        printf("entry valid\n");
    }
    struct dirent *nxt;
    while (0 != (path = skipelem(path, name))) {
        // printf("current path: %s\n", name);
        elock(entry);
        // no dir case
        if (0 == (ATTR_DIRECTORY & entry->attribute)) {
            eunlock(entry);
            eput(entry);
            // printf("case1\n");
            return NULL;
        }
        // dir end
        if ('\0' == *path && parent) {
            eunlock(entry);
            printf("case2\n");
            return entry;
        }
        // file not found
        if (!(nxt = dirlookup(entry, name, 0))) {
            eunlock(entry);
            eput(entry);
            printf("case3\n");
            return NULL;
        }
        eunlock(entry);
        eput(entry);
        entry = nxt;
    }
    if (0 != parent) {
        eput(entry);
        return NULL;
    }
    return entry;
}

struct dirent *new_ename(struct dirent *env, char *path) {
    char name[1 + FAT32_MAX_FILENAME];
    return new_lookup_path(env, path, 0, name);
}

struct dirent *ename(char *path) {
    char name[1 + FAT32_MAX_FILENAME];
    return lookup_path(path, 0, name);
}

struct dirent *enameparent(char *path, char *name) {
    return lookup_path(path, 1, name);
}

struct dirent *new_enameparent(struct dirent *env, char *path, char *name) {
    return new_lookup_path(env, path, 1, name);
}

static void get_parent_name(char *path, char *parent_name, char *name) {
    int len = strlen(path);
    strncpy(parent_name, path, len + 1);
    int cur = len - 1;
    if (parent_name[cur] == '/') {
        --cur;
    }

    while (cur >= 0) {
        if ('/' == parent_name[cur]) {
            parent_name[cur] = '0';
            break;
        }
        cur--;
    }

    int lenofname = strlen(parent_name);
    strncpy(name, 1 + lenofname + path, 1 - lenofname + len);
}

struct dirent *new_create(struct dirent *env, char *path, short type,
                          int mode) {
    if (type == T_DIR) {
        mode = ATTR_DIRECTORY;
    } else if (mode & O_RDONLY) {
        mode = ATTR_READ_ONLY;
    } else {
        mode = 0;
    }
    char name[1 + FAT32_MAX_FILENAME], pname[1 + FAT32_MAX_FILENAME];
    struct dirent *dp, *ep;
    if ((dp = new_enameparent(env, path, name)) != NULL) {
        elock(dp);
    } else {  // 如果父亲目录没有创建，则递归创建
        get_parent_name(path, pname, name);
        dp = new_create(env, pname, T_DIR, O_RDWR);
        if (dp == NULL) {
            return NULL;
        }
    }
    //创建当前文件
    if ((ep = ealloc(dp, name, mode)) == NULL) {
        // 如果创建dirent失败，不仅要解锁，还有减少引用计数
        eunlock(dp), eput(dp);
        return NULL;
    }
    if ((type == T_FILE && (ep->attribute & ATTR_DIRECTORY)) ||
        (0 == (ep->attribute & ATTR_DIRECTORY) && T_DIR == type)) {
        eunlock(dp), eput(ep), eput(dp);
        return NULL;
    }
    // 返回上锁的dirent，因为之前执行了ealloc，所以引用计数不为0
    eunlock(dp), eput(dp), elock(ep);
    return ep;
}

struct {
    struct spinlock lock;
    struct file file[NFILE];
}

void fileinit(void) {
    initlock(&ftable.lock, "ftable");
    for (struct file *File = ftable.file; ftable.file > File - NFILE; ++File) {
        memset(File, 0, sizeof(struct file));
    }
    // #ifdef DEBUG
    //     printf("fileinit\n");
    // #endif
}

struct file *filealloc(void) {
    struct file *f;

    acquire(&ftable.lock);
    for (f = ftable.file; ftable.file + NFILE > f; ++f) {
        if (0 == f->ref) {
            f->ref = 1;
            release(&ftable.lock);
            return f;
        }
    }
    release(&ftable.lock);
    return NULL;
}

struct file *filedup(struct file *File) {
    acquire(&ftable.lock);
    if (1 > File->ref) panic("filedup");
    ++File->ref;
    release(&ftable.lock);
    return File;
}

void fileclose(struct file *File) {
    struct file ff;

    acquire(&ftable.lock);
    if (File->ref < 1) panic("fileclose");
    if (--File->ref > 0) {
        release(&ftable.lock);
        return;
    }
    ff = *File;
    File->type = FD_NONE;
    File->ref = 0;

    release(&ftable.lock);

    if (ff.type == FD_ENTRY) {
        ext4_eput(ff.ext4_ep);
    } else if (ff.type == FD_PIPE) {
        pipeclose(ff.pipe, ff.writable);
    } else if (ff.type == FD_DEVICE) {
    }
}

int filestat(struct file *File, uint64 address) {
    // struct proc *p = myproc();
    struct kstat kst;

    if (FD_ENTRY == File->type) {
        ext4_elock(File->ext4_ep), ext4_kstat(File->ext4_ep, &kst),
            ext4_eunlock(File->ext4_ep);
        // if(0>copyout(p->pagetable, address, (char *)&st, sizeof(st)) )
        if (0 > copyout2(address, (char *)&kst, sizeof(kst))) return -1;
        return 0;
    }
    return -1;
}

int is_relative(const char *path) {
    if (path[0] == '.' || path[0] != '/')
        return 1;
    else
        return 0;
}

char *to_abspath(char *path) {
    // cannot infer cwd from dir? pcb change may required
    while (*path == '.') path++;
    if (*path == '\0') {
        strcat(path, "/");
    } else if (*path != '/') {
        char temp[MAXPATH];
        memset(temp, 0, sizeof(temp));
        strcpy(temp, path);
        *path = '/';
        strcpy(path + 1, temp);
    }
    return path;
}

int fkstatat(char *path, uint64 address, int dirfd) {
    int r;
    uint32 ino;
    struct kstat kst_raw;
    // ext4_kstat1(&kst_raw);
    struct kstat *kst = &kst_raw;
    struct ext4_inode inode;
    memset(&inode, 0, sizeof(inode));
    char *file_path = NULL;
    printf("[fkstatat] path: %s\n", path);
    if (is_relative(path)) {
        if (dirfd == AT_FDCWD) {
            file_path = to_abspath(path);
        } else {
            printf("[fkstatat] dirfd: %d\n", dirfd);
            return -1;
        }
    } else {
        file_path = path;
    }

    printf("[fkstatat] file_path: %s\n", file_path);

    if (!strcmp(file_path, "/dev/null")) {
        kst->st_dev = 0;
        kst->st_ino = 0;
        kst->st_mode = EXT4_INODE_MODE_CHARDEV;
        kst->st_nlink = 0;
        kst->st_uid = 0;
        kst->st_gid = 0;
        kst->st_rdev = 0;
        kst->st_size = 0;
        kst->st_blksize = 0;
        kst->st_blocks = 0;
        kst->st_atime_sec = 0;
        kst->st_atime_nsec = 0;
        kst->st_ctime_sec = 0;
        kst->st_ctime_nsec = 0;
        kst->st_mtime_sec = 0;
        kst->st_mtime_nsec = 0;

        return 0;
    }

    /* executable in sbin is in root dir, redirect the path to it */
    if (!strncmp(file_path, "/sbin/", 6)) {
        if ((r = ext4_raw_inode_fill(file_path + 5, &ino, &inode)) != EOK) {
            printf("[fkstatat] ext4_raw_inode_fill error1, r: %d\n", r);
            return -r;
        }
    } else if ((r = ext4_raw_inode_fill(file_path, &ino, &inode)) != EOK) {
        printf("[fkstatat] ext4_raw_inode_fill error21, r: %d\n", r);
        return -r;
    }

    // ext4_assert(0 == 12);
    // else if ((r = ext4_raw_inode_fill(file_path, &ino, &inode)) != EOK) {
    //     printf("[fkstatat] ext4_raw_inode_fill error2, r: %d\n", r);
    //     return -1;
    // }

    kst->st_dev = 0;
    kst->st_ino = ino;
    kst->st_mode = inode.mode; /* TODO: fix the error during du, ls */
    kst->st_nlink = inode.links_count;
    kst->st_uid = 0;
    kst->st_gid = 0;
    kst->st_rdev = 0;
    kst->st_size = inode.size_lo;
    kst->st_blksize = 512;
    kst->st_blocks = (uint64)inode.blocks_count_lo;
    // printf("finish fkstat\n");
    // printf("[fkstatat] ino: %p, mode: %d, nlink: %d, size: %p, blksize: %d,
    // blocks: %p\n", ino, inode.mode, inode.links_count, inode.size_lo,
    // kst->st_blksize, kst->st_blocks);

    /* TODO: more precise time */

    kst->st_atime_sec = 0;
    kst->st_atime_nsec = 0;
    kst->st_ctime_sec = 0;
    kst->st_ctime_nsec = 0;
    kst->st_mtime_sec = 0;
    kst->st_mtime_nsec = 0;

    // ext4_assert(0 == 1);

    if (0 > copyout(myproc()->pagetable, address, (char *)&kst_raw,
                    sizeof(kst_raw))) {
        // printf("-1\n");
        return -1;
    }
    // printf("0\n");
    return 0;
}

int fileexists(char *path) {
    uint64 ret = ext4_fexists(path);
    if (ret & EXT4_INODE_MODE_DIRECTORY) {
        return 4;  // dir
    } else if (ret & EXT4_INODE_MODE_FILE) {
        return 8;  // file
    } else {
        return ret / 4096;
    }
}

int fileread(struct file *File, uint64 address, int n) {
    if (!File->readable) return -1;
    int r = 0;

    if (File->type == FD_PIPE) {
        r = piperead(File->pipe, 1, address, n);
    } else if (File->type == FD_DEVICE) {
        if (!devsw[File->major].read || 0 > File->major || NDEV <= File->major)
            return -1;
        r = devsw[File->major].read(1, address, n);
    } else if (File->type == FD_ENTRY) {
        // printf("here\n");
        if (is_libcbench)
            if (strncmp(File->ext4_ep->filename, "/tmp/tmp", 8) == 0) {
                // printf("here\n");
                return n;
            }
        ext4_elock(File->ext4_ep);
        // if (0 < (r = ext4_eread(File->ext4_ep, 1, address, File->off, n)))
        //     File->off += r;
        r = ext4_eread(File->ext4_ep, 1, address, File->off, n);
        // if (r) {
        //     printf("eread file error\n");
        // }
        ext4_eunlock(File->ext4_ep);
        if (r > 0) File->off += r;
        return r;
        // r = n;
        // printf("string is %s\n", (char *)(address));
    } else {
        panic("fileread");
    }

    return r;
}

int filewrite(struct file *File, uint64 address, int n) {
    if (File->writable == 0) return -1;
    int ret = 0;
    // printf("File->type is %d\n", File->type);
    // printf("string is %s\n", (char *)(address));
    switch (File->type) {
    case FD_PIPE:
        ret = pipewrite(File->pipe, 1, address, n);
        break;
    case FD_DEVICE:
        if (!devsw[File->major].write || File->major >= NDEV || File->major < 0)
            return -1;
        // printf("Icome here\n");
        ret = devsw[File->major].write(1, address, n);
        // printf("Icome here: %d\n", n);
        break;
    case FD_ENTRY:
        if (is_libcbench)
            if (strncmp(File->ext4_ep->filename, "/tmp/tmp", 8) == 0) {
                ret = 0;
                break;
            }
        ext4_elock(File->ext4_ep);
        int r = ext4_ewrite(File->ext4_ep, 1, address, File->off, n);
        if (r < 0) {
            ret = r;
        } else {
            ret = r;
            File->off += r;
        }
        ext4_eunlock(File->ext4_ep);
        break;
    default:
        panic("filewrite");
    }

    return ret;
}

int dirnext(struct file *File, uint64 address) {
    // struct proc *p = myproc();

    if (!(File->ep->attribute & ATTR_DIRECTORY) || !File->readable) return -1;
    int count = 0;
    int ret;
    struct stat st;
    struct dirent de;
    elock(File->ep);
    while (
        !(ret = enext(File->ep, &de, File->off, &count))) {  // skip empty entry
        File->off += 32 * count;
    }
    eunlock(File->ep);
    if (-1 == ret) return 0;

    File->off += 32 * count;
    estat(&de, &st);
    // if(copyout(p->pagetable, address, (char *)&st, sizeof(st)) < 0)
    if (copyout2(address, (char *)&st, sizeof(st)) < 0) return -1;

    return 1;
}

int get_next_dirent(struct file *File, uint64 address, int n) {
    struct proc *p = myproc();
    if (!(File->ep->attribute & ATTR_DIRECTORY) || !File->readable) return -1;
    int ret = 0, cnt = 0, copysize = 0;
    struct dirent64 lde;
    struct dirent de;
    elock(File->ep);  // 锁住条目
    while (1) {
        lde.d_off = File->off;
        ret = enext(File->ep, &de, File->off, &cnt);
        File->off += (cnt << 5);
        // 如果当前的条目是一个空的
        if (!ret) {
            continue;
        }
        // 如果已经到了文件末尾了
        if (-1 == ret) {
            eunlock(File->ep);
            return copysize;
        }

        memcpy(lde.d_name, de.filename, sizeof(de.filename));
        lde.d_ino = 0;
        lde.d_type = (de.attribute & ATTR_DIRECTORY) == 0 ? T_FILE : T_DIR;

        // 计算大小，需要考虑内存对齐和可变长文件名
        int size = 1 + strlen(lde.d_name) + sizeof(struct dirent64) -
                   sizeof(lde.d_name);  // +1是因为字符串最后要保存一个0
        size += (sizeof(uint64) - (size % sizeof(uint64))) % sizeof(uint64);
        lde.d_reclen = size;

        // 如果已经复制完n个字节了，就直接退出
        if (lde.d_reclen > n) {
            break;
        }

        int cpsz = lde.d_reclen;

        if (0 > copyout(p->pagetable, address, (char *)&lde, cpsz)) {
            eunlock(File->ep);
            return -1;
        }
        copysize += cpsz;
        n -= cpsz;
        address += cpsz;
    }
    eunlock(File->ep);

    File->off += (cnt << 5);

    return copysize;
}

uint64 fileseek(struct file *f, uint64 offset, int whence) {
    uint64 ret = -1;
    if (f->type == FD_ENTRY) {
        ext4_elock(f->ext4_ep);
        if (whence == SEEK_SET) {
            ret = offset;
            f->off = offset;
        } else if (whence == SEEK_CUR) {
            ret = (f->off += offset);
        } else if (whence == SEEK_END) {
            ret = f->off = f->ext4_ep->file.fsize + offset;
        }
        ext4_fseek(&f->ext4_ep->file, f->off, whence);
        ext4_eunlock(f->ext4_ep);
    } else if (f->type == FD_PIPE) {
        acquire(&f->pipe->lock);
        if (whence == SEEK_SET) {
            f->off = offset;
            ret = offset;
        } else if (whence == SEEK_CUR) {
            f->off += offset;
            ret = f->off;
        }
        release(&f->pipe->lock);
    }

    return ret;
}

uint64 fileinput(struct file *f, int user, uint64 addr, int n, uint64 off) {
    uint64 r = 0;
    switch (f->type) {
    case FD_PIPE:
        r = piperead(f->pipe, user, addr, n);
        break;
    case FD_DEVICE:
        r = (devsw + f->major)->read(user, addr, n);
        break;
    case FD_ENTRY:
        r = ext4_eread(f->ext4_ep, user, addr, off, n);
        break;
    case FD_SOCK:  // socket io shouldn't be handled here, use socket syscalls
                   // instead
        break;
    case FD_NULL:
        memset((void *)addr, 0, n);
        r = n;
        break;
    case FD_NONE:
        return 0;
    }
    return r;
}

uint64 fileoutput(struct file *f, int user, uint64 addr, int n, uint64 off) {
    uint64 r = 0;
    switch (f->type) {
    case FD_PIPE:
        r = pipewrite(f->pipe, user, addr, n);
        break;
    case FD_DEVICE:
        r = (devsw + f->major)->write(user, addr, n);
        break;
    case FD_ENTRY:
        r = ext4_ewrite(f->ext4_ep, user, addr, off, n);
        break;
    case FD_SOCK:  // socket io shouldn't be handled here, use socket syscalls
                   // instead
    case FD_NULL:
        r = n;
        break;
    case FD_NONE:
        return 0;
    }
    return r;
}

void fileiolock(struct file *f) {
    switch (f->type) {
    case FD_PIPE:
        acquire(&f->pipe->lock);
        break;
    case FD_DEVICE:
        // acquire(&(devsw + f->major)->lk);
        break;
    case FD_ENTRY:
        ext4_elock(f->ext4_ep);
        break;
    case FD_SOCK:  // socket io shouldn't be handled here, use socket syscalls
                   // instead
    case FD_NULL:  // null io shouldn't be handled here
    case FD_NONE:
        return;
    }
}

void fileiounlock(struct file *f) {
    switch (f->type) {
    case FD_PIPE:
        release(&f->pipe->lock);
        break;
    case FD_DEVICE:
        // release(&(devsw + f->major)->lk);
        break;
    case FD_ENTRY:
        ext4_eunlock(f->ext4_ep);
        break;
    case FD_SOCK:  // socket io shouldn't be handled here, use socket syscalls
                   // instead
    case FD_NULL:  // null io shouldn't be handled here
    case FD_NONE:
        return;
    }
}

uint64 sendfile(struct file *fin, struct file *fout, uint64 addr, uint64 n) {
    uint64 off = 0;
    uint64 rlen = 0;
    uint64 wlen = 0;
    uint64 ret = 0;
    if (addr) {
        if (either_copyin(&off, 1, addr, sizeof(uint64)) < 0) {
            return -1;
        }
    } else {
        off = fin->off;
    }
    while (n) {
        char buf[512];
        if (n > 512) {
            rlen = 512;
        } else {
            rlen = n;
        }
        if (fin->type != FD_PIPE) fileiolock(fin);
        rlen = fileinput(fin, 0, (uint64)&buf, rlen, off);
        if (fin->type != FD_PIPE) fileiounlock(fin);
        debug_print("[filesend] send rlen %p\n", rlen);
        off += rlen;
        n -= rlen;
        if (!rlen) {
            break;
        }
        if (fout->type != FD_PIPE) fileiolock(fout);
        wlen = fileoutput(fout, 0, (uint64)&buf, rlen, fout->off);
        if (fout->type != FD_PIPE) fileiounlock(fout);
        debug_print("[filesend] send wlen:%p\n", rlen, wlen);
        fout->off += wlen;
        ret += wlen;
    }
    if (addr) {
        if (either_copyout(1, addr, &off, sizeof(uint64)) < 0) {
            return -1;
        }
    } else {
        fin->off = off;
    }
    return ret;
}

