static int argfd(int n, int *pfd, struct file **pf) {
    struct file *File;
    int fd;

    if (argint(n, &fd) < 0) return -1;

    // mmap映射匿名区域的时候会需要fd为-1
    if (fd == -1) {
        return -2;
    }

    if (fd == -100) {
        *pfd = fd;
        *pf = NULL;
        return 0;
    }

    if (fd == 200) {
        *pfd = fd;
        return 200;
    }

    if ((File = myproc()->ofile[fd]) == NULL || fd >= NOFILE || fd < 0)
        return -1;
    if (0 != pfd) *pfd = fd;
    if (0 != pf) *pf = File;
    return 0;
}

static int fdalloc(struct file *File) {
    struct proc *p = myproc();

    for (int fd = 0; NOFILEMAX(p) > fd; fd++) {
        if (p->ofile[fd] == 0) {
            p->ofile[fd] = File;
            return fd;
        }
    }
    return -1;
}

static int fdalloc2(struct file *f, int start) {
    int fd;
    struct proc *p = myproc();
    for (fd = start; fd < NOFILEMAX(p); fd++) {
        if (p->ofile[fd] == 0) {
            p->ofile[fd] = f;
            return fd;
        }
    }

    return -24;
}

static int fdalloc3(struct file *File, int new) {
    struct proc *p = myproc();
    if (new < 0 || new >= NOFILEMAX(p)) {
        return -1;
    }
    if (!p->ofile[new]) {
        /* code */
        p->ofile[new] = File;
        return new;
    } else {
        fileclose(p->ofile[new]);
        p->ofile[new] = File;
        return new;
    }
    return -1;
}

void get_absolute_path(const char *path, const char *cwd, char *absolute_path) {
    if (path == NULL) {
        strncpy(absolute_path, cwd, strlen(cwd));
    } else if (path[0] == '/') {
        strcpy(absolute_path, path);
    } else {
        strcpy(absolute_path, cwd);
        strcat(absolute_path, "/");
        strcat(absolute_path, path);
    }
    // handle ./ and ../
    char *p = absolute_path;
    while (*p != '\0') {
        if (*p == '.' && *(p + 1) == '/') {
            strcpy(p, p + 2);
        } else if (*p == '.' && *(p + 1) == '.' && *(p + 2) == '/') {
            char *q = p - 2;
            while (q >= absolute_path && *q != '/') {
                q--;
            }
            if (q >= absolute_path) {
                strcpy(q + 1, p + 3);
                p = q;
            } else {
                strcpy(absolute_path, p + 3);
                p = absolute_path;
            }
        } else {
            p++;
        }
    }

    /* handle trailing . and .. */
    p = absolute_path + strlen(absolute_path) - 2;
    if ((*p == '/' || *p == '.') && *(p + 1) == '.' && *(p + 2) == '\0') {
        *p = *(p + 1) = *(p + 2) = '\0';
    }
    p--;
    if (*p == '/' && *(p + 1) == '.' && *(p + 2) == '.' && *(p + 3) == '\0') {
        if (p == absolute_path) {
            *(p + 1) = *(p + 2) = *(p + 3) = '\0';
            return;
        }
        char *q = p - 1;
        while (q >= absolute_path && *q != '/') {
            q--;
        }
        if (q >= absolute_path) {
            *q = '\0';
            p = q;
        } else {
            strcpy(absolute_path, p + 4);
            p = absolute_path;
        }
    }

    while (absolute_path[0] == '/' && absolute_path[1] == '/') {
        strcpy(absolute_path, absolute_path + 1);
    }
    size_t len = strlen(absolute_path);
    if (absolute_path[len - 1] == '/') {
        absolute_path[len - 1] = '\0';
        --len;
    }
    if (strlen(absolute_path) == 0) {
        strcpy(absolute_path, "/");
    } else if (absolute_path[0] != '/') {
        size_t len2 = strlen(absolute_path);
        char *x = absolute_path + len2;
        *(x + 1) = 0;
        while (x > absolute_path) {
            *x = *(x - 1);
            x--;
        }
        *x = '/';
    }
}

static uint64 do_mkdir(char *abs_path, int mode) {
    struct ext4_dirent *ext4_ep;
    ext4_ep = ext4_getdir_fcache(&(root_entry), abs_path);
    if (ext4_ep == NULL) {
        return -1;
    }
    ext4_elock(ext4_ep);
    int r = ext4_dir_mk(abs_path);
    if (r) {
        ext4_eunlock(ext4_ep);
        printf("mkdir failed\n");
        return -r;
    }
    ext4_eunlock(ext4_ep);
    return 0;
}

uint64 sys_mkdirat(void) {
    // 目前测试中的mkdir都是调用了mkdirat，并且测试中并没有测试mkdirat
    // 所以我们目前只考虑path，不考虑mkdirat的其他参数
    // 下面的写法目前是和mkdir一样的，但是注意，我们的参数path是第1个，而mkdir的path是第0个
    struct dirent *ep;
    struct file *File;
    int dirfd;
    int mode;
    char path[FAT32_MAX_PATH];

    if (argfd(0, &dirfd, &File) < 0 || argstr(1, path, FAT32_MAX_PATH) < 0 ||
        argint(2, &mode) < 0) {
        return -1;
    }

    char abs_path[FAT32_MAX_PATH];
    char *cwd =
        File == NULL ? myproc()->ext4_dir->filename : File->ep->filename;
    get_absolute_path(path, cwd, abs_path);
    do_mkdir(abs_path, mode);
    return 0;
}

uint64 sys_dup(void) {
    int fd;
    struct file *File;

    if (0 > argfd(0, 0, &File) || 0 > (fd = fdalloc(File))) return -1;
    filedup(File);
    return fd;
}

uint64 sys_dup3(void) {
    int fd, new;
    int old;
    struct file *File;
    if (0 > argfd(0, &old, &File) || 0 > argint(1, &new) || new < 0) return -1;
    if (new >= NOFILEMAX(myproc())) return -24;
    if (old == new) return new;
    if (0 > (fd = fdalloc3(File, new))) return -1;
    filedup(File);
    return fd;
}

