static struct dirent *create(char *path, short type, int mode) {
    struct dirent *dp;
    char name[FAT32_MAX_FILENAME + 1];
    struct dirent *ep;
    if (NULL == (dp = enameparent(path, name))) return NULL;

    if (T_DIR == type) {
        mode = ATTR_DIRECTORY;
    } else if (O_RDONLY & mode) {
        mode = ATTR_READ_ONLY;
    } else {
        mode = 0;
    }
    elock(dp);

    if (NULL == (ep = ealloc(dp, name, mode))) {
        eunlock(dp), eput(dp);
        return NULL;
    }

    if (((ep->attribute & ATTR_DIRECTORY) && type == T_FILE) ||
        (type == T_DIR && 0 == (ep->attribute & ATTR_DIRECTORY))) {
        eunlock(dp), eput(ep), eput(dp);
        return NULL;
    }
    eunlock(dp), eput(dp), elock(ep);
    return ep;
}

uint64 do_open(char *newpath, int flags, struct ext4_dirent **epp_new) {
    int fd;
    flags |= O_RDWR;
    char abs_path[FAT32_MAX_PATH];
    struct ext4_dirent *epp;
    if (myproc()->ext4_dir->filename == NULL) {
        get_absolute_path(newpath, "/", abs_path);
    } else {
        get_absolute_path(newpath, myproc()->ext4_dir->filename, abs_path);
    }

    int ret = fileexists(abs_path);
    int r = 0;
    if (!ret && !(flags & O_CREATE)) {
        return -2;
        // file not exists
    } else if (ret == 4 || (flags & O_DIRECTORY)) {
        // dir
        epp = ext4_getdir_fcache(&(root_entry), abs_path);
        ext4_elock(epp);
        if (flags & O_DIRECTORY) {
            r = ext4_dir_mk(abs_path);
        }
        r = ext4_dir_open(&epp->dir, abs_path);

    } else {
        epp = ext4_getdir_fcache(&(root_entry), abs_path);
        ext4_elock(epp);
        if ((flags & O_CREATE) && ret == 0) {
            r = ext4_fopen(&epp->file, abs_path, "w");
        } else {
            r = ext4_fopen(&epp->file, abs_path, "r");
