    struct proc *p = myproc();

    if (0 > argstr(0, path, FAT32_MAX_PATH) || NULL == (ep = ename(path))) {
        return -1;
    }
    elock(ep);
    if (!(ATTR_DIRECTORY & ep->attribute)) {
        eunlock(ep), eput(ep);
        return -1;
    }
    eunlock(ep), eput(p->cwd);
    p->cwd = ep;
    return 0;
}

uint64 sys_pipe(void) {
    int fd0 = -1, fd1;
    struct file *rf, *wf;
    uint64 fdarray;
    struct proc *p = myproc();

    if (0 > argaddr(0, &fdarray) || 0 > pipealloc(&rf, &wf)) return -1;
    if ((fd0 = fdalloc(rf)) < 0 || (fd1 = fdalloc(wf)) < 0) {
        if (0 <= fd0) p->ofile[fd0] = 0;
        fileclose(rf), fileclose(wf);
        return -1;
    }
    // if (0 > copyout(p->pagetable, fdarray, (char *)&fd0, sizeof(fd0)) ||
    //     0 > copyout(p->pagetable, fdarray + sizeof(fd0), (char *)&fd1,
    //                 sizeof(fd1))) {
    if (copyout2(fdarray, (char *)&fd0, sizeof(fd0)) < 0 ||
        copyout2(sizeof(fd0) + fdarray, (char *)&fd1, sizeof(fd1)) < 0) {
        p->ofile[fd1] = 0, p->ofile[fd0] = 0;

        fileclose(rf), fileclose(wf);
        return -1;
    }
    return 0;
}

uint64 sys_pipe2(void) {
    struct proc *p = myproc();
    struct file *rf, *wf;
    int fd0, fd1;
    uint64 fdarray;  // user pointer to array of two integers
    if (0 > argaddr(0, &fdarray) || 0 > pipealloc(&rf, &wf)) return -1;
    fd0 = -1;
    if (0 > (fd0 = fdalloc(rf)) || 0 > (fd1 = fdalloc(wf))) {
        if (0 <= fd0) p->ofile[fd0] = 0;
        fileclose(rf), fileclose(wf);
        return -1;
    }
    if (copyout(p->pagetable, fdarray, (char *)&fd0, sizeof(fd0)) < 0 ||
        copyout(p->pagetable, sizeof(fd0) + fdarray, (char *)&fd1,
                sizeof(fd1)) < 0) {
        // if(copyout2(fdarray, (char*)&fd0, sizeof(fd0)) < 0 ||
        // copyout2(sizeof(fd0) + fdarray, (char *)&fd1, sizeof(fd1)) < 0){
        p->ofile[fd1] = 0, p->ofile[fd0] = 0;
        fileclose(rf), fileclose(wf);
        return -1;
    }
    return 0;
}

uint64 sys_dev(void) {
    struct file *File;
    int major, minor, fd, omode;

    if (0 > argint(0, &omode) || 0 > argint(1, &major) ||
        0 > argint(2, &minor)) {
        return -1;
    }

    if (omode & O_CREATE) {
        panic("dev file on FAT");
    }

    if (major >= NDEV || major < 0) return -1;

    if ((File = filealloc()) == NULL || (fd = fdalloc(File)) < 0) {
        if (0 != File) fileclose(File);
        return -1;
    }

    File->major = major;
    File->ep = 0;
    File->off = 0;
    File->type = FD_DEVICE;

    File->readable = !(omode & O_WRONLY);
    File->writable = (omode & O_RDWR) || (omode & O_WRONLY);

    return fd;
}

