uint64 sys_remove(void) {
    int len;
    struct dirent *ep;
    char path[FAT32_MAX_PATH];

    if (0 >= (len = argstr(1, path, FAT32_MAX_PATH))) return -1;

    char *s = len + path - 1;
    while (*s == '/' && path <= s) {
        --s;
    }
    if ((s == path || *--s == '/') && *s == '.' && s >= path) {
        return -1;
    }

    if (NULL == (ep = ename(path))) {
        return -1;
    }
    elock(ep);
    if ((ep->attribute & ATTR_DIRECTORY) && !isdirempty(ep)) {
        eunlock(ep), eput(ep);
        return -1;
    }
    elock(ep->parent), eremove(ep), eunlock(ep->parent), eunlock(ep), eput(ep);

    return 0;
}

