uint64 sys_rename(void) {
    char old[FAT32_MAX_PATH], new[FAT32_MAX_PATH];
    if (0 > argstr(0, old, FAT32_MAX_PATH) ||
        0 > argstr(1, new, FAT32_MAX_PATH)) {
        return -1;
    }
    char *name;
    int srclock = 0;
    uint off;

    struct dirent *pdst = NULL, *src = NULL, *dst = NULL;

    if (NULL == (src = ename(old)) || NULL == (pdst = enameparent(new, old)) ||
        NULL == (name = formatname(old))) {
        // src doesn't exist || dst parent doesn't exist || illegal
        // new name
        goto fail;
    }
    for (struct dirent *ep = pdst; NULL != ep; ep = ep->parent) {
        if (src == ep) {
            // In what universe can we move a directory into its child?
            goto fail;
        }
    }

    elock(src);  // must hold child's lock before acquiring parent's, because we
                 // do so in other similar cases
    srclock = 1;
    elock(pdst);
    dst = dirlookup(pdst, name, &off);
    if (dst != NULL) {
        eunlock(pdst);
        if (src == dst) {
            goto fail;
        } else if (ATTR_DIRECTORY & src->attribute & dst->attribute) {
            elock(dst);
            if (0 == isdirempty(dst)) {  // it's ok to overwrite an empty dir
                eunlock(dst);
                goto fail;
            }
            elock(pdst);
        } else {
            // src is not a dir || dst exists and is not an dir
            goto fail;
        }
    }

    if (dst) {
        eremove(dst), eunlock(dst);
    }
    memmove(src->filename, name, FAT32_MAX_FILENAME);
    emake(pdst, src, off);
    if (pdst != src->parent) {
        eunlock(pdst), elock(src->parent);
    }
    eremove(src), eunlock(src->parent);
    struct dirent *psrc = src->parent;  // src must not be root, or it won't
                                        // pass the for-loop test
    src->valid = 1;
    src->parent = edup(pdst);
    src->off = off;

    eunlock(src), eput(psrc);
    if (0 != dst) {
        eput(dst);
    }
    eput(pdst), eput(src);

    return 0;

fail:
    if (0 != srclock) eunlock(src);
    if (0 != dst) eput(dst);
    if (0 != pdst) eput(pdst);
    if (0 != src) eput(src);
    return -1;
}

