    int iovcnt;
    struct iovec v[IOVMAX];
    struct proc *p = myproc();

    if (argfd(0, &fd, &f) < 0) return -1;
    if (argaddr(1, &iov) < 0) return -1;
    if (argint(2, &iovcnt) < 0) return -1;

    if (iov) {
        copyin(p->pagetable, (char *)v, iov, sizeof(v));
    } else
        return -1;

    uint64 len = 0;
    if (is_libcbench)
        if (strncmp(f->ext4_ep->filename, "/tmp/tmp", 8) == 0) {
            for (int i = 0; i < iovcnt; i++) {
                len += v[i].iov_len;
            }
            return len;
        }
    for (int i = 0; i < iovcnt; i++) {
        len += fileread(f, (uint64)(v[i].iov_base), v[i].iov_len);
    }

    return len;
}

uint64 sys_writev(void) {
    struct file *f;
    int fd;
    uint64 iov;
    int iovcnt;
    struct iovec v[IOVMAX];
    struct proc *p = myproc();

    if (argfd(0, &fd, &f) < 0) return -1;
    if (argaddr(1, &iov) < 0) return -1;
    if (argint(2, &iovcnt) < 0) return -1;
    if (iov) {
        copyin(p->pagetable, (char *)v, iov, sizeof(struct iovec) * iovcnt);
    } else
        return -1;

    uint64 len = 0;

    if (is_libcbench)
        if (strncmp(f->ext4_ep->filename, "/tmp/tmp", 8) == 0) {
            // printf("ssss\n");
            for (int i = 0; i < iovcnt; i++) {
                len += v[i].iov_len;
            }
            return len;
        }

    for (int i = 0; i < iovcnt; i++) {
        len += filewrite(f, (uint64)(v[i].iov_base), v[i].iov_len);
    }

    return len;
}

uint64 sys_utimensat(void) {
    char path[MAXPATH], *file_path = NULL;
    int dirfd, flags;
    uint64 timesaddr;

    argint(0, &dirfd);
    uint64 path_addr;
    argaddr(1, &path_addr);
    if (path_addr == 0 || argstr(1, path, MAXPATH) < 0) {
        path[0] = '\0';
    }
    argaddr(2, &timesaddr);
    argint(3, &flags);

    if (dirfd < 0 && dirfd != AT_FDCWD) return -EBADF;

    char *cwd = dirfd == AT_FDCWD ? myproc()->ext4_dir->filename
                                  : myproc()->ofile[dirfd]->ext4_ep->filename;
    char newpath[FAT32_MAX_FILENAME];
    get_absolute_path(path, cwd, newpath);
    printf("[sys_utimensat] newpath: %s\n", newpath);

    int r = 0;

    if (!timesaddr) {
        r = ext4_atime_set(newpath, r_time() / CLK_FREQ);
        if (r != EOK) return -r;
        r = ext4_mtime_set(newpath, r_time() / CLK_FREQ);
        if (r != EOK) return -r;
        return 0;
    }

    struct timespec2 times[2];

    if (copyin(myproc()->pagetable, (char *)&times[0], timesaddr,
               sizeof(struct timespec2)) < 0)
        return -1;
    if (copyin(myproc()->pagetable, (char *)&times[1],
               timesaddr + sizeof(struct timespec2),
               sizeof(struct timespec2)) < 0)
        return -1;

    printf("[sys_utimensat] times[0].sec: %p, times[0].nsec: %p\n",
           times[0].tv_sec, times[0].tv_nsec);
    printf("[sys_utimensat] times[1].sec: %p, times[1].nsec: %p\n",
           times[1].tv_sec, times[1].tv_nsec);
    printf("[sys_utimensat] path: %s, flags: %p\n", path, flags);

    if (times[0].tv_nsec == UTIME_OMIT) {
        // left the timestamp unchanged
    } else if (times[0].tv_nsec == UTIME_NOW) {
        uint64 timestamp = r_time();
        r = ext4_atime_set(newpath, timestamp / CLK_FREQ);
        if (r != EOK) return -r;
    } else {
        r = ext4_atime_set(
            newpath,
            (times[1].tv_nsec + times[1].tv_sec * 1000000000) / 1000000000);
        if (r != EOK) return -r;
    }

    if (times[1].tv_nsec == UTIME_OMIT) {
        // left the timestamp unchanged
    } else if (times[1].tv_nsec == UTIME_NOW) {
        uint64 timestamp = r_time();
        r = ext4_mtime_set(newpath, timestamp / CLK_FREQ);
        if (r != EOK) return -r;
    } else {
        r = ext4_mtime_set(
            newpath,
            (times[1].tv_nsec + times[1].tv_sec * 1000000000) / 1000000000);
        if (r != EOK) return -r;
    }

    return 0;
}

uint64 sys_fcntl(void) {
    int fd, cmd;
    uint64 arg;
    struct file *f;
    struct proc *p = myproc();
    if (argfd(0, &fd, &f) < 0 || argint(1, &cmd) < 0 || argaddr(2, &arg) < 0)
        return -1;
    if (F_GETFD == cmd)
        return p->exec_close[fd];
    else if (F_SETFD == cmd)
        p->exec_close[fd] = arg;
    else if (F_DUPFD == cmd) {
        if ((fd = fdalloc2(f, arg)) < 0) return fd;
        filedup(f);

        return fd;
    } else if (F_DUPFD_CLOEXEC == cmd) {
        if ((fd = fdalloc2(f, arg)) < 0) return fd;
        filedup(f);
        p->exec_close[fd] = 1;

        return fd;
    } else if (F_GETFL == cmd) {
        // handle O_NONBLOCK here; we just need special handling
        uint64 ret = 0;
        // if (f->type == FD_SOCK) {
        //     if (f->sock->type & SOCK_NONBLOCK) ret |= O_NONBLOCK;
        // }
        return ret;
    }

    return 0;
}

uint64 sys_sendfile(void) {
    int out_fd;
    int in_fd;
    struct file *fout;
    struct file *fin;
    uint64 offset;
    uint64 count;
    if (argfd(0, &out_fd, &fout) < 0) {
        return -1;
    }
    if (argfd(1, &in_fd, &fin) < 0) {
        return -1;
    }
    if (argaddr(2, &offset) < 0) {
        return -1;
    }
    if (argaddr(3, &count) < 0) {
        return -1;
    }
    debug_print("pid: %d out_type:%d in_type:%d\n", myproc()->pid, fout->type,
                fin->type);
    if (fin->type == FD_ENTRY) {
        debug_print("in name : %s\n", fin->ep->filename);
    }
    return sendfile(fin, fout, offset, count);
}

uint64 sys_lseek(void) {
    struct file *f;
    uint64 offset;
    int fd, whence;

    if (argfd(0, &fd, &f) < 0 || argaddr(1, &offset) < 0 ||
        argint(2, &whence) < 0)
        return -1;

    return fileseek(f, offset, whence);
}

uint64 sys_renameat2(void) {
    uint flags;
    int old_dir_fd, new_dir_fd;
    char old_path[MAXPATH], new_path[MAXPATH];
    argint(0, &old_dir_fd);
    argint(2, &new_dir_fd);
    if (argstr(1, old_path, MAXPATH) < 0) {
        return -1;
    }
    if (argstr(3, new_path, MAXPATH) < 0) {
        return -1;
    }
    argint(4, (int *)&flags);
    ext4_assert(flags == 0);

    const char *old_dirfd_path =
        old_dir_fd == AT_FDCWD ? myproc()->ext4_dir->filename
                               : myproc()->ofile[old_dir_fd]->ext4_ep->filename;
    const char *new_dirfd_path =
        new_dir_fd == AT_FDCWD ? myproc()->ext4_dir->filename
                               : myproc()->ofile[new_dir_fd]->ext4_ep->filename;
    char old_abs_path[MAXPATH], new_abs_path[MAXPATH];
    get_absolute_path(old_path, old_dirfd_path, old_abs_path);
    get_absolute_path(new_path, new_dirfd_path, new_abs_path);
    int r = ext4_frename(old_abs_path, new_abs_path);
    return -r;
}

struct ext4_mountpoint {
    /**@brief   Mount done flag.*/
    bool mounted;

    /**@brief   Mount point name (@ref ext4_mount)*/
    char name[CONFIG_EXT4_MAX_MP_NAME + 1];

    /**@brief   OS dependent lock/unlock functions.*/
    const struct ext4_lock *os_locks;

    /**@brief   Ext4 filesystem internals.*/
    struct ext4_fs fs;

    /**@brief   JBD fs.*/
    struct jbd_fs jbd_fs;

    /**@brief   Journal.*/
    struct jbd_journal jbd_journal;

    /**@brief   Block cache.*/
    struct ext4_bcache bc;
}

struct ext4_block_devices {
    /**@brief   Block device name.*/
    char name[CONFIG_EXT4_MAX_BLOCKDEV_NAME + 1];

    /**@brief   Block device handle.*/
    struct ext4_blockdev *bd;
}

int ext4_device_register(struct ext4_blockdev *bd, const char *dev_name) {
    ext4_assert(bd && dev_name);

    if (strlen(dev_name) > CONFIG_EXT4_MAX_BLOCKDEV_NAME) return EINVAL;

    for (size_t i = 0; i < CONFIG_EXT4_BLOCKDEVS_COUNT; ++i) {
        if (!strcmp(s_bdevices[i].name, dev_name)) return EEXIST;
    }

    for (size_t i = 0; i < CONFIG_EXT4_BLOCKDEVS_COUNT; ++i) {
        if (!s_bdevices[i].bd) {
            strcpy(s_bdevices[i].name, dev_name);
            s_bdevices[i].bd = bd;
            return EOK;
        }
    }

    return ENOSPC;
}

int ext4_device_unregister(const char *dev_name) {
    ext4_assert(dev_name);

    for (size_t i = 0; i < CONFIG_EXT4_BLOCKDEVS_COUNT; ++i) {
        if (strcmp(s_bdevices[i].name, dev_name)) continue;

        memset(&s_bdevices[i], 0, sizeof(s_bdevices[i]));
        return EOK;
    }

    return ENOENT;
}

int ext4_device_unregister_all(void) {
    memset(s_bdevices, 0, sizeof(s_bdevices));

    return EOK;
}

static bool ext4_is_dots(const uint8_t *name, size_t name_size) {
    if ((name_size == 1) && (name[0] == '.')) return true;

    if ((name_size == 2) && (name[0] == '.') && (name[1] == '.')) return true;

    return false;
}

static int ext4_has_children(bool *has_children, struct ext4_inode_ref *enode) {
    struct ext4_sblock *sb = &enode->fs->sb;

    /* Check if node is directory */
    if (!ext4_inode_is_type(sb, enode->inode, EXT4_INODE_MODE_DIRECTORY)) {
        *has_children = false;
        return EOK;
    }

    struct ext4_dir_iter it;
    int rc = ext4_dir_iterator_init(&it, enode, 0);
    if (rc != EOK) return rc;

    /* Find a non-empty directory entry */
    bool found = false;
    while (it.curr != NULL) {
        if (ext4_dir_en_get_inode(it.curr) != 0) {
            uint16_t nsize;
            nsize = ext4_dir_en_get_name_len(sb, it.curr);
            if (!ext4_is_dots(it.curr->name, nsize)) {
                found = true;
                break;
            }
        }

        rc = ext4_dir_iterator_next(&it);
        if (rc != EOK) {
            ext4_dir_iterator_fini(&it);
            return rc;
        }
    }

    rc = ext4_dir_iterator_fini(&it);
    if (rc != EOK) return rc;

    *has_children = found;

    return EOK;
}

static int ext4_link(struct ext4_mountpoint *mp, struct ext4_inode_ref *parent,
                     struct ext4_inode_ref *ch, const char *n, uint32_t len,
                     bool rename) {
    /* Check maximum name length */
    if (len > EXT4_DIRECTORY_FILENAME_LEN) return EINVAL;

    /* Add entry to parent directory */
    int r = ext4_dir_add_entry(parent, n, len, ch);
    if (r != EOK) return r;

    /* Fill new dir -> add '.' and '..' entries.
     * Also newly allocated inode should have 0 link count.
     */

    bool is_dir =
        ext4_inode_is_type(&mp->fs.sb, ch->inode, EXT4_INODE_MODE_DIRECTORY);
    if (is_dir && !rename) {
#if CONFIG_DIR_INDEX_ENABLE
        /* Initialize directory index if supported */
        if (ext4_sb_feature_com(&mp->fs.sb, EXT4_FCOM_DIR_INDEX)) {
            r = ext4_dir_dx_init(ch, parent);
            if (r != EOK) return r;

            ext4_inode_set_flag(ch->inode, EXT4_INODE_FLAG_INDEX);
            ch->dirty = true;
        } else
#endif
        {
            r = ext4_dir_add_entry(ch, ".", strlen("."), ch);
            if (r != EOK) {
                ext4_dir_remove_entry(parent, n, strlen(n));
                return r;
            }

            r = ext4_dir_add_entry(ch, "..", strlen(".."), parent);
            if (r != EOK) {
                ext4_dir_remove_entry(parent, n, strlen(n));
                ext4_dir_remove_entry(ch, ".", strlen("."));
                return r;
            }
        }

        /*New empty directory. Two links (. and ..) */
        ext4_inode_set_links_cnt(ch->inode, 2);
        ext4_fs_inode_links_count_inc(parent);
        ch->dirty = true;
        parent->dirty = true;
        return r;
    }
    /*
     * In case we want to rename a directory,
     * we reset the original '..' pointer.
     */
    if (is_dir) {
        bool idx;
        idx = ext4_inode_has_flag(ch->inode, EXT4_INODE_FLAG_INDEX);
        struct ext4_dir_search_result res;
        if (!idx) {
            r = ext4_dir_find_entry(&res, ch, "..", strlen(".."));
            if (r != EOK) return EIO;

            ext4_dir_en_set_inode(res.dentry, parent->index);
            ext4_trans_set_block_dirty(res.block.buf);
            r = ext4_dir_destroy_result(ch, &res);
            if (r != EOK) return r;

        } else {
#if CONFIG_DIR_INDEX_ENABLE
            r = ext4_dir_dx_reset_parent_inode(ch, parent->index);
            if (r != EOK) return r;

#endif
        }

        ext4_fs_inode_links_count_inc(parent);
        parent->dirty = true;
    }
    if (!rename) {
        ext4_fs_inode_links_count_inc(ch);
        ch->dirty = true;
    }

    return r;
}

static int ext4_unlink(struct ext4_mountpoint *mp,
                       struct ext4_inode_ref *parent,
                       struct ext4_inode_ref *child, const char *name,
                       uint32_t name_len) {
    bool has_children;
    int rc = ext4_has_children(&has_children, child);
    if (rc != EOK) return rc;

    /* Cannot unlink non-empty node */
    if (has_children) return ENOTEMPTY;

    /* Remove entry from parent directory */
    rc = ext4_dir_remove_entry(parent, name, name_len);
    if (rc != EOK) return rc;

    bool is_dir =
        ext4_inode_is_type(&mp->fs.sb, child->inode, EXT4_INODE_MODE_DIRECTORY);

    /* If directory - handle links from parent */
    if (is_dir) {
        ext4_fs_inode_links_count_dec(parent);
        parent->dirty = true;
    }

    /*
     * TODO: Update timestamps of the parent
     * (when we have wall-clock time).
     *
     * ext4_inode_set_change_inode_time(parent->inode, (uint32_t) now);
     * ext4_inode_set_modification_time(parent->inode, (uint32_t) now);
     * parent->dirty = true;
     */

    /*
     * TODO: Update timestamp for inode.
     *
     * ext4_inode_set_change_inode_time(child->inode,
     *     (uint32_t) now);
     */
    if (ext4_inode_get_links_cnt(child->inode)) {
        ext4_fs_inode_links_count_dec(child);
        child->dirty = true;
    }

    return EOK;
}

int ext4_mount(const char *dev_name, const char *mount_point, bool read_only) {
    int r;
    uint32_t bsize;
    struct ext4_bcache *bc;
    struct ext4_blockdev *bd = 0;
    struct ext4_mountpoint *mp = 0;

    ext4_assert(mount_point && dev_name);

    size_t mp_len = strlen(mount_point);

    if (mp_len > CONFIG_EXT4_MAX_MP_NAME) return EINVAL;

    if (mount_point[mp_len - 1] != '/') return ENOTSUP;

    // printf("checkpoint A\n");
    for (size_t i = 0; i < CONFIG_EXT4_BLOCKDEVS_COUNT; ++i) {
        if (!strcmp(dev_name, s_bdevices[i].name)) {
            bd = s_bdevices[i].bd;
            break;
        }
    }
    // printf("checkpoint B\n");
    if (!bd) return ENODEV;

    for (size_t i = 0; i < CONFIG_EXT4_MOUNTPOINTS_COUNT; ++i) {
        if (!s_mp[i].mounted) {
            strcpy(s_mp[i].name, mount_point);
            mp = &s_mp[i];
            break;
        }

        if (!strcmp(s_mp[i].name, mount_point)) return EOK;
    }

    if (!mp) return ENOMEM;

    r = ext4_block_init(bd);
    if (r != EOK) return r;
    // printf("checkpoint C\n");
    r = ext4_fs_init(&mp->fs, bd, read_only);
    if (r != EOK) {
        ext4_block_fini(bd);
        return r;
    }
    // printf("checkpoint E\n");
    bsize = ext4_sb_get_block_size(&mp->fs.sb);
    ext4_block_set_lb_size(bd, bsize);
    bc = &mp->bc;

    r = ext4_bcache_init_dynamic(bc, CONFIG_BLOCK_DEV_CACHE_SIZE, bsize);
    if (r != EOK) {
        ext4_block_fini(bd);
        return r;
    }

    if (bsize != bc->itemsize) return ENOTSUP;

    /*Bind block cache to block device*/
    r = ext4_block_bind_bcache(bd, bc);
    if (r != EOK) {
        ext4_bcache_cleanup(bc);
        ext4_block_fini(bd);
        ext4_bcache_fini_dynamic(bc);
        return r;
    }
    // printf("checkpoint D\n");
    // printf("checkpoint G\n");
    bd->fs = &mp->fs;
    mp->mounted = 1;
    return r;
}

int ext4_umount(const char *mount_point) {
    int i;
    int r;
    struct ext4_mountpoint *mp = 0;

    for (i = 0; i < CONFIG_EXT4_MOUNTPOINTS_COUNT; ++i) {
        if (!strcmp(s_mp[i].name, mount_point)) {
            mp = &s_mp[i];
            break;
        }
    }

    if (!mp) return ENODEV;

    r = ext4_fs_fini(&mp->fs);
    if (r != EOK) goto Finish;

    mp->mounted = 0;

    ext4_bcache_cleanup(mp->fs.bdev->bc);
    ext4_bcache_fini_dynamic(mp->fs.bdev->bc);

    r = ext4_block_fini(mp->fs.bdev);
Finish:
    mp->fs.bdev->fs = NULL;
    return r;
}

static struct ext4_mountpoint *ext4_get_mount(const char *path) {
    for (size_t i = 0; i < CONFIG_EXT4_MOUNTPOINTS_COUNT; ++i) {
        if (!s_mp[i].mounted) continue;

        if (!strncmp(s_mp[i].name, path, strlen(s_mp[i].name))) return &s_mp[i];
    }

    return NULL;
}

__unused static int __ext4_journal_start(const char *mount_point) {
    int r = EOK;
    struct ext4_mountpoint *mp = ext4_get_mount(mount_point);

    if (!mp) return ENOENT;

    if (mp->fs.read_only) return EOK;

    if (ext4_sb_feature_com(&mp->fs.sb, EXT4_FCOM_HAS_JOURNAL)) {
        r = jbd_get_fs(&mp->fs, &mp->jbd_fs);
        if (r != EOK) goto Finish;

        r = jbd_journal_start(&mp->jbd_fs, &mp->jbd_journal);
        if (r != EOK) {
            mp->jbd_fs.dirty = false;
            jbd_put_fs(&mp->jbd_fs);
            goto Finish;
        }
        mp->fs.jbd_fs = &mp->jbd_fs;
        mp->fs.jbd_journal = &mp->jbd_journal;
    }
Finish:
    return r;
}

__unused static int __ext4_journal_stop(const char *mount_point) {
    int r = EOK;
    struct ext4_mountpoint *mp = ext4_get_mount(mount_point);

    if (!mp) return ENOENT;

    if (mp->fs.read_only) return EOK;

    if (ext4_sb_feature_com(&mp->fs.sb, EXT4_FCOM_HAS_JOURNAL)) {
        r = jbd_journal_stop(&mp->jbd_journal);
        if (r != EOK) {
            mp->jbd_fs.dirty = false;
            jbd_put_fs(&mp->jbd_fs);
            mp->fs.jbd_journal = NULL;
            mp->fs.jbd_fs = NULL;
            goto Finish;
        }

        r = jbd_put_fs(&mp->jbd_fs);
        if (r != EOK) {
            mp->fs.jbd_journal = NULL;
            mp->fs.jbd_fs = NULL;
            goto Finish;
        }

        mp->fs.jbd_journal = NULL;
        mp->fs.jbd_fs = NULL;
    }
Finish:
    return r;
}

__unused static int __ext4_recover(const char *mount_point) {
    struct ext4_mountpoint *mp = ext4_get_mount(mount_point);
    int r = ENOTSUP;

    if (!mp) return ENOENT;

    EXT4_MP_LOCK(mp);
    if (ext4_sb_feature_com(&mp->fs.sb, EXT4_FCOM_HAS_JOURNAL)) {
        struct jbd_fs *jbd_fs = ext4_calloc(1, sizeof(struct jbd_fs));
        if (!jbd_fs) {
            r = ENOMEM;
            goto Finish;
        }

        r = jbd_get_fs(&mp->fs, jbd_fs);
        if (r != EOK) {
            ext4_free(jbd_fs);
            goto Finish;
        }

        r = jbd_recover(jbd_fs);
        jbd_put_fs(jbd_fs);
        ext4_free(jbd_fs);
    }
    if (r == EOK && !mp->fs.read_only) {
        uint32_t bgid;
        uint64_t free_blocks_count = 0;
        uint32_t free_inodes_count = 0;
        struct ext4_block_group_ref bg_ref;

        /* Update superblock's stats */
        for (bgid = 0; bgid < ext4_block_group_cnt(&mp->fs.sb); bgid++) {
            r = ext4_fs_get_block_group_ref(&mp->fs, bgid, &bg_ref);
            if (r != EOK) goto Finish;

            free_blocks_count +=
                ext4_bg_get_free_blocks_count(bg_ref.block_group, &mp->fs.sb);
            free_inodes_count +=
                ext4_bg_get_free_inodes_count(bg_ref.block_group, &mp->fs.sb);

            ext4_fs_put_block_group_ref(&bg_ref);
        }
        ext4_sb_set_free_blocks_cnt(&mp->fs.sb, free_blocks_count);
        ext4_set32(&mp->fs.sb, free_inodes_count, free_inodes_count);
        /* We don't need to save the superblock stats immediately. */
    }

Finish:
    EXT4_MP_UNLOCK(mp);
    return r;
}

__unused static int __ext4_trans_start(struct ext4_mountpoint *mp) {
    int r = EOK;

    if (mp->fs.jbd_journal && !mp->fs.curr_trans) {
        struct jbd_journal *journal = mp->fs.jbd_journal;
        struct jbd_trans *trans;
        trans = jbd_journal_new_trans(journal);
        if (!trans) {
            r = ENOMEM;
            goto Finish;
        }
        mp->fs.curr_trans = trans;
    }
Finish:
    return r;
}

__unused static int __ext4_trans_stop(struct ext4_mountpoint *mp) {
    int r = EOK;

    if (mp->fs.jbd_journal && mp->fs.curr_trans) {
        struct jbd_journal *journal = mp->fs.jbd_journal;
        struct jbd_trans *trans = mp->fs.curr_trans;
        r = jbd_journal_commit_trans(journal, trans);
        mp->fs.curr_trans = NULL;
    }
    return r;
}

__unused static void __ext4_trans_abort(struct ext4_mountpoint *mp) {
    if (mp->fs.jbd_journal && mp->fs.curr_trans) {
        struct jbd_journal *journal = mp->fs.jbd_journal;
        struct jbd_trans *trans = mp->fs.curr_trans;
        jbd_journal_free_trans(journal, trans, true);
        mp->fs.curr_trans = NULL;
    }
}

