    //     ref->dirty = true;
    // }

    // if (ext5_bg_has_flag(bg, EXT4_BLOCK_GROUP_INODE_UNINIT)) {
    //     rc = ext5_fs_init_inode_bitmap(ref);
    //     // printf("rc n error\n");
    //     if (rc != EOK) {
