pte_t *walk(pagetable_t pgtb, uint64 va, int allocation) {
    if (MAXVA <= va) panic("walk");

    for (int level = 2; level > 0; --level) {
        pte_t *PTE = &pgtb[PX(level, va)];
        if (PTE_V & *PTE) {
            pgtb = (pagetable_t)PTE2PA(*PTE);
        } else {
            if ((pgtb = (pde_t *)kalloc()) == NULL || allocation == 0)
                return NULL;
            memset(pgtb, 0, PGSIZE);
            *PTE = PTE_V | PA2PTE(pgtb);
        }
    }
    return &pgtb[PX(0, va)];
}

uint64 walkaddr(pagetable_t pgtb, uint64 va) {
    uint64 pa;
    pte_t *PTE;

    if (MAXVA <= va) return NULL;

    PTE = walk(pgtb, va, 0);
    if (!PTE || !(*PTE & PTE_V) || !(*PTE & PTE_U)) {
        return NULL;
    }
    pa = PTE2PA(*PTE);
    return pa;
}

void kvmmap(uint64 va, uint64 pa, uint64 sz, int perm) {
    if (mappages(kernel_pagetable, va, sz, pa, perm)) panic("kvmmap");
}

uint64 kwalkaddr(pagetable_t kpt, uint64 va) {
    pte_t *PTE;
    uint64 pa, off = va % PGSIZE;

    PTE = walk(kpt, va, 0);
    if (PTE == 0) panic("kvmpa");
    if (!(*PTE & PTE_V)) panic("kvmpa");
    pa = PTE2PA(*PTE);
    return off + pa;
}

int mappages(pagetable_t pgtb, uint64 va, uint64 sz, uint64 pa, int perm) {
    // for visionfive 2
    perm |= PTE_D | PTE_A;
    pte_t *PTE;

    uint64 a = PGROUNDDOWN(va);
    uint64 lst = PGROUNDDOWN(va + sz - 1);

    while (1) {
        if ((PTE = walk(pgtb, a, 1)) == NULL) return -1;
        if (0 != (*PTE & PTE_V)) panic("remap");
        *PTE = PTE_V | PA2PTE(pa) | perm;
        if (a == lst) break;
        pa += PGSIZE, a += PGSIZE;
    }

    return 0;
}

void vmunmap(pagetable_t pgtb, uint64 va, uint64 npages, int do_free) {
    pte_t *PTE;

    if ((va % PGSIZE)) panic("vmunmap: not aligned");

    for (uint64 a = va; va + npages * PGSIZE > a; a += PGSIZE) {
        if (!(PTE = walk(pgtb, a, 0))) panic("vmunmap: walk");
        if (!(*PTE & PTE_V)) panic("vmunmap: not mapped");
        if (PTE_FLAGS(*PTE) == PTE_V) panic("vmunmap: not a leaf");
        if (0 != do_free) {
            uint64 pa = PTE2PA(*PTE);
            kfree((void *)pa);
        }
        *PTE = 0;
    }
}

pagetable_t uvmcreate() {
    pagetable_t pgtb = (pagetable_t)kalloc();
    if (NULL == pgtb) return NULL;
    memset(pgtb, 0, PGSIZE);
    return pgtb;
}

void uvminit(pagetable_t pgtb, pagetable_t kpgtb, uchar *src, uint sz) {
    char *mem;
    uint64 i;
    for (i = 0; i + PGSIZE < sz; i += PGSIZE) {
        mem = kalloc();
        memset(mem, 0, PGSIZE);
        mappages(pgtb, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X | PTE_U);
        mappages(kpgtb, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X);
        memmove(mem, src + i, PGSIZE);
    }
    mem = kalloc();
    memset(mem, 0, PGSIZE);
    mappages(pgtb, i, PGSIZE, (uint64)mem, PTE_X | PTE_U | PTE_W | PTE_R);
    mappages(kpgtb, i, PGSIZE, (uint64)mem, PTE_X | PTE_W | PTE_R);
    memmove(mem, src + i, sz % PGSIZE);
}

uint64 uvmalloc1(pagetable_t pgtb, uint64 st, uint64 ed, int perm) {
    if (st >= ed) return -1;
    char *mem;
    for (uint64 a = st; a < ed; a += PGSIZE) {
        mem = kalloc();
        if (NULL == mem) {
            uvmdealloc1(pgtb, st, a);
            printf("uvmalloc kalloc failed\n");
            return -1;
        }
        memset(mem, 0, PGSIZE);
        if (mappages(pgtb, a, PGSIZE, (uint64)mem, perm)) {
            kfree(mem);
            uvmdealloc1(pgtb, st, a);
            printf("[uvmalloc]map user page failed\n");
            return -1;
        }
    }
    return 0;
}

uint64 uvmdealloc1(pagetable_t pgtb, uint64 st, uint64 ed) {
    if (ed <= st) return -1;
    if (PGROUNDUP(ed) > PGROUNDUP(st)) {
        int npages = (PGROUNDUP(ed) - PGROUNDUP(st)) / PGSIZE;
        vmunmap(pgtb, PGROUNDUP(st), npages, 1);
    }
    return 0;
}

uint64 uvmalloc(pagetable_t pgtb, pagetable_t kpgtb, uint64 presz, uint64 newsz,
                int perm) {
    if (presz > newsz) return presz;

    presz = PGROUNDUP(presz);
    char *mem;
    for (uint64 a = presz; newsz > a; a += PGSIZE) {
        mem = kalloc();
        if (NULL == mem) {
            uvmdealloc(pgtb, kpgtb, a, presz);
            return 0;
        }
        memset(mem, 0, PGSIZE);
        if (mappages(pgtb, a, PGSIZE, (uint64)mem, perm | PTE_U)) {
            kfree(mem);
            uvmdealloc(pgtb, kpgtb, a, presz);
            return 0;
        }
        if (mappages(kpgtb, a, PGSIZE, (uint64)mem, perm)) {
            int npages = (a - presz) / PGSIZE;
            vmunmap(pgtb, presz, npages + 1, 1);
            vmunmap(kpgtb, presz, npages, 0);
            return 0;
        }
    }
    return newsz;
}

uint64 uvmdealloc(pagetable_t pgtb, pagetable_t kpgtb, uint64 presz,
                  uint64 newsz) {
    if (presz <= newsz) return presz;
    if (PGROUNDUP(presz) > PGROUNDUP(newsz)) {
        int npages = (PGROUNDUP(presz) - PGROUNDUP(newsz)) / PGSIZE;
        vmunmap(kpgtb, PGROUNDUP(newsz), npages, 0),
            vmunmap(pgtb, PGROUNDUP(newsz), npages, 1);
    }
    return newsz;
}

void freewalk(pagetable_t pgtb) {
    for (int idx = 0; idx < 512; ++idx) {
        pte_t PTE = pgtb[idx];
        if (!(PTE & (PTE_R | PTE_W | PTE_X)) && (PTE & PTE_V)) {
            // this PTE points to a lower-level page table.
            uint64 child = PTE2PA(PTE);
            freewalk((pagetable_t)child);
            pgtb[idx] = 0;
        } else if ((PTE & PTE_V) != 0) {
            // panic("freewalk: leaf");
            continue;
        }
    }
    kfree((void *)pgtb);
}

void uvmfree(pagetable_t pgtb, uint64 sz) {
    if (0 < sz) vmunmap(pgtb, 0, PGROUNDUP(sz) / PGSIZE, 1);
    freewalk(pgtb);
}

int uvmcopy(pagetable_t old, pagetable_t new, pagetable_t knew, uint64 sz) {
    pte_t *PTE;
    char *mem;
    uint flags;
    uint64 pa, idx = 0, ki = 0;
    while (sz > idx) {
        if (NULL == (PTE = walk(old, idx, 0)))
            panic("uvmcopy: PTE should exist");
        if (!(*PTE & PTE_V)) panic("uvmcopy: page not present");
        pa = PTE2PA(*PTE);
        flags = PTE_FLAGS(*PTE);
        if (NULL == (mem = kalloc())) goto err;
        memmove(mem, (char *)pa, PGSIZE);
        if (mappages(new, idx, PGSIZE, (uint64)mem, flags)) {
            kfree(mem);
            goto err;
        }
        idx += PGSIZE;
        // printf("knew is %p\n", knew);
        // printf("ki is %p\n", ki);
        // printf("mem is %p\n", (uint64)mem);

        if (mappages(knew, ki, PGSIZE, (uint64)mem, ~PTE_U & flags)) {
            goto err;
        }
        ki += PGSIZE;
    }
    return 0;

err:
    vmunmap(knew, 0, ki / PGSIZE, 0), vmunmap(new, 0, idx / PGSIZE, 1);
    return -1;
}

void uvmclear(pagetable_t pgtb, uint64 va) {
    pte_t *PTE = walk(pgtb, va, 0);
    if (NULL == PTE) panic("uvmclear");
    *PTE &= ~PTE_U;
}

int copyout(pagetable_t pgtb, uint64 dstva, char *src, uint64 len) {
    uint64 va0, pa0, n;

    while (0 < len) {
        va0 = PGROUNDDOWN(dstva);
        pa0 = walkaddr(pgtb, va0);
        if (NULL == pa0) return -1;
        n = va0 + PGSIZE - dstva;
        if (len < n) n = len;
        memmove((void *)(pa0 + (dstva - va0)), src, n);

        len -= n, src += n;
        dstva = va0 + PGSIZE;
    }
    return 0;
}

int copyout2(uint64 dstva, char *src, uint64 len) {
    uint64 sz = myproc()->sz;
    if (dstva >= sz || dstva + len > sz) return -1;
    memmove((void *)dstva, src, len);
    return 0;
}

int copyin(pagetable_t pgtb, char *dst, uint64 srcva, uint64 len) {
    uint64 va0, pa0, n;

    while (0 < len) {
        va0 = PGROUNDDOWN(srcva);
        pa0 = walkaddr(pgtb, va0);
        if (NULL == pa0) return -1;
        n = va0 + PGSIZE - srcva;
        if (len < n) n = len;
        memmove(dst, (void *)(pa0 + (srcva - va0)), n);

        len -= n, dst += n;
        srcva = va0 + PGSIZE;
    }
    return 0;
}

int copyin2(char *dst, uint64 srcva, uint64 len) {
    uint64 sz = myproc()->sz;
    if (srcva >= sz || srcva > sz - len) {
        return -1;
    }
    memmove(dst, (void *)srcva, len);
    return 0;
}

int copyinstr(pagetable_t pgtb, char *dst, uint64 srcva, uint64 mx) {
    int got_null = 0;
    uint64 n, va0, pa0;

    while (mx > 0 && !got_null) {
        va0 = PGROUNDDOWN(srcva);
        pa0 = walkaddr(pgtb, va0);
        if (pa0 == NULL) return -1;
        n = PGSIZE - srcva + va0;
        if (n > mx) n = mx;

        char *p = (char *)(pa0 + srcva - va0);
        while (n > 0) {
            if (*p != '\0') {
                *dst = *p;
            } else {
                *dst = '\0';
                got_null = 1;
                break;
            }
            ++p, ++dst, --n, --mx;
        }
        srcva = va0 + PGSIZE;
    }
    if (got_null == 0)
        return -1;
    else
        return 0;
}

int copyinstr2(char *dst, uint64 srcva, uint64 mx) {
    uint64 sz = myproc()->sz;
    int got_null = 0;
    while (mx > 0 && srcva < sz) {
        char *p = (char *)srcva;
        if (*p != '\0') {
            *dst = *p;
        } else {
            *dst = '\0';
            got_null = 1;
            break;
        }
        ++dst, --mx, ++srcva;
    }
    if (got_null == 0)
        return -1;
    else
        return 0;
}

pagetable_t proc_kpagetable() {
    pagetable_t kpt = (pagetable_t)kalloc();
    if (NULL == kpt) return NULL;
    memmove(kpt, kernel_pagetable, PGSIZE);
    char *pstack = kalloc();
    if (pstack == NULL ||
        mappages(kpt, VKSTACK, PGSIZE, (uint64)pstack, PTE_R | PTE_W))
        goto fail;
    return kpt;

fail:
    kvmfree(kpt, 1);
    return NULL;
}

void kfreewalk(pagetable_t kpt) {
    for (int idx = 0; idx < 512; ++idx) {
        pte_t PTE = kpt[idx];
        if ((PTE & (PTE_R | PTE_W | PTE_X)) && (PTE & PTE_V)) {
            kfreewalk((pagetable_t)PTE2PA(PTE));
            kpt[idx] = 0;
        } else if (PTE_V & PTE) {
            break;
        }
    }
    kfree((void *)kpt);
}

void kvmfreeusr(pagetable_t kpt) {
    pte_t PTE;
    for (int idx = 0; idx < PX(2, MAXUVA); ++idx) {
        PTE = kpt[idx];
        if (!(PTE & (PTE_R | PTE_W | PTE_X)) && (PTE & PTE_V)) {
            kfreewalk((pagetable_t)PTE2PA(PTE));
            kpt[idx] = 0;
        }
    }
}

void kvmfree(pagetable_t kpt, int stkfree) {
    if (stkfree != 0) {
        vmunmap(kpt, VKSTACK, 1, 1);
        pte_t PTE = kpt[PX(2, VKSTACK)];
        if (!(PTE & (PTE_R | PTE_W | PTE_X)) && (PTE & PTE_V)) {
            kfreewalk((pagetable_t)PTE2PA(PTE));
        }
    }
    kvmfreeusr(kpt);
    kfree(kpt);
}

void vmprint(pagetable_t pgtb) {
    const int capacity = 512;
    printf("page table %p\n", pgtb);
    for (pte_t *PTE = (pte_t *)pgtb; PTE - pgtb < +capacity; ++PTE) {
        if (PTE_V & *PTE) {
            pagetable_t pt2 = (pagetable_t)PTE2PA(*PTE);
            printf("..%d: PTE %p pa %p\n", PTE - pgtb, *PTE, pt2);

            for (pte_t *pte2 = (pte_t *)pt2; pte2 - pt2 < capacity; ++pte2) {
                if ((*pte2 & PTE_V) != 0) {
                    pagetable_t pt3 = (pagetable_t)PTE2PA(*pte2);
                    printf(".. ..%d: PTE %p pa %p\n", pte2 - pt2, *pte2, pt3);

                    for (pte_t *pte3 = (pte_t *)pt3; pte3 - pt3 < capacity;
                         ++pte3)
                        if ((*pte3 & PTE_V) != 0)
                            printf(".. .. ..%d: PTE %p pa %p\n", pte3 - pt3,
                                   *pte3, PTE2PA(*pte3));
                }
            }
        }
    }
    return;
}

uint64 experm(pagetable_t pgtb, uint64 va, uint64 perm) {
    uint64 pa;
    pte_t *PTE;

    if (MAXVA <= va) return NULL;

    PTE = walk(pgtb, va, 0);
    if (!PTE || !(*PTE & PTE_V) || !(*PTE & PTE_U)) return NULL;
    *PTE |= perm;
    pa = PTE2PA(*PTE);
    return pa;
}

static int loadseg(pagetable_t pagetable, uint64 va, struct ext4_dirent *ep,
                   uint offset, uint sz) {
    uint i = 0, n;
    uint64 pa;
    uint64 va_off = 0;
    if ((va % PGSIZE) != 0) {
        va_off = va % PGSIZE;
        va = va - va_off;
        pa = walkaddr(pagetable, va);
        if ((void *)pa == NULL) panic("loadseg: address should exist");
        n = PGSIZE - va_off;
        if (ext4_eread(ep, 0, (uint64)(pa + va_off), offset, n) != n) {
            printf("loadseg: read error\n");
            return -1;
        }
        i += n;
        va += PGSIZE;
    }

    for (; i < sz;) {
        pa = walkaddr(pagetable, va);
        if ((void *)pa == NULL) panic("loadseg: address should exist");
        if (sz - i < PGSIZE)
            n = sz - i;
        else
            n = PGSIZE;
        if (ext4_eread(ep, 0, (uint64)pa, offset + i, n) != n) return -1;
        i += n;
        va += PGSIZE;
    }

    return 0;
}

