uint64 loadelf(struct elfhdr *elf, struct ext4_dirent *ep, struct proghdr *phdr,
               pagetable_t pagetable, pagetable_t kpagetable, uint64 *sz,
               int *is_dynamic) {
    uint64 sz1;
    int i, off;
    struct proghdr ph;
    int getphdr = 0;
    // Load program into memory.
    for (i = 0, off = elf->phoff; i < elf->phnum;
         i++, off += sizeof(struct proghdr)) {
        if (ext4_eread(ep, 0, (uint64)&ph, off, sizeof(struct proghdr)) !=
            sizeof(struct proghdr)) {
            printf("eread failed\n");
            return -1;
        }
        // printf(
        //     "ph.vaddr: %p, ph.memsz: %p, ph.filesz: %p, ph.off: %p, ph.flags:
        //     "
        //     "%p\n",
        //     ph.vaddr, ph.memsz, ph.filesz, ph.off, ph.flags);
        if (ph.type == ELF_PROG_LOAD) {
            if (ph.memsz < ph.filesz) {
                printf("ph.memsz < ph.filesz\n");
                return -1;
            }
            if (ph.vaddr + ph.memsz < ph.vaddr) {
                printf("ph.vaddr + ph.memsz < ph.vaddr\n");
                return -1;
            }
            if (!getphdr && phdr && ph.off == 0) {
                phdr->vaddr = elf->phoff + ph.vaddr;
            }
            int perm = 0;
            if (ph.flags & ELF_PROG_FLAG_EXEC) perm |= PTE_X;
            if (ph.flags & ELF_PROG_FLAG_WRITE) perm |= PTE_W;
            if (ph.flags & ELF_PROG_FLAG_READ) perm |= PTE_R;
            // printf("failed 1\n");
            if ((sz1 = uvmalloc(pagetable, kpagetable, *sz,
                                PGROUNDUP(ph.vaddr + ph.memsz), perm)) == 0) {
                printf("uvmalloc failed\n");
                return -1;
            }
            *sz = sz1;
            // printf("failed 2\n");
            if (loadseg(pagetable, ph.vaddr, ep, ph.off, ph.filesz) < 0) {
                printf("loadseg failed\n");
                return -1;
            }

            // printf("failed 3\n");
        } else if (ph.type == ELF_PROG_PHDR) {
            if (phdr) {
                getphdr = 1;
                *phdr = ph;
            }
        } else if (ph.type == ELF_PROG_INTERP) {
            *is_dynamic = 1;
        } else {
            // printf("ph.type: %d ph.type != ELF_PROG_LOAD\n", ph.type);
        }
    }
    // debug_print("loadelf success\n");
    return 0;
}

uint64 get_total_mapping_size(struct elfhdr *interp_elf_ex,
                              struct ext4_dirent *interpreter) {
    uint64 min_addr = -1;
    uint64 max_addr = 0;
    int is_true = 0;
    struct proghdr ph;
    for (uint i = 0, off = interp_elf_ex->phoff; i < interp_elf_ex->phnum;
         i++, off += sizeof(struct proghdr)) {
        if (ext4_eread(interpreter, 0, (uint64)&ph, off,
                       sizeof(struct proghdr)) != sizeof(struct proghdr)) {
            debug_print("[get_total_mapping_size]eread failed\n");
            return -1;
        }
        if (ph.type == ELF_PROG_LOAD) {
            min_addr = min(min_addr, PGROUNDDOWN(ph.vaddr));
            max_addr = max(max_addr, ph.vaddr + ph.memsz);
            is_true = 1;
        }
    }
    return is_true ? (max_addr - min_addr) : 0;
}

uint64 load_elf_interp(pagetable_t pagetable, struct elfhdr *interp_elf_ex,
                       struct ext4_dirent *interpreter) {
    uint64 total_size = 0;
    uint64 start_addr = 0;
    struct proghdr ph;
    /*----------------------获取总共需要的内存大小--------------------*/
    total_size = get_total_mapping_size(interp_elf_ex, interpreter);
    if (total_size == 0) {
        debug_print("[load_elf_interp]get_total_mapping_size failed\n");
        return -1;
    }
    /*----------------------分配总共需要的内存大小--------------------*/
    start_addr = mmap(LDSO, total_size, PROT_READ | PROT_WRITE | PROT_EXEC,
                      MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (start_addr == -1) {
        debug_print("[load_elf_interp]mmap failed\n");
        return -1;
    }
    /*----------------------加载elf文件--------------------*/
    for (uint i = 0, off = interp_elf_ex->phoff; i < interp_elf_ex->phnum;
         i++, off += sizeof(struct proghdr)) {
        if (ext4_eread(interpreter, 0, (uint64)&ph, off,
                       sizeof(struct proghdr)) != sizeof(struct proghdr)) {
            debug_print("[load_elf_interp]eread failed\n");
            return -1;
        }
        if (ph.type == ELF_PROG_LOAD) {
            if (ph.memsz < ph.filesz) {
                debug_print("[load_elf_interp]ph.memsz < ph.filesz\n");
                return -1;
            }
            if (ph.vaddr + ph.memsz < ph.vaddr) {
                debug_print(
                    "[load_elf_interp]ph.vaddr + ph.memsz < ph.vaddr\n");
                return -1;
            }
            if (loadseg(pagetable, start_addr + ph.vaddr, interpreter, ph.off,
                        ph.filesz) < 0) {
                debug_print("[load_elf_interp]loadseg failed\n");
                return -1;
            }
        }
    }
    return start_addr;
}

int user_stack_push_str(pagetable_t pt, uint64 *ustack, char *str, uint64 sp,
                        uint64 stackbase) {
    uint64 argc = ++ustack[0];
    if (argc > MAXARG + 1) {
        return -1;
    }
    sp -= strlen(str) + 1;
    sp -= sp % 16;  // riscv sp must be 16-byte aligned
    if (sp < stackbase) {
        return -1;
    }
    if (copyout(pt, sp, str, strlen(str) + 1) < 0) {
        printf("copyout failed\n");
        return -1;
    }
    ustack[argc] = sp;
    ustack[argc + 1] = 0;
    return sp;
}

void alloc_aux(uint64 *aux, uint64 atid, uint64 value) {
    // printf("aux[%d] = %p\n",atid,value);
    uint64 argc = aux[0];
    aux[argc * 2 + 1] = atid;
    aux[argc * 2 + 2] = value;
    aux[argc * 2 + 3] = 0;
    aux[argc * 2 + 4] = 0;
    aux[0]++;
}

int loadaux(pagetable_t pagetable, uint64 sp, uint64 stackbase, uint64 *aux) {
    int argc = aux[0];
    if (!argc) return sp;
    /*
    printf("aux argc:%d\n",argc);
    for(int i=1;i<=2*argc+2;i++){
      printf("final raw aux[%d] = %p\n",i,aux[i]);
    }
    */
    sp -= (2 * argc + 2) * sizeof(uint64);
    if (sp < stackbase) {
        return -1;
    }
    aux[0] = 0;
    if (copyout(pagetable, sp, (char *)(aux + 1),
                (2 * argc + 2) * sizeof(uint64)) < 0) {
        return -1;
    }
    return sp;
}

int is_sh_script(char *path) {
    int len = strlen(path);
    if (len < 3) {
        return 0;
    }
    if (path[len - 1] == 'h' && path[len - 2] == 's' && path[len - 3] == '.') {
        return 1;
    }
    return 0;
}

int exec(char *path, char **argv, char **env) {
    // printf("failed 0\n");
    if (strncmp(path, "libc-bench", 10)) {
        is_libcbench = 1;
    }

    char *s, *last;
    uint64 argc, sz = 0, sp, ustack[MAXARG + 1], stackbase;
    struct elfhdr elf;
    struct dirent *ed = NULL;
    struct ext4_dirent *epp = NULL;
    struct proghdr ph;
    pagetable_t pagetable = 0, oldpagetable;
    pagetable_t kpagetable = 0, oldkpagetable;
    struct ext4_dirent *interpreter = NULL;
    struct elfhdr interpreter_elf;
    uint64 interp_start_addr = 0;
    uint64 program_entry = 0;
    int is_dynamic = 0;
    struct proc *p = myproc();
    free_vma_list(p);
    vma_init(p);
    // printf("failed 001\n");
    oldpagetable = p->pagetable;
    oldkpagetable = p->kpagetable;

    kpagetable = create_kpagetable(p);

    if (kpagetable == 0) {
        debug_print("[exec]create_kpagetable failed\n");
        return -1;
    }
    int is_shell_script = is_sh_script(path);
    if (is_shell_script) {
        goto bad;
    }

    int r = 0;
    char file_path[EXT4_MAX_FILENAME + 1];
    if (path[0] != '/') {
        file_path[0] = '/';
        memcpy(file_path + 1, path, EXT4_MAX_FILENAME - 1);
    } else {
        memcpy(file_path, path, EXT4_MAX_FILENAME);
    }
    printf("file path is %s\n", file_path);

    int ret = fileexists(file_path);
    if (!ret) {
        return ret;
    }
    // printf("failed 001\n");
    epp = ext4_getdir_fcache(&root_entry, file_path);
    // ep.dir = root_dir1;
    // ep.file = f;
    // r = ext4_dir_open(&ep.dir, "/");
    r = ext4_dir_open(&(epp->dir), "/");
    if (r) printf("dir open failed: %d\n", r);

    r = ext4_fopen(&epp->file, file_path, "r+");
    if (r) {
        printf("ext4 fopen failed: %d\n", r);
        goto bad;
    }

    size_t rb = 0;

    r = ext4_fread(&epp->file, read_buffer, 4096, &rb);
    if (r) {
        printf("ext4 fread failed: %d\n", r);
        goto bad;
    }

    ext4_edup(epp);
    ext4_elock(epp);
    // printf("locked\n");

    if (readelfhdr(epp, &elf) < 0) {
        printf("readelfhdr failed\n");
        goto bad;
    }

    if ((pagetable = proc_pagetable(p)) == NULL) goto bad;

    // 此处修改是为了mmap映射动态链接时更方便
    p->pagetable = pagetable;

    // Load program into memory.
    if (loadelf(&elf, epp, &ph, pagetable, kpagetable, &sz, &is_dynamic) < 0) {
        printf("loadelf failed\n");
        goto bad;
    }
    /* -------------------动态链接-------------------------------------------*/
    // 动态链接目前默认处理/libc.so

    // printf("failed 4\n");
    if (is_dynamic) {
        interpreter = ext4_getdir_fcache(&root_entry, "/lib/musl/libc.so");
        r = ext4_fopen(&interpreter->file, "/lib/musl/libc.so", "r+");
        if (r) {
            debug_print("ext4 open interp failed: %d\n", r);
            goto bad;
        }

        ext4_elock(interpreter);
        if (readelfhdr(interpreter, &interpreter_elf) < 0) {
            debug_print("readelfhdr failed\n");
            goto bad;
        }

        interp_start_addr =
            load_elf_interp(pagetable, &interpreter_elf, interpreter);
        program_entry = interp_start_addr + interpreter_elf.entry;
        debug_print("interp_start_addr:%p program_entry:%p\n",
                    interp_start_addr, program_entry);

        ext4_eunlock(interpreter);
        ext4_eput(interpreter);
        interpreter = NULL;
    } else {
        program_entry = elf.entry;
    }

    /*--------------------动态链接结束---------------------------------------*/
    ext4_eunlock(epp);
    ext4_eput(epp);
    epp = 0;

    p = myproc();

    // printf("failed 5\n");
    uint64 oldsz = p->sz;
    alloc_vma_stack(p);
    sp = get_proc_sp(p);
    stackbase = sp - INIT_STACK_SIZE;
    // printf("[exec] stackbase: %p stacktop: %p\n", stackbase, sz);

    /*--------------------开始处理environment---------------------------------------*/
    uint64 envp[MAXARG + 1];
    envp[0] = 0;
    if ((sp = user_stack_push_str(pagetable, envp, "UB_BINDIR=.", sp,
                                  stackbase)) == -1) {
        printf("user_stack_push_str failed 1\n");
        goto bad;
    }

    // 添加随机数
    uint64 random[2] = {0xcde142a16cb93072, 0x128a39c127d8bbf2};
    sp -= 16;
    if (sp < stackbase || copyout(pagetable, sp, (char *)random, 16) < 0) {
        printf("[exec] random copy bad\n");
        goto bad;
    }

    // printf("elf entry: %p\n", elf.entry);

    uint64 aux[MAXARG * 2 + 3] = {0, 0, 0};
    alloc_aux(aux, AT_HWCAP, 0);
    alloc_aux(aux, AT_PAGESZ, PGSIZE);
    alloc_aux(aux, AT_PHDR, ph.vaddr);
    alloc_aux(aux, AT_PHENT, elf.phentsize);
    alloc_aux(aux, AT_PHNUM, elf.phnum);
    alloc_aux(aux, AT_BASE, interp_start_addr);
    alloc_aux(aux, AT_ENTRY, elf.entry);
    alloc_aux(aux, AT_UID, 0);
    alloc_aux(aux, AT_EUID, 0);
    alloc_aux(aux, AT_GID, 0);
    alloc_aux(aux, AT_EGID, 0);
    alloc_aux(aux, AT_SECURE, 0);
    alloc_aux(aux, AT_RANDOM, sp);
    // printf("coming 2\n");
    // Push argument strings, prepare rest of stack in ustack.
    ustack[0] = 0;
    int redirection = -1;
    int jump = 0;
    char *redir_file = 0;
    for (argc = 0; argv[argc]; argc++) {
        if (strlen(argv[argc]) == 1 && strncmp(argv[argc], ">", 1) == 0) {
            // printf("redirection 1 %s\n", argv[argc]);
            redirection = REDIR_OUT;
            continue;
        } else if (strlen(argv[argc]) == 2 &&
                   strncmp(argv[argc], ">>", 2) == 0) {
            // printf("redirection 2\n");
            redirection = REDIR_APPEND;
            continue;
        }
        if (redirection != -1 && jump == 0) {
            redir_file = argv[argc];
            jump = 1;
            continue;
        }
        if (argc >= MAXARG) goto bad;
        if ((sp = user_stack_push_str(pagetable, ustack, argv[argc], sp,
                                      stackbase)) == -1) {
            printf("user_stack_push_str failed 2\n");
            goto bad;
        }
    }
    uint64 envnum = 0;
    if (env) {
        for (envnum = 0; env[envnum]; envnum++) {
            if ((sp = user_stack_push_str(pagetable, envp, env[envnum], sp,
                                          stackbase)) == -1) {
                printf("user_stack_push_str failed 3\n");
                goto bad;
            }
        }
    }

    if ((sp = loadaux(pagetable, sp, stackbase, aux)) == -1) {
        printf("loadaux failed\n");
        goto bad;
    }

    argc = envp[0];
    if (argc) {
        sp -= (argc + 1) * sizeof(uint64);
        if (sp < stackbase) {
            printf("sp < stackbase\n");
            goto bad;
        }
        sp -= sp % 8;
        if (copyout(pagetable, sp, (char *)(envp + 1),
                    (argc + 1) * sizeof(uint64)) < 0) {
            printf("copyout failed\n");
            goto bad;
        }
    }
    argc = ustack[0];
    // push the array of argv[] pointers.
    sp -= (argc + 2) * sizeof(uint64);
    sp -= sp % 8;
    if (sp < stackbase) goto bad;
    if (copyout(pagetable, sp, (char *)ustack, (argc + 2) * sizeof(uint64)) < 0)
        goto bad;

    // printf("ustack[0]:%d\n",ustack[0]);
    // printf("sp:%p\n", sp);
    // stackdisplay(pagetable, sp, MAXUVA - 0x1000 - sp);
    // arguments to user main(argc, argv)
    // argc is returned via the system call return
    // value, which goes in a0.
    p->trapframe->a1 = sp + 8;

    // Save program name for debugging.
    for (last = s = path; *s; s++)
        if (*s == '/') last = s + 1;
    safestrcpy(p->name, last, sizeof(p->name));

    // Commit to the user image.

    p->pagetable = pagetable;
    p->kpagetable = kpagetable;
    p->sz = sz;
    p->trapframe->epc = program_entry;  // initial program counter = main
    p->trapframe->sp = sp;              // initial stack pointer
    // debug_print("program entry:%p\n", program_entry);
    // maybe it's wrong
    for (int fd = 0; fd < NOFILEMAX(p); fd++) {
        struct file *f = p->ofile[fd];
        if (f && p->exec_close[fd]) {
            fileclose(f);
            p->ofile[fd] = 0;
            p->exec_close[fd] = 0;
        }
    }
    // 处理重定向
    if (redirection != -1) {
        fileclose(p->ofile[1]);
        p->ofile[1] = 0;
        int fd = 0;
        if (redirection == REDIR_OUT) {
            fd = open(redir_file, O_WRONLY | O_CREATE);
        } else if (redirection == REDIR_APPEND) {
            fd = open(redir_file, O_WRONLY | O_CREATE | O_APPEND);
        }
        // if (fd != 1) {
        //     debug_print("[exec]:fd != 1\n");
        //     goto bad;
        // }
        p->exec_close[1] = fd;
    }

    proc_freepagetable(oldpagetable, oldsz);
    w_satp(MAKE_SATP(p->kpagetable));
    sfence_vma();
    kvmfree(oldkpagetable, 0);

    // print_vma(p);

    return 0;  // this ends up in a0, the first argument to main(argc, argv)

bad:
#ifdef DEBUG
    printf("[exec] reach bad\n");
#endif
    if (pagetable) proc_freepagetable(pagetable, sz);
    if (kpagetable) kvmfree(kpagetable, 0);
    if (interpreter) {
        ext4_eunlock(interpreter);
        ext4_eput(interpreter);
    }
    if (epp) {
        ext4_eunlock(epp);
        ext4_eput(epp);
    }
    if (is_shell_script) {
        exit(0);
    }
    return -1;
}

struct run {
    struct run *next;
}

struct {
    struct spinlock lock;
    struct run *freelist;
    uint64 npage;
}

void kinit() {
    initlock(&kmem.lock, "kmem");
    kmem.npage = 0;
    kmem.freelist = 0;
    freerange(kernel_end, (void *)PHYSTOP);
#ifdef DEBUG
    printf("kernel_end: %p, phystop: %p\nkinit\n", kernel_end, (void *)PHYSTOP);
#endif
}

void freerange(void *pa_st, void *pa_ed) {
    char *page_ptr;
    page_ptr = (char *)PGROUNDUP((uint64)pa_st);
    for (; (char *)pa_ed >= PGSIZE + page_ptr; page_ptr += PGSIZE)
        kfree(page_ptr);
}

void kfree(void *phys_addr) {
    struct run *r_ptr;

    if (kernel_end > (char *)phys_addr || PHYSTOP <= (uint64)phys_addr ||
        ((uint64)phys_addr % PGSIZE) != 0)
        panic("kfree");

    memset(phys_addr, 1, PGSIZE);
    r_ptr = (struct run *)phys_addr;
    acquire(&kmem.lock);
    r_ptr->next = kmem.freelist;
    kmem.freelist = r_ptr;
    ++kmem.npage;
    release(&kmem.lock);
}

void *kalloc(void) {
    struct run *r_ptr;
    acquire(&kmem.lock);
    r_ptr = kmem.freelist;
    if (r_ptr != 0) {
        kmem.freelist = r_ptr->next;
        --kmem.npage;
    }
    release(&kmem.lock);
    if (r_ptr != 0) memset((char *)r_ptr, 5, PGSIZE);
    return (void *)r_ptr;
}

void *kmalloc(uint64 size) {
    if (size == 0) {
        return NULL;
    }

    // 计算需要多少个页面
    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;
    void *addr = NULL;
    void *current_page;

    // 分配多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        current_page = kalloc();
        if (current_page == NULL) {
            // 分配失败，释放已经分配的页面
            for (uint64 j = 0; j < i; ++j) {
                kfree((char *)addr + j * PGSIZE);
            }
            return NULL;
        }
        if (i == 0) {
            addr = current_page;
        }
    }
    return addr;
}

void *cmalloc(uint64 cnt, uint each_size) {
    uint64 size = cnt * each_size;
    // printf("size is %d\n", size);
    if (size == 0) {
        return NULL;
    }

    // 计算需要多少个页面
    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;
    void *addr = NULL;
    void *current_page;

    // 分配多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        current_page = kalloc();
        memset(current_page, 0, PGSIZE);
        if (current_page == NULL) {
            // 分配失败，释放已经分配的页面
            for (uint64 j = 0; j < i; ++j) {
                kfree((char *)addr + j * PGSIZE);
            }
            return NULL;
        }
        if (i == 0) {
            addr = current_page;
        }
    }

    return addr;
}

void free(void *addr, uint64 size) {
    if (addr == NULL || size == 0) {
        return;
    }

    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;

    // 释放多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        kfree((char *)addr + i * PGSIZE);
    }
}

int pipealloc(struct file **file0, struct file **file1) {
    struct pipe *Pipe;

    *file0 = *file1 = 0;
    Pipe = 0;
    if ((*file0 = filealloc()) == NULL || (*file1 = filealloc()) == NULL)
        goto bad;
    if ((Pipe = (struct pipe *)kalloc()) == NULL) goto bad;

    Pipe->readopen = 1;
    Pipe->writeopen = 1;
    Pipe->nwrite = 0;
    Pipe->nread = 0;

    initlock(&Pipe->lock, "pipe");
    (*file0)->writable = 0;
    (*file0)->pipe = Pipe;
    (*file0)->type = FD_PIPE;
    (*file0)->readable = 1;

    (*file1)->writable = 1;
    (*file1)->pipe = Pipe;
    (*file1)->type = FD_PIPE;
    (*file1)->readable = 0;

    return 0;

bad:
    if (Pipe != 0) kfree((char *)Pipe);
    if (*file0) fileclose(*file0);
    if (*file1) fileclose(*file1);
    return -1;
}

void pipeclose(struct pipe *Pipe, int writable) {
    acquire(&Pipe->lock);
    if (writable == 0) {
        Pipe->readopen = 0;
        wakeup(&Pipe->nwrite);
    } else {
        Pipe->writeopen = 0;
        wakeup(&Pipe->nread);
    }
    if (!Pipe->writeopen && !Pipe->readopen) {
        release(&Pipe->lock);
        kfree((char *)Pipe);
    } else {
        release(&Pipe->lock);
    }
}

int pipewrite(struct pipe *pi, int user, uint64 addr, int n) {
    int i;
    char ch;
    struct proc *pr = myproc();

    acquire(&pi->lock);
    for (i = 0; i < n; i++) {
        while (pi->nwrite == pi->nread + PIPESIZE) {  // DOC: pipewrite-full
            if (pi->readopen == 0 || pr->killed) {
                release(&pi->lock);
                return -1;
            }
            wakeup(&pi->nread);
            sleep(&pi->nwrite, &pi->lock);
        }
        if (either_copyin(&ch, user, addr + i, 1) == -1) break;
        pi->data[pi->nwrite++ % PIPESIZE] = ch;
    }
    wakeup(&pi->nread);
    release(&pi->lock);
    return i;
}

int piperead(struct pipe *pi, int user, uint64 addr, int n) {
    int i;
    struct proc *pr = myproc();
    char ch;

    acquire(&pi->lock);
    while (pi->nread == pi->nwrite && pi->writeopen) {  // DOC: pipe-empty
        if (pr->killed) {
            release(&pi->lock);
            return -1;
        }
        sleep(&pi->nread, &pi->lock);  // DOC: piperead-sleep
    }
    for (i = 0; i < n; i++) {  // DOC: piperead-copy
        if (pi->nread == pi->nwrite) break;
        ch = pi->data[pi->nread++ % PIPESIZE];
        if (either_copyout(user, addr + i, &ch, 1) == -1) break;
    }
    wakeup(&pi->nwrite);  // DOC: piperead-wakeup
    release(&pi->lock);
    return i;
}

