static struct proc *allocproc(void) {
    struct proc *new_proc;
    // printf("new proc\n");
    for (new_proc = proc; &proc[NPROC] > new_proc; ++new_proc) {
        acquire(&new_proc->lock);
        if (new_proc->state != UNUSED) {
            release(&new_proc->lock);
        } else
            goto found;
    }
    return NULL;

found:
    new_proc->ktime = 1;
    new_proc->utime = 1;
    new_proc->pid = allocpid();
    new_proc->vma = NULL;
    new_proc->filelimit = NOFILE;
    new_proc->uid = new_proc->gid = new_proc->pgid = 0;
    new_proc->thread_num = 0;
    new_proc->clear_child_tid = NULL;
    memset(new_proc->sigaction, 0, sizeof(new_proc->sigaction));
    memset(new_proc->sig_set.__val, 0, sizeof(new_proc->sig_set));
    memset(new_proc->sig_pending.__val, 0, sizeof(new_proc->sig_pending));
    if ((new_proc->trapframe = (struct trapframe *)kalloc()) == NULL) {
        release(&new_proc->lock);
        return NULL;
    }
    // An empty user page table.
    // And an identical kernel page table for this proc.
    if ((new_proc->pagetable = proc_pagetable(new_proc)) == NULL ||
        (new_proc->kpagetable = proc_kpagetable()) == NULL) {
        freeproc(new_proc);
        release(&new_proc->lock);
        return NULL;
    }

    new_proc->kstack = VKSTACK;

    new_proc->exec_close = kalloc();
    for (int fd = 0; fd < NOFILE; fd++) {
        new_proc->exec_close[fd] = 0;
    }

    // Set up new context to start executing at forkret,
    // which returns to user space.
    memset(&new_proc->context, 0, sizeof(new_proc->context));
    new_proc->context.ra = (uint64)forkret;
    // printf("fork ret\n");
    new_proc->context.sp = PGSIZE + new_proc->kstack;
    new_proc->main_thread = alloc_thread();
    copycontext(&new_proc->main_thread->context, &new_proc->context);
    new_proc->thread_num++;
    new_proc->main_thread->p = new_proc;
    new_proc->main_thread->sz = new_proc->sz;
    new_proc->main_thread->clear_child_tid = new_proc->clear_child_tid;
    new_proc->main_thread->kstack = new_proc->kstack;
    new_proc->thread_queue = new_proc->main_thread;
    if (mappages(new_proc->kpagetable, new_proc->kstack - PGSIZE, PGSIZE,
                 (uint64)(new_proc->main_thread->trapframe), PTE_R | PTE_W) < 0)
        panic("allocproc: map thread trapframe failed");
    new_proc->main_thread->vtf = new_proc->kstack - PGSIZE;
    return new_proc;
}

static void freeproc(struct proc *p) {
    if (p->trapframe) kfree((void *)p->trapframe);

    kfree((void *)p->exec_close);
    p->trapframe = 0;

    thread *t = p->thread_queue;
    while (NULL != t) {
        thread *tmp = t->next_thread;
        if (NULL != t->next_thread) t->next_thread->pre_thread = NULL;
        t->state = t_UNUSED;
        t->next_thread = free_thread;
        if (NULL != free_thread) free_thread->pre_thread = t;
        free_thread = t;
        kfree((void *)t->trapframe);
        if (t->kstack != p->kstack) {
            vmunmap(p->kpagetable, t->kstack, 1, 0);
            kfree((void *)t->kstack_pa);
        }
        t = tmp;
    }

    if (p->kpagetable) {
        kvmfree(p->kpagetable, 1);
    }
    p->kpagetable = 0;
    if (p->pagetable) {
        free_vma_list(p);
        proc_freepagetable(p->pagetable, p->sz);
    }
    // TODO: free threads
    // printf("free proc : %d freemem_mount:%p\n",p->pid, freemem_amount());
    p->pagetable = 0;
    p->vma = NULL;
    p->sz = 0;
    p->pid = 0;
    p->main_thread->state = t_UNUSED;
    p->main_thread = 0;
    p->parent = 0;
    p->name[0] = 0;
    p->chan = 0;
    p->killed = 0;
    p->xstate = 0;
    p->state = UNUSED;
}

struct vma *vma_init(struct proc *p) {
    if (p == NULL) {
        printf("p is not existing\n");
        return NULL;
    }
    struct vma *vma = (struct vma *)kalloc();
    if (vma == NULL) {
        printf("vma kalloc failed\n");
        return NULL;
    }
    vma->type = NONE;
    vma->prev = vma->next = vma;
    p->vma = vma;

    if (alloc_mmap_vma(p, 0, USER_MMAP_START, 0, 0, 0, 0) == NULL) {
        // free_vma_list(p);
        return NULL;
    }
    return vma;
}

struct vma *alloc_vma(struct proc *p, enum segtype type, uint64 addr, uint64 sz,
                      int perm, int allocation, uint64 padr) {
    uint64 st = PGROUNDDOWN(addr);
    uint64 end = addr + sz;
    end = PGROUNDUP(end);

    struct vma *find_vma = p->vma->next;
    while (find_vma != p->vma) {
        if (end <= find_vma->addr)
            break;
        else if (st >= find_vma->end)
            find_vma = find_vma->next;
        else {
            printf("vma address overflow\n");
            return NULL;
        }
    }
    struct vma *vma = (struct vma *)kalloc();
    if (NULL == vma) {
        printf("vma kalloc failed\n");
        return NULL;
    }
    if (0 != sz) {
        if (allocation) {
            if (0 != uvmalloc1(p->pagetable, st, end, perm)) {
                printf("uvmalloc failed\n");
                kfree(vma);
                return NULL;
            }
        } else if (padr != 0) {
            if (0 != mappages(p->pagetable, st, sz, padr, perm)) {
                printf("mappages failed\n");
                kfree(vma);
                return NULL;
            }
        }
    }
    vma->addr = st;
    vma->sz = sz;
    vma->perm = perm;
    vma->end = end;
    vma->fd = -1;
    vma->f_off = 0;
    vma->type = type;
    vma->prev = find_vma->prev;
    vma->next = find_vma;
    find_vma->prev->next = vma;
    find_vma->prev = vma;

    return vma;
}

struct vma *find_mmap_vma(struct vma *head) {
    struct vma *vma = head->next;
    while (vma != head) {
        if (vma->type == MMAP) return vma;
        vma = vma->next;
    }
    return NULL;
}

struct vma *alloc_mmap_vma(struct proc *p, int flags, uint64 addr, uint64 sz,
                           int perm, int fd, uint64 f_off) {
    struct vma *vma = NULL;
    struct vma *find_vma = find_mmap_vma(p->vma);
    if (!addr) addr = PGROUNDDOWN(find_vma->addr - sz);
    vma = alloc_vma(p, MMAP, addr, sz, perm, 1, NULL);
    if (vma == NULL) {
        printf("alloc_mmap_vma: alloc_vma failed\n");
        return NULL;
    }

    vma->f_off = f_off, vma->fd = fd;

    return vma;
}

struct vma *vma_copy(struct proc *np, struct vma *head) {
    struct vma *new_vma = (struct vma *)kalloc();
    if (NULL == new_vma) {
        debug_print("vma copy failed\n");
        goto failure;
    }
    new_vma->next = new_vma->prev = new_vma;
    new_vma->type = NONE;
    np->vma = new_vma;

    struct vma *pre_vma = head->next;
    struct vma *nvma = NULL;
    while (pre_vma != head) {
        nvma = (struct vma *)kalloc();  // TODO: fix this
        if (NULL == nvma) {
            goto failure;
        }
        memmove(nvma, pre_vma, sizeof(struct vma));
        nvma->next = nvma->prev = NULL;
        nvma->prev = new_vma->prev;
        nvma->next = new_vma;
        new_vma->prev->next = nvma;
        new_vma->prev = nvma;
        pre_vma = pre_vma->next;
    }

    return new_vma;

failure:
    np->vma = NULL;
    // TODO free_vma_list
    return NULL;
}

int vma_map(pagetable_t old, pagetable_t new, struct vma *vma) {
    uint64 start = vma->addr;
    pte_t *pte;
    uint64 pa;
    char *mem;
    long flags;

    while (start < vma->end) {
        if ((pte = walk(old, start, 0)) == NULL) {
            panic("uvmcopy: pte should exist");
        }
        if ((*pte & PTE_V) == 0) {
            panic("uvmcopy: page not present");
        }
        pa = PTE2PA(*pte);
        flags = PTE_FLAGS(*pte);
        mem = (char *)kalloc();

        if (NULL == mem) goto failure2;
        memmove(mem, (char *)pa, PGSIZE);

        if (mappages(new, start, PGSIZE, (uint64)mem, flags) != 0) {
            kfree(mem);
            goto failure2;
        }

        start += PGSIZE;
    }

    pa = walkaddr(new, vma->addr);
    return 0;

failure2:
    vmunmap(new, vma->addr, (start - vma->addr) / PGSIZE, 1);
    return -1;
}

int free_vma(struct proc *p, struct vma *del) {
    if (del == NULL) {
        debug_print("[free_vma] del is nil\n");
        return 0;
    }
    if (del->prev == NULL || del->next == NULL) {
        debug_print("[free_vma] del is illegal\n");
        return 0;
    }

    struct vma *prev = del->prev;
    struct vma *next = del->next;
    prev->next = next;
    next->prev = prev;
    del->next = del->prev = NULL;
    if (uvmdealloc1(p->pagetable, del->addr, del->end) != 0) {
        debug_print("[free_vma] uvmdealloc fail\n");
        return 0;
    }
    kfree(del);
    del = NULL;
    return 1;
}

int free_vma_list(struct proc *p) {
    struct vma *vma_head = p->vma;
    if (vma_head == NULL) {
        return 1;
    }
    struct vma *vma = vma_head->next;

    while (vma != vma_head) {
        uint64 a;
        pte_t *pte;
        for (a = vma->addr; a < vma->end; a += PGSIZE) {
            if ((pte = walk(p->pagetable, a, 0)) == 0) continue;
            if ((*pte & PTE_V) == 0) continue;
            if (PTE_FLAGS(*pte) == PTE_V) continue;
            uint64 pa = PTE2PA(*pte);
            kfree((void *)pa);
            *pte = 0;
        }
        vma = vma->next;
        kfree(vma->prev);
    }
    kfree(vma);
    p->vma = NULL;
    return 1;
}

pagetable_t proc_pagetable(struct proc *p) {
    pagetable_t pgtb = uvmcreate();
    if (!pgtb) return NULL;

    if (NULL == vma_init(p)) {
        uvmfree(pgtb, 0);
        return NULL;
    }
    // only the supervisor uses it, on the way
    // to/from user space, so not PTE_U.
    // map the trampoline code (for system call return)
    // printf("failed 1\n");
    if (mappages(pgtb, TRAMPOLINE, PGSIZE, (uint64)trampoline, PTE_R | PTE_X) <
        0) {
        uvmfree(pgtb, 0);
        return NULL;
    }
    // printf("failed 2\n");
    if (mappages(pgtb, TRAPFRAME, PGSIZE, (uint64)(p->trapframe),
                 PTE_R | PTE_W) < 0) {
        vmunmap(pgtb, TRAMPOLINE, 1, 0);
        uvmfree(pgtb, 0);
        return NULL;
    }
    // printf("failed 3\n");
    if (mappages(pgtb, SIGTRAMPOLINE, PGSIZE, (uint64)signal_trampoline,
                 PTE_R | PTE_X | PTE_U) < 0) {
        vmunmap(pgtb, TRAMPOLINE, 1, 0);
        vmunmap(pgtb, TRAPFRAME, 1, 0);
        uvmfree(pgtb, 0);
        return NULL;
    }
    // printf("failed 4\n");
    return pgtb;
}

void proc_freepagetable(pagetable_t pgtb, uint64 sz) {
    vmunmap(pgtb, TRAMPOLINE, 1, 0);
    vmunmap(pgtb, TRAPFRAME, 1, 0);
    vmunmap(pgtb, SIGTRAMPOLINE, 1, 0);
    uvmfree(pgtb, sz);
}

void userinit(void) {
    struct proc *p;
    p = allocproc();
    initproc = p;
    // allocate one user page and copy init's instructions
    // and data into it.
    // uvminit(p->pagetable, p->kpagetable, initcode, sizeof(initcode));
    uvminit(p->pagetable, p->kpagetable, initcode, initcode_size);
    p->sz = initcode_size;
    p->sz = PGROUNDUP(p->sz);
    // prepare for the very first "return" from kernel to user.
    alloc_vma_stack(p);
    p->trapframe->sp = get_proc_sp(p), p->trapframe->epc = 0x0;
    safestrcpy(p->name, "initcode", sizeof p->name);
    p->state = RUNNABLE, p->tmask = 0;
    copytrapframe(p->main_thread->trapframe, p->trapframe);
    p->main_thread->state = t_RUNNABLE;
    release(&p->lock);
//     printf("first usercode: %p\n", initcode);
#ifdef DEBUG
    printf("userinit\n");
#endif
}

int growproc(int n) {
    struct proc *p = myproc();
    uint sz = p->sz;
    if (n < 0) {
        sz = uvmdealloc(p->pagetable, p->kpagetable, sz, sz + n);
    } else if (n > 0) {
        if ((sz = uvmalloc(p->pagetable, p->kpagetable, sz, sz + n,
                           PTE_R | PTE_W)) == 0) {
            return -1;
        }
    }
    p->sz = sz;
    return 0;
}

int fork(void) {
    int i, pid;
    struct proc *np;
    struct proc *p = myproc();

    // Allocate process.
    if ((np = allocproc()) == NULL) {
        return -1;
    }

    // Copy user memory from parent to child.
    if (uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz) < 0) {
        freeproc(np);
        release(&np->lock);
        return -1;
    }
    // printf("failed 002\n");
    struct vma *nvma = vma_copy(np, p->vma);
    if (NULL != nvma) {
        nvma = nvma->next;
        while (nvma != np->vma) {
            if (vma_map(p->pagetable, np->pagetable, nvma) < 0) {
                printf("clone: vma deep mapping failed\n");
                return -1;
            }
            nvma = nvma->next;
        }
    }
    // printf("failed 003\n");
    np->sz = p->sz;

    np->parent = p;

    // copy tracing mask from parent.
    np->tmask = p->tmask;

    // copy saved user registers.
    *(np->trapframe) = *(p->trapframe);

    // Cause fork to return 0 in the child.
    np->trapframe->a0 = 0;
    copytrapframe(np->main_thread->trapframe, np->trapframe);
    // increment reference counts on open file descriptors.
    for (int idx = 0; NOFILE > idx; ++idx)
        if (p->ofile[idx]) np->ofile[idx] = filedup(p->ofile[idx]);
    // np->cwd = edup(p->cwd);
    np->ext4_dir = ext4_edup(p->ext4_dir);
    safestrcpy(np->name, p->name, sizeof(p->name));

    pid = np->pid;

    np->state = RUNNABLE;
    np->main_thread->state = t_RUNNABLE;

    release(&np->lock);

    return pid;
}

void reparent(struct proc *p) {
    for (struct proc *q = proc; q < &proc[NPROC]; ++q) {
        if (p == q->parent) {
            acquire(&q->lock);
            q->parent = initproc;
            release(&q->lock);
        }
    }
}

void exit(int status) {
    struct proc *p = myproc();
    if (initproc == p) panic("init exiting");
    // Close all open files.
    for (int i = 0; i < NOFILE; ++i) {
        if (p->ofile[i] != 0) {
            struct file *f = p->ofile[i];
            fileclose(f);
            p->ofile[i] = 0;
        }
    }
    // eput(p->cwd);
    ext4_eput(p->ext4_dir);
    p->cwd = 0;
    // we might re-parent a child to init. we can't be precise about
    // waking up init, since we can't acquire its lock once we've
    // acquired any other proc lock. so wake up init whether that's
    // necessary or not. init may miss this wakeup, but that seems
    // harmless.
    acquire(&initproc->lock);
    wakeup1(initproc);
    release(&initproc->lock);
    // grab a copy of p->parent, to ensure that we unlock the same
    // parent we locked. in case our parent gives us away to init while
    // we're waiting for the parent lock. we may then race with an
    // exiting parent, but the result will be a harmless spurious wakeup
    // to a dead or wrong process; proc structs are never re-allocated
    // as anything else.
    acquire(&p->lock);
    struct proc *original_parent = p->parent;
    release(&p->lock);
    acquire(&original_parent->lock);
    acquire(&p->lock);
    reparent(p);
    // Parent might be sleeping in wait().
    wakeup1(original_parent);
    // Parent might be sleeping in wait4pid().
    if (original_parent->state == SLEEPING && original_parent->chan == p) {
        original_parent->state = RUNNABLE;
    }

    p->xstate = status;
    p->state = ZOMBIE;
    p->main_thread->state = t_ZOMBIE;

    release(&original_parent->lock);
    sched();
    panic("zombie exit");
}

int wait(uint64 addr) {
    int kids, pid;
    struct proc *np, *p = myproc();

    // hold p->lock for the whole time to avoid lost
    // wakeups from a child's exit().
    acquire(&p->lock);

    while (1) {
        kids = 0;
        for (np = proc; &proc[NPROC] > np; ++np) {
            // this code uses np->parent without holding np->lock.
            // acquiring the lock first would cause a deadlock,
            // since np might be an ancestor, and we already hold p->lock.
            if (np->parent == p) {
                acquire(&np->lock);
                kids = 1;
                if (np->state == ZOMBIE) {
                    // Found one.
                    pid = np->pid;
                    if (addr && 0 > copyout2(addr, (char *)&np->xstate,
                                             sizeof(np->xstate))) {
                        release(&np->lock), release(&p->lock);
                        return -1;
                    }
                    freeproc(np);
                    release(&np->lock), release(&p->lock);
                    return pid;
                }
                release(&np->lock);
            }
        }
        if (p->killed != 0 || !kids) {
            release(&p->lock);
            return -1;
        }
        sleep(p, &p->lock);
    }
}

void scheduler(void) {
    struct cpu *c = mycpu();
    extern pagetable_t kernel_pagetable;
    c->proc = 0;
    while (1) {
        // Avoid deadlock by ensuring that devices can interrupt.
        intr_on();
        int found = 0;
        for (struct proc *p = proc; &proc[NPROC] > p; ++p) {
            acquire(&p->lock);
            if (RUNNABLE == p->state) {
                thread *t = p->thread_queue;
                while (NULL != t) {
                    if (t->state == t_RUNNABLE ||
                        (t->state == t_TIMING &&
                         t->awakeTime < r_time() + (1LL << 35)))
                        break;
                    t = t->next_thread;
                }
                if (NULL == t) continue;
                if (p->thread_queue != t) {  // 放到队首，避免死线程集中在首部
                    if (NULL != t->next_thread) {
                        t->next_thread->pre_thread = t->pre_thread;
                    }
                    if (NULL != t->pre_thread) {
                        t->pre_thread->next_thread = t->next_thread;
                    }
                    t->pre_thread = NULL;
                    t->next_thread = p->thread_queue;
                    p->thread_queue->pre_thread = t;
                    p->thread_queue = t;
                }
                p->main_thread = t;
                copycontext(&p->context, &p->main_thread->context);
                copytrapframe(p->trapframe, p->main_thread->trapframe);
                p->main_thread->state = t_RUNNING;
                p->main_thread->awakeTime = 0;
                p->state = RUNNING;
                futexClear(p->main_thread);
                c->proc = p;
                w_satp(MAKE_SATP(p->kpagetable));
                sfence_vma();
                swtch(&c->context, &p->context);
                copycontext(&p->main_thread->context, &p->context);
                w_satp(MAKE_SATP(kernel_pagetable));
                sfence_vma();
                // Process is done running for now.
                // It should have changed its p->state before coming back.
                c->proc = 0;

                found = 1;
            }
            release(&p->lock);
        }
        if (!found) {
            intr_on();
            asm volatile("wfi");
        }
    }
}

void sched(void) {
    struct proc *p = myproc();
    if (!holding(&p->lock)) panic("sched p->lock");
    if (mycpu()->noff != 1) panic("sched locks");
    if (RUNNING == p->state || p->main_thread->state == t_RUNNING)
        panic("sched running");
    if (intr_get()) panic("sched interruptible");

    copytrapframe(p->main_thread->trapframe, p->trapframe);
    int intena = mycpu()->intena;
    swtch(&p->context, &mycpu()->context);
    mycpu()->intena = intena;
}

void yield(void) {
    struct proc *Proc = myproc();
    acquire(&Proc->lock);
    Proc->state = RUNNABLE;
    Proc->main_thread->state = t_RUNNABLE;
    sched();
    release(&Proc->lock);
}

