void sleep(void *chan, struct spinlock *lk) {
    struct proc *p = myproc();
    // Must acquire p->lock in order to
    // change p->state and then call sched.
    // Once we hold p->lock, we can be
    // guaranteed that we won't miss any wakeup
    // (wakeup locks p->lock),
    // so it's okay to release lk.
    if (&p->lock != lk) {   // DOC: sleeplock0
        acquire(&p->lock);  // DOC: sleeplock1
        release(lk);
    }
    // Go to sleep.
    p->state = SLEEPING;
    p->chan = chan;
    p->main_thread->state = t_RUNNABLE;
    sched();
    // Tidy up.
    p->chan = 0;
    // Reacquire original lock.
    if (&p->lock != lk) {
        release(&p->lock);
        acquire(lk);
    }
}

void wakeup(void *chan) {
    for (struct proc *p = proc; &proc[NPROC] > p; ++p) {
        acquire(&p->lock);
        if (p->chan == chan && p->state == SLEEPING) {
            p->state = RUNNABLE;
        }
        release(&p->lock);
    }
}

static void wakeup1(struct proc *p) {
    if (holding(&p->lock) == 0) panic("wakeup1");
    if (p->state == SLEEPING && p->chan == p) {
        p->state = RUNNABLE;
    }
}

int kill(int pid, int sig) {
    for (struct proc *p = proc; &proc[NPROC] > p; ++p) {
        acquire(&p->lock);
        if (pid == p->pid) {
            p->sig_pending.__val[0] |= (1 << (sig));
            // printf("kill peding:%p, killed:%d\n", p->sig_pending.__val[0],
            // p->killed);
            if (p->killed == 0 || p->killed > sig) {
                p->killed = sig;
            }
            if (p->state == SLEEPING) {
                // Wake process from sleep().
                p->state = RUNNABLE;
            }
            release(&p->lock);
            return 0;
        }
        release(&p->lock);
    }
    // not found
    return 0;
}

int tgkill(int tgid, int tid, int sig) {
    for (struct proc *p = proc; &proc[NPROC] > p; ++p) {
        acquire(&p->lock);
        if (tgid == p->pid) {
            thread *t = p->thread_queue;
            while (NULL != t) {
                if (tid == t->tid) {
                    p->sig_pending.__val[0] |= (1 << (sig));
                    if (p->killed == 0 || p->killed > sig) {
                        p->killed = sig;
                    }
                    if (p->state == SLEEPING) {
                        // Wake process from sleep().
                        p->state = RUNNABLE;
                    }
                    release(&p->lock);
                    return 0;
                }
                t = t->next_thread;
            }
        }
        release(&p->lock);
    }
    return -1;
}

int either_copyout(int user_dst, uint64 dst, void *src, uint64 length) {
    struct proc *p = myproc();
    if (user_dst != 0) {
        return copyout(p->pagetable, dst, src, length);
        // return copyout2(dst, src, length);
    } else {
        memmove((char *)dst, src, length);
        return 0;
    }
}

int either_copyin(void *dst, int user_src, uint64 src, uint64 length) {
    struct proc *p = myproc();
    if (user_src) {
        return copyin(p->pagetable, dst, src, length);
        // return copyin2(dst, src, length);
    } else {
        memmove(dst, (char *)src, length);
        return 0;
    }
}

void procdump(void) {
    static char *states[] = {[UNUSED] "unused",
                             [SLEEPING] "sleep ",
                             [RUNNABLE] "runble",
                             [RUNNING] "run   ",
                             [ZOMBIE] "zombie"};
    char *state;
    printf("\nPID\tSTATE\tNAME\tMEM\n");
    for (struct proc *p = proc; p < &proc[NPROC]; p++) {
        if (p->state == UNUSED) continue;
        if (states[p->state] && p->state >= 0 && p->state < NELEM(states))
            state = states[p->state];
        else
            state = "???";
        printf("%d\t%s\t%s\t%d", p->pid, state, p->name, p->sz);
        printf("\n");
    }
}

uint64 procnum(void) {
    int idx = 0;
    for (struct proc *p = proc; &proc[NPROC] > p; ++p)
        if (p->state != UNUSED) ++idx;

    return idx;
}

struct proc *findchild(struct proc *p, int pid, struct proc **child) {
    *child = NULL;
    // iterator all process
    for (struct proc *np = proc; np < &proc[NPROC]; ++np) {
        if (np->parent == p && (pid == -1 || np->pid == pid)) {
            acquire(&np->lock);
            *child = np;
            if (np->state == ZOMBIE) {
                return np;
            }
            release(&np->lock);
        }
    }
    return NULL;
}

int wait4pid(int pid, uint64 addr, int options) {
    struct proc *p = myproc(), *tchild = NULL, *child = NULL;
    int pid_kid;
    acquire(&p->lock);
    for (;;) {
        pid_kid = pid;
        child = findchild(p, pid, &tchild);
        if (NULL != child) {
            pid_kid = child->pid;
            child->xstate <<= 8;
            if (addr && 0 > copyout(p->pagetable, addr, (char *)&child->xstate,
                                    sizeof(child->xstate))) {
                release(&child->lock);
                release(&p->lock);
                return -1;
            }
            freeproc(child);
            release(&child->lock);
            release(&p->lock);
            return pid_kid;
        }
        /*
        if (options & WNOHANG) {
          release(&p->lock);
          return 0;
        }
        */
        if (tchild == 0) {
            release(&p->lock);
            return -1;
        }
        if (pid != -1) {
            sleep(tchild, &p->lock);
            // pay attention!
        } else
            sleep(p, &p->lock);
    }
    release(&p->lock);
    return 0;

    // TODO: deal with options
}

uint64 sys_yield() {
    yield();
    return 0;
}

static void copycontext_from_trapframe(context *t, struct trapframe *f) {
    t->ra = f->ra;
    t->sp = f->kernel_sp;
    t->s0 = f->s0;
    t->s1 = f->s1;
    t->s2 = f->s2;
    t->s3 = f->s3;
    t->s4 = f->s4;
    t->s5 = f->s5;
    t->s6 = f->s6;
    t->s7 = f->s7;
    t->s8 = f->s8;
    t->s9 = f->s9;
    t->s10 = f->s10;
    t->s11 = f->s11;
}

uint64 clone(uint64 new_stack, uint64 new_fn) {
    struct proc *np, *p = myproc();
    int idx, pid;
    // Allocate process.
    np = allocproc();
    if (np == NULL) {
        return -1;
    }

    // Copy user memory from parent to child.
    if (0 > uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz)) {
        freeproc(np);
        release(&np->lock);
        return -1;
    }
    np->parent = p;
    np->sz = p->sz;
    // copy tracing mask from parent.
    np->tmask = p->tmask;
    // copy saved user registers.
    *(np->trapframe) = *(p->trapframe);
    // Cause fork to return 0 in the child.
    np->trapframe->a0 = 0;
    // increment reference counts on open file descriptors.
    for (idx = 0; idx < NOFILE; ++idx)
        if (p->ofile[idx]) np->ofile[idx] = filedup(p->ofile[idx]);

    np->ext4_dir = ext4_edup(p->ext4_dir);
    safestrcpy(np->name, p->name, sizeof(p->name));
    pid = np->pid;
    np->trapframe->sp = new_stack;
    np->state = RUNNABLE;
    np->trapframe->epc = new_fn;
    release(&np->lock);
    return pid;
}

uint64 clone_thread(uint64 stack_va, uint64 ptid, uint64 tls, uint64 ctid) {
    struct proc *p = myproc();
    thread *t = alloc_thread();
    t->p = p;
    if (mappages(p->kpagetable, p->kstack - PGSIZE * p->thread_num * 2, PGSIZE,
                 (uint64)(t->trapframe), PTE_R | PTE_W) < 0)
        panic("thread_clone: mappages");
    t->vtf = p->kstack - PGSIZE * p->thread_num * 2;
    void *kstack_pa = kalloc();
    if (NULL == kstack_pa) panic("thread_clone: kalloc kstack failed");
    if (mappages(p->kpagetable, p->kstack - PGSIZE * (1 + p->thread_num * 2),
                 PGSIZE, (uint64)kstack_pa, PTE_R | PTE_W) < 0)
        panic("thread_clone: mappages");
    thread_stack_param tmp;

    if (copyin(p->pagetable, (char *)(&tmp), stack_va,
               sizeof(thread_stack_param)) < 0) {
        panic("copy in thread_stack_param failed");
    }
    t->kstack_pa = (uint64)kstack_pa;
    t->kstack = p->kstack - PGSIZE * (1 + p->thread_num * 2);
    // printf("thread stack param:%p %p\n",tmp.func_point,tmp.arg_point);

    t->next_thread = p->thread_queue;
    if (NULL != p->thread_queue) p->thread_queue->pre_thread = t;
    p->thread_queue = t;

    copytrapframe(t->trapframe, p->trapframe);
    t->trapframe->a0 = tmp.func_point;
    t->trapframe->tp = tls;
    t->trapframe->kernel_sp =
        p->kstack - PGSIZE * (1 + p->thread_num * 2) + PGSIZE;
    t->trapframe->sp = stack_va;
    t->trapframe->epc = tmp.func_point;
    copycontext_from_trapframe(&t->context, t->trapframe);
    t->context.ra = (uint64)forkret;
    t->context.sp = t->trapframe->kernel_sp;
    if (ptid != 0) {
        if (either_copyout(1, ptid, (void *)&t->tid, sizeof(int)) < 0)
            panic("thread_clone: either_copyout");
    }
    t->clear_child_tid = ctid;
    p->thread_num++;

    return t->tid;
}

uint64 alloc_vma_stack(struct proc *p) {
    // 起始分配100个page
    uint64 end = USER_STACK_TOP;
    uint64 start = end - INIT_STACK_SIZE;
    struct vma *find_vma = p->vma->next;
    // stack 放到链表的最后端
    while (find_vma != p->vma && find_vma->next != p->vma) {
        find_vma = find_vma->next;
    }

    struct vma *vma = (struct vma *)kalloc();
    if (NULL == vma) {
        printf("vma kalloc failed\n");
        return -1;
    }

    if (uvmalloc1(p->pagetable, start, end, PTE_R | PTE_W | PTE_U) != 0) {
        printf("user stack vma alloc failed\n");
        kfree(vma);
        return -1;
    }
    vma->type = STACK;
    vma->perm = PTE_R | PTE_W;
    vma->addr = start;
    vma->end = end;
    vma->sz = INIT_STACK_SIZE;
    vma->flags = 0;
    vma->fd = -1;
    vma->f_off = -1;
    vma->prev = find_vma;
    vma->next = find_vma->next;
    find_vma->next->prev = vma;
    find_vma->next = vma;
    return 0;
}

uint64 handle_stack_page_fault(struct proc *p, uint64 va) {
    if (!(va >= USER_STACK_DOWN && va < USER_STACK_TOP)) {
        return -1;
    }
    struct vma *vma = p->vma->next;
    while (vma != p->vma) {
        if (vma->type == STACK) {
            break;
        }
        vma = vma->next;
    }
    if (vma->type != STACK) {
        printf("handle_stack_page_fault: vma type is not stack\n");
        return -1;
    }
    printf("handle stack page fault now start %p, now end :%p, va:%p\n",
           vma->addr, vma->end, va);
    uint64 start = vma->addr - INCREASE_STACK_SIZE_PER_FAULT;
    if (start > va) {
        start = PGROUNDDOWN(va);
    }
    uint64 end = vma->addr;

    if (uvmalloc1(p->pagetable, start, end, PTE_R | PTE_W | PTE_U) != 0) {
        printf("user stack vma alloc failed\n");
        return -1;
    }
    vma->addr = start;
    vma->sz = vma->sz + INCREASE_STACK_SIZE_PER_FAULT;

    return 0;
}

uint64 get_proc_sp(struct proc *p) {
    struct vma *vma = p->vma->next;
    while (vma != p->vma) {
        if (vma->type == STACK) {
            break;
        }
        vma = vma->next;
    }
    if (vma->type != STACK) {
        printf("get_proc_sp: vma type is not stack\n");
        return -1;
    }
    return vma->end;
}

void print_vma(struct proc *p) {
    printf("============ vma list ===========\n");
    struct vma *vma = p->vma->next;
    while (vma != p->vma) {
        printf("%p-%p %dKB\t", vma->addr, vma->addr + vma->sz, vma->sz / 1024);
        if (vma->perm & PTE_R) {
            printf("r");
        } else {
            printf("-");
        }
        if (vma->perm & PTE_W) {
            printf("w");
        } else {
            printf("-");
        }
        if (vma->perm & PTE_X) {
            printf("x");
        } else {
            printf("-");
        }
        if (vma->type == MMAP) {
            printf(" mmap");
        } else if (vma->type == STACK) {
            printf(" stack");
        } else {
            printf(" unknown");
        }
        printf("\n");
        vma = vma->next;
    }
    printf("========== end vma list =========\n");
}

uint64 sys_clone(void) {
    uint64 new_stack, new_fn;
    uint64 ptid, tls, ctid;
    argaddr(1, &new_stack);
    if (argaddr(0, &new_fn) < 0) {
        debug_print("sys_clone: argaddr(0, &new_fn) < 0\n");
        return -1;
    }
    if (argaddr(2, &ptid) < 0) {
        debug_print("sys_clone: argaddr(2, &ptid) < 0\n");
        return -1;
    }
    if (argaddr(3, &tls) < 0) {
        debug_print("sys_clone: argaddr(3, &tls) < 0\n");
        return -1;
    }
    if (argaddr(4, &ctid) < 0) {
        debug_print("sys_clone: argaddr(4, &ctid) < 0\n");
        return -1;
    }
    debug_print(
        "sys_clone: new_stack = %p, new_fn = %p, ptid = %p, tls = %p, ctid = "
        "%p\n",
        new_stack, new_fn, ptid, tls, ctid);
    if (new_stack == 0) {
        return fork();
    }
    if (new_fn & CLONE_VM)
        return clone_thread(new_stack, ptid, tls, ctid);
    else
        return clone(new_stack, new_fn);
}

