uint64 sys_exec(void) {
    char path[FAT32_MAX_PATH], *argv[MAXARG];
    uint64 uargv;
    uint64 uarg;
    if (argaddr(1, &uargv) < 0 || argstr(0, path, FAT32_MAX_PATH) < 0) {
        return -1;
    }
    memset(argv, 0, sizeof(argv));
    int idx;
    for (idx = 0;; ++idx) {
        if (NELEM(argv) <= idx) {
            goto bad;
        }
        if (fetchaddr(sizeof(uint64) * idx + uargv, (uint64 *)&uarg) < 0) {
            goto bad;
        }
        if (!uarg) {
            argv[idx] = 0;
            break;
        }
        argv[idx] = kalloc();
        if (!argv[idx]) goto bad;
        if (fetchstr(uarg, argv[idx], PGSIZE) < 0) goto bad;
    }

    int res = exec(path, argv, NULL);

    for (idx = 0; idx < NELEM(argv) && argv[idx]; ++idx) kfree(argv[idx]);

    return res;

bad:
    for (idx = 0; idx < NELEM(argv) && argv[idx]; ++idx) kfree(argv[idx]);
    return -1;
}

uint64 sys_execve(void) {
    // printf("start execve\n");
    char *argv[MAXARG], path[FAT32_MAX_PATH];
    char *envp[MAXARG];
    // char *env[MAXARG];
    uint64 uargv, uarg, uenv;

    if (argaddr(1, &uargv) < 0 || argstr(0, path, FAT32_MAX_PATH) < 0 ||
        argaddr(2, &uenv)) {
        return -1;
    }
    memset(argv, 0, sizeof(argv));
    int idx;
    for (idx = 0;; ++idx) {
        if (idx >= NELEM(argv)) {
            goto bad;
        }
        if (fetchaddr(uargv + sizeof(uint64) * idx, (uint64 *)&uarg) < 0) {
            goto bad;
        }
        if (!uarg) {
            argv[idx] = 0;
            break;
        }
        argv[idx] = kalloc();
        if (!argv[idx]) goto bad;
        if (0 > fetchstr(uarg, argv[idx], PGSIZE)) goto bad;
    }

    memset(envp, 0, sizeof(envp));
    int res;
    if (uenv) {
        for (idx = 0;; ++idx) {
            if (idx >= NELEM(envp)) {
                goto bad;
            }
            if (fetchaddr(uenv + sizeof(uint64) * idx, (uint64 *)&uarg) < 0) {
                goto bad;
            }
            if (!uarg) {
                envp[idx] = 0;
                break;
            }
            envp[idx] = kalloc();
            if (!envp[idx]) goto bad;
            if (0 > fetchstr(uarg, envp[idx], PGSIZE)) goto bad;
        }

        res = exec(path, argv, envp);
    } else {
        res = exec(path, argv, NULL);
    }

    for (idx = 0; idx < NELEM(argv) && argv[idx]; ++idx) kfree(argv[idx]);
    for (idx = 0; idx < NELEM(envp) && envp[idx]; ++idx) kfree(envp[idx]);

    return res;

bad:
    for (idx = 0; idx < NELEM(argv) && argv[idx]; ++idx) kfree(argv[idx]);
    for (idx = 0; idx < NELEM(envp) && envp[idx]; ++idx) kfree(envp[idx]);
    return -1;
}

