uint64 sys_nanosleep(void) {
    uint64 addr_sec;
    uint64 addr_usec;

    if (argaddr(0, &addr_sec) < 0 || argaddr(1, &addr_usec) < 0) return -1;

    struct proc *p = myproc();
    uint64 sec, usec;
    if (copyin(p->pagetable, (char *)&sec, addr_sec, sizeof sec) < 0) return -1;
    if (copyin(p->pagetable, (char *)&usec, addr_usec, sizeof usec) < 0)
        return -1;
    int n = usec / 50000000 + sec * 20;

    int msk = p->tmask;
    if (msk) {
        printf(") ...\n");
    }
    acquire(&p->lock);
    uint64 tick0 = ticks;
    while (ticks < n / 10 + tick0) {
        if (p->killed != 0) {
            return -1;
        }
        sleep(&ticks, &p->lock);
    }
    release(&p->lock);

    return 0;
}

