uint64 sys_brk(void) {
    int n, address;

    if (argint(0, &n) < 0) return -1;
    address = myproc()->sz;
    if (!n) {
        return address;
    }
    if (address <= n) {
        if (growproc(n - address) >= 0)
            return 0;
        else
            return -1;
    }
    return -1;
}

uint64 sys_sleep(void) {
    uint tck0;
    int n;

    if (0 > argint(0, &n)) return -1;
    acquire(&tickslock);
    tck0 = ticks;
    while (ticks < n + tck0) {
        if (myproc()->killed != 0) {
            release(&tickslock);
            return -1;
        }
        sleep(&ticks, &tickslock);
    }
    release(&tickslock);
    return 0;
}

uint64 sys_kill(void) {
