void consputc(int c) {
    if (c == BACKSPACE) {
        // if the user typed backspace, overwrite with a space.
        sbi_console_putchar('\b');
        sbi_console_putchar(' ');
        sbi_console_putchar('\b');
    } else {
        sbi_console_putchar(c);
    }
}

struct {
    struct spinlock lock;

    // input
#define INPUT_BUF 128
    char buf[INPUT_BUF];
    uint r;  // Read index
    uint w;  // Write index
    uint e;  // Edit index
}

int consolewrite(int user_src, uint64 src, int n) {
    int i;

    acquire(&cons.lock);
    for (i = 0; i < n; i++) {
        char c;
        if (either_copyin(&c, user_src, src + i, 1) == -1) break;
        sbi_console_putchar(c);
    }
    release(&cons.lock);

    return i;
}

int consoleread(int user_dst, uint64 dst, int n) {
    uint target;
    int c;
    char cbuf;

    target = n;
    acquire(&cons.lock);
    while (n > 0) {
        // wait until interrupt handler has put some
        // input into cons.buffer.
        while (cons.r == cons.w) {
            if (myproc()->killed) {
                release(&cons.lock);
                return -1;
            }
            sleep(&cons.r, &cons.lock);
        }

        c = cons.buf[cons.r++ % INPUT_BUF];

        if (c == C('D')) {  // end-of-file
            if (n < target) {
                // Save ^D for next time, to make sure
                // caller gets a 0-byte result.
                cons.r--;
            }
            break;
        }

        // copy the input byte to the user-space buffer.
        cbuf = c;
        if (either_copyout(user_dst, dst, &cbuf, 1) == -1) break;

        dst++;
        --n;

        if (c == '\n') {
            // a whole line has arrived, return to
            // the user-level read().
            break;
        }
    }
    release(&cons.lock);

    return target - n;
}

void consoleintr(int c) {
    acquire(&cons.lock);

    switch (c) {
    case C('P'):  // Print process list.
        procdump();
        break;
    case C('U'):  // Kill line.
        while (cons.e != cons.w && cons.buf[(cons.e - 1) % INPUT_BUF] != '\n') {
            cons.e--;
            consputc(BACKSPACE);
        }
        break;
    case C('H'):  // Backspace
    case '\x7f':
        if (cons.e != cons.w) {
            cons.e--;
            consputc(BACKSPACE);
        }
        break;
    default:
        if (c != 0 && cons.e - cons.r < INPUT_BUF) {
#ifndef QEMU
            if (c == '\r') break;  // on k210, "enter" will input \n and \r
#else
            c = (c == '\r') ? '\n' : c;
#endif
            // echo back to the user.
            consputc(c);

            // store for consumption by consoleread().
            cons.buf[cons.e++ % INPUT_BUF] = c;

            if (c == '\n' || c == C('D') || cons.e == cons.r + INPUT_BUF) {
                // wake up consoleread() if a whole line (or end-of-file)
                // has arrived.
                cons.w = cons.e;
                wakeup(&cons.r);
            }
        }
        break;
    }

    release(&cons.lock);
}

void consoleinit(void) {
    initlock(&cons.lock, "cons");
#ifdef QEMU
    uartinit();
#endif
    cons.e = cons.w = cons.r = 0;

    // connect read and write system calls
    // to consoleread and consolewrite.
    devsw[CONSOLE].read = consoleread;
    devsw[CONSOLE].write = consolewrite;
}

void push_off(void) {
    int old = intr_get();

    intr_off();
    // printf("\e[32mpush_off()\e[0m: cpuid(): %d\n", cpuid());
    if (mycpu()->noff == 0) mycpu()->intena = old;
    // printstring("push_off noff++ noff:\n");
    // printint(mycpu()->noff, 10, 1);
    // consputc('\n');
    mycpu()->noff += 1;
}

void pop_off(void) {
    struct cpu *c = mycpu();

    // printf("\e[31mpop_off()\e[0m: cpuid(): %d\n", cpuid());
    if (intr_get()) panic("pop_off - interruptible");
    if (c->noff < 1) {
        // printf("c->noff = %d\n", c->noff);
        // consputc('P');
        panic("pop_off");
    }
    // printf("c->noff: %d\n", c->noff);
    // printf("c: %x\n", c);
    // printstring("pop_off noff--\n");
    c->noff -= 1;
    if (c->noff == 0 && c->intena) intr_on();
}

void plicinit(void) {
    writed(1, PLIC_V + DISK_IRQ * sizeof(uint32));
    writed(1, PLIC_V + UART_IRQ * sizeof(uint32));

#ifdef DEBUG
    printf("plicinit\n");
#endif
}

void plicinithart(void) {
    int hart = cpuid();
#ifdef QEMU
    // set uart's enable bit for this hart's S-mode.
    *(uint32*)PLIC_SENABLE(hart) = (1 << UART_IRQ) | (1 << DISK_IRQ);
    // set this hart's S-mode priority threshold to 0.
    *(uint32*)PLIC_SPRIORITY(hart) = 0;
#else
    uint32 *hart_m_enable = (uint32 *)PLIC_MENABLE(hart);
    *(hart_m_enable) = readd(hart_m_enable) | (1 << DISK_IRQ);
    uint32 *hart0_m_int_enable_hi = hart_m_enable + 1;
    *(hart0_m_int_enable_hi) =
        readd(hart0_m_int_enable_hi) | (1 << (UART_IRQ % 32));
#endif
#ifdef DEBUG
    printf("plicinithart\n");
#endif
}

int plic_claim(void) {
    int hart = cpuid();
    int irq;
#ifndef QEMU
    irq = *(uint32*)PLIC_MCLAIM(hart);
#else
    irq = *(uint32 *)PLIC_SCLAIM(hart);
#endif
    return irq;
}

void plic_complete(int irq) {
    int hart = cpuid();
#ifndef QEMU
    *(uint32*)PLIC_MCLAIM(hart) = irq;
#else
    *(uint32 *)PLIC_SCLAIM(hart) = irq;
#endif
}

