    struct proc *p = myproc();
    // if (addr >= p->sz || addr + sizeof(uint64) > p->sz) return -1;
    if (copyin(p->pagetable, (char *)ip, addr, sizeof(*ip)) != 0) {
        printf("fetchaddr: copyin failed\n");
        return -1;
    }
    // if (copyin2((char *)ip, addr, sizeof(*ip)) != 0) return -1;
    return 0;
}

int fetchstr(uint64 addr, char *buf, int max) {
    struct proc *p = myproc();
    int err = copyinstr(p->pagetable, buf, addr, max);
    // int err = copyinstr2(buf, addr, max);
    if (err < 0) return err;
    return strlen(buf);
}

static uint64 argraw(int n) {
    struct proc *p = myproc();
    switch (n) {
    case 0:
        return p->trapframe->a0;
    case 1:
        return p->trapframe->a1;
    case 2:
        return p->trapframe->a2;
    case 3:
        return p->trapframe->a3;
    case 4:
        return p->trapframe->a4;
    case 5:
        return p->trapframe->a5;
    }
    panic("argraw");
    return -1;
}

int argint(int n, int *ip) {
    *ip = argraw(n);
    return 0;
}

int argaddr(int n, uint64 *ip) {
    *ip = argraw(n);
    return 0;
}

int argstr(int n, char *buf, int max) {
    uint64 addr;
    if (argaddr(n, &addr) < 0) return -1;
    return fetchstr(addr, buf, max);
}

void syscall(void) {
    int num;

    // printf("fucntion num: %d\n");
    struct proc *p = myproc();

    num = p->trapframe->a7;

    // printf("fucntion num: %d\n");
    if (num > 0 && num < NELEM(syscalls) && syscalls[num]) {
        // if (num != SYS_write) printf("pid %d: %s\n", p->pid, sysnames[num]);
        p->trapframe->a0 = syscalls[num]();
        // if (num != SYS_write)
        //     printf("%s -> %d\n", sysnames[num], p->trapframe->a0);
        // trace
        if ((p->tmask & (1 << num)) != 0) {
            printf("pid %d: %s -> %d\n", p->pid, sysnames[num],
                   p->trapframe->a0);
        }
    } else {
        printf("pid %d %s: unknown sys call %d\n", p->pid, p->name, num);
        p->trapframe->a0 = -1;
    }
}

