void swap(void *a, void *b, uint64 size) {
    unsigned char tmp;
    unsigned char *pa = a;
    unsigned char *pb = b;
    for (uint64 i = 0; i < size; i++) {
        tmp = pa[i];
        pa[i] = pb[i];
        pb[i] = tmp;
    }
}

void *partition(void *base, uint64 num, uint64 size,
                int (*compar)(const void *, const void *)) {
    char *pivot = (char *)base + (num - 1) * size;
    char *i = base - size;
    for (char *j = base; j < pivot; j += size) {
        if (compar(j, pivot) <= 0) {
            i += size;
            swap(i, j, size);
        }
    }
    swap(i + size, pivot, size);
    return i + size;
}

void q1sort(void *base, uint64 num, uint64 size,
            int (*compar)(const void *, const void *)) {
    if (num < 2) return;

    void *p = partition(base, num, size, compar);
    uint64 left_size = ((char *)p - (char *)base) / size;
    uint64 right_size = num - left_size - 1;

    q1sort(base, left_size, size, compar);
    q1sort((char *)base + (left_size + 1) * size, right_size, size, compar);
}

