uint64 sys_times() {
    struct tms ptms;
    uint64 utms;
    argaddr(0, &utms);
    ptms.tms_utime = myproc()->utime;
    ptms.tms_stime = myproc()->ktime;
    ptms.tms_cstime = 1;
    ptms.tms_cutime = 1;
    struct proc *p;
    for (p = proc; p < proc + NPROC; p++) {
        acquire(&p->lock);
        if (p->parent == myproc()) {
            ptms.tms_cutime += p->utime;
            ptms.tms_cstime += p->ktime;
        }
        release(&p->lock);
    }
    copyout2(utms, (char *)&ptms, sizeof(ptms));
    return 0;
}

void set_bit(volatile uint32 *bits, uint32 mask, uint32 value) {
    uint32 org = (*bits) & ~mask;
    *bits = org | (value & mask);
}

void set_bit_offset(volatile uint32 *bits, uint32 mask, uint64 offset,
                    uint32 value) {
    set_bit(bits, mask << offset, value << offset);
}

void set_gpio_bit(volatile uint32 *bits, uint64 offset, uint32 value) {
    set_bit_offset(bits, 1, offset, value);
}

uint32 get_bit(volatile uint32 *bits, uint32 mask, uint64 offset) {
    return ((*bits) & (mask << offset)) >> offset;
}

uint32 get_gpio_bit(volatile uint32 *bits, uint64 offset) {
    return get_bit(bits, 1, offset);
}

