            if (pid == 0) {
                fork();
                fork();
                exit(0);
            } else if (pid < 0) {
                printf("grind: fork failed\n");
                exit(1);
            }
            wait(0);
        } else if (what == 15) {
            sbrk(6011);
        } else if (what == 16) {
            if (sbrk(0) > break0) sbrk(-(sbrk(0) - break0));
        } else if (what == 17) {
