            wait(0);
        } else if (what == 18) {
            int pid = fork();
            if (pid == 0) {
                kill(getpid());
                exit(0);
            } else if (pid < 0) {
                printf("grind: fork failed\n");
                exit(1);
            }
            wait(0);
        } else if (what == 19) {
            int fds[2];
            if (pipe(fds) < 0) {
                printf("grind: pipe failed\n");
                exit(1);
            }
            int pid = fork();
            if (pid == 0) {
                fork();
                fork();
                if (write(fds[1], "x", 1) != 1)
                    printf("grind: pipe write failed\n");
                char c;
                if (read(fds[0], &c, 1) != 1)
                    printf("grind: pipe read failed\n");
                exit(0);
            } else if (pid < 0) {
                printf("grind: fork failed\n");
                exit(1);
            }
            close(fds[0]);
            close(fds[1]);
            wait(0);
        } else if (what == 20) {
