                exit(2);
            } else if (pid1 < 0) {
                fprintf(2, "fork failed\n");
                exit(3);
            }
            int pid2 = fork();
            if (pid2 == 0) {
                close(aa[1]);
                close(bb[0]);
                close(0);
                if (dup(aa[0]) != 0) {
                    fprintf(2, "dup failed\n");
                    exit(4);
                }
                close(aa[0]);
                close(1);
                if (dup(bb[1]) != 1) {
                    fprintf(2, "dup failed\n");
                    exit(5);
                }
                close(bb[1]);
                char *args[2] = {"cat", 0};
                execve("/cat", args, NULL);
                fprintf(2, "cat: not found\n");
                exit(6);
            } else if (pid2 < 0) {
                fprintf(2, "fork failed\n");
                exit(7);
            }
            close(aa[0]);
            close(aa[1]);
            close(bb[1]);
            char buf[3] = {0, 0, 0};
            read(bb[0], buf + 0, 1);
