    int pid1 = fork();
    if (pid1 < 0) {
        printf("grind: fork failed\n");
        exit(1);
    }
    if (pid1 == 0) {
        rand_next = 31;
        go(0);
        exit(0);
    }

    int pid2 = fork();
    if (pid2 < 0) {
        printf("grind: fork failed\n");
        exit(1);
    }
    if (pid2 == 0) {
        rand_next = 7177;
        go(1);
        exit(0);
    }

    int st1 = -1;
    wait(&st1);
    if (st1 != 0) {
        kill(pid1);
        kill(pid2);
    }
    int st2 = -1;
    wait(&st2);

    exit(0);
}

