int checkenvname(char *s) {
    if ((*s >= 'A' && *s <= 'Z') || (*s >= 'a' && *s <= 'z') || *s == '_')
        ;
    else
        return 0;
    char *tmp = s + 1;
    while ((*tmp >= 'A' && *tmp <= 'Z') || (*tmp >= 'a' && *tmp <= 'z') ||
           (*tmp >= '0' && *tmp <= '9') || *tmp == '_')
        tmp++;
    return (int)(tmp - s);
}

int export(char *argv[]) {
    if (!strcmp(argv[1], "-p")) {  // print all the env vars
        if (!nenv) {
            printf("NO env var exported\n");
            return 0;
        }
        for (int i = 0; i < nenv; i++)
            printf("export %s=%s\n", envs[i].name, envs[i].value);
        return 0;
    } else if (nenv == NENVS) {
        fprintf(2, "too many env vars\n");
        return -1;
    }
    char name[32], value[96];
    char *s = argv[1], *t = name;

    for (s = argv[1], t = name; (*t = *s++) != '='; t++)
        ;
    *t = 0;

    if (checkenvname(name) != ((s - argv[1]) - 1)) {
        fprintf(2, "Invalid NAME!\n");
        return -1;
    }
    for (t = value; (*t = *s); s++, t++)
        ;
    if (*--t == '/') *t = 0;

    strcpy(envs[nenv].name, name);
    strcpy(envs[nenv].value, value);
    nenv++;
    return 0;
}

int replace(char *buf) {
    char raw[100], name[32], *s, *t, *tmp;
    int n = 0;
    strcpy(raw, buf);
    for (s = raw, t = buf; (*t = *s); t++) {
        if (*s++ == '$') {
            tmp = name;
            if ((*s >= 'A' && *s <= 'Z') || (*s >= 'a' && *s <= 'z') ||
                *s == '_') {
                *tmp++ = *s++;
                while ((*s >= 'A' && *s <= 'Z') || (*s >= 'a' && *s <= 'z') ||
                       (*s >= '0' && *s <= '9') || *s == '_')
                    *tmp++ = *s++;
                *tmp = 0;
                for (int i = 0; i < nenv; i++)
                    if (!strcmp(name, envs[i].name))
                        for (tmp = envs[i].value; (*t = *tmp); t++, tmp++)
                            ;
                t--;
            }
            n++;
        }
    }
    return n;
}

void runcmd(struct cmd *cmd) {
    int p[2];
    struct backcmd *bcmd;
    struct execcmd *ecmd;
    struct listcmd *lcmd;
    struct pipecmd *pcmd;
    struct redircmd *rcmd;

    if (cmd == 0) exit(1);

    switch (cmd->type) {
    default:
        panic("runcmd");

    case EXEC:
        ecmd = (struct execcmd *)cmd;
        if (ecmd->argv[0] == 0) exit(1);

        execve(ecmd->argv[0], ecmd->argv, NULL);

        int i;
        char env_cmd[64];
        for (i = 0; i < nenv; i++) {
            char *s_tmp = env_cmd;
            char *d_tmp = envs[i].value;
            while ((*s_tmp = *d_tmp++)) s_tmp++;
            *s_tmp++ = '/';
            d_tmp = ecmd->argv[0];
            while ((*s_tmp++ = *d_tmp++))
                ;

            execve(env_cmd, ecmd->argv, NULL);
        }
        fprintf(2, "exec %s failed\n", ecmd->argv[0]);
        break;

    case REDIR:
        rcmd = (struct redircmd *)cmd;
        close(rcmd->fd);
        if (open(rcmd->file, rcmd->mode) < 0) {
            fprintf(2, "open %s failed\n", rcmd->file);
            exit(1);
        }
        runcmd(rcmd->cmd);
        break;

    case LIST:
        lcmd = (struct listcmd *)cmd;
        if (fork1() == 0) runcmd(lcmd->left);
        wait(0);
        runcmd(lcmd->right);
        break;

    case PIPE:
        pcmd = (struct pipecmd *)cmd;
        if (pipe(p) < 0) panic("pipe");
        if (fork1() == 0) {
            close(1);
            dup(p[1]);
            close(p[0]);
            close(p[1]);
            runcmd(pcmd->left);
        }
        if (fork1() == 0) {
            close(0);
            dup(p[0]);
            close(p[0]);
            close(p[1]);
            runcmd(pcmd->right);
        }
        close(p[0]);
        close(p[1]);
        wait(0);
        wait(0);
        break;

    case BACK:
        bcmd = (struct backcmd *)cmd;
        if (fork1() == 0) runcmd(bcmd->cmd);
        break;
    }
    exit(0);
}

