        while (countStr[countIndex] != '\0' &&
               str[i + countIndex] == countStr[countIndex]) {
            countIndex++;
        }

        if (countStr[countIndex] == '\0') {
            // "COUNT"匹配成功，查找数字部分
            num = 0;
            i += countIndex;
            while (str[i] != '\0') {
                if (str[i] >= '0' && str[i] <= '9') {
                    num = num * 10 + (str[i] - '0');
