void wc(int fd, char *name) {
    int i, n;
    int l, w, c, inword;

    l = w = c = 0;
    inword = 0;
    while ((n = read(fd, buf, sizeof(buf))) > 0) {
        for (i = 0; i < n; i++) {
            c++;
            if (buf[i] == '\n') l++;
            if (strchr(" \r\t\n\v", buf[i]))
                inword = 0;
            else if (!inword) {
                w++;
                inword = 1;
            }
        }
    }
    if (n < 0) {
        printf("wc: read error\n");
        exit(1);
    }
    printf("%d\t%d\t%d\t%s\n", l, w, c, name);
}

int main(int argc, char *argv[]) {
    int fd, i;

    if (argc <= 1) {
        wc(0, "");
        exit(0);
    }

    printf("LINE\tWORD\tBYTE\tFILE\n");
    for (i = 1; i < argc; i++) {
        if ((fd = open(argv[i], 0)) < 0) {
            printf("wc: cannot open %s\n", argv[i]);
            exit(1);
        }
        wc(fd, argv[i]);
        close(fd);
    }
    exit(0);
}

int readline(int fd, char *buf, int len) {
    char *p = buf;
    while (read(fd, p, 1) != 0 && p < buf + len) {
        if (*p == '\n') {
            if (p == buf) {  // ignore empty line
                continue;
            }
            *p = '\0';
            break;
        }
        p++;
    }
    if (p == buf) {
        return 0;
    }
    return p - buf;
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(2, "Usage: xargs COMMAND [INITIAL-ARGS]...\n");
        exit(-1);
    }
    char *argvs[MAXARG];
    char buf[128];
    int i;
    for (i = 1; i < argc; i++) {
        argvs[i - 1] = argv[i];  // argvs[0] = COMMAND
    }
    i--;
    if (readline(0, buf, 128) == 0) {  // if there is no input
        argvs[i] = 0;
        if (fork() == 0) {
            execve(argv[1], argvs, NULL);
            printf("xargs: exec %s fail\n", argv[1]);
            exit(0);
        }
        wait(0);
    } else {
        argvs[i] = buf;
        argvs[i + 1] = 0;
        do {
            if (fork() == 0) {
                execve(argv[1], argvs, NULL);
                printf("xargs: exec %s fail\n", argv[1]);
                exit(0);
            }
            wait(0);
        } while (readline(0, buf, 128) != 0);
    }
    exit(0);
}

int main(void) {
    if (fork() > 0) sleep(5);  // Let child exit before parent.
    exit(0);
}
